'use client';

// eslint-disable-next-line @typescript-eslint/no-unused-vars
import React, { useState, useEffect, useCallback } from 'react';
import { useSearchParams, useRouter } from 'next/navigation';
import { ChatProvider, useChatContext, ConversationMeta } from '@/providers/ChatProvider';
import { ConversationalSearch } from '@/components/ai/ConversationalSearch';

// ---------------------------------------------------------------------------
// Date grouping helper
// ---------------------------------------------------------------------------
function groupByDate(conversations: ConversationMeta[]) {
  const now = new Date();
  const today = new Date(now.getFullYear(), now.getMonth(), now.getDate());
  const yesterday = new Date(today.getTime() - 86400000);
  const lastWeek = new Date(today.getTime() - 7 * 86400000);

  const groups: { label: string; items: ConversationMeta[] }[] = [
    { label: 'Today', items: [] },
    { label: 'Yesterday', items: [] },
    { label: 'Last 7 Days', items: [] },
    { label: 'Older', items: [] },
  ];

  for (const conv of conversations) {
    const d = new Date(conv.updated_at || conv.created_at);
    if (d >= today) groups[0].items.push(conv);
    else if (d >= yesterday) groups[1].items.push(conv);
    else if (d >= lastWeek) groups[2].items.push(conv);
    else groups[3].items.push(conv);
  }

  return groups.filter((g) => g.items.length > 0);
}

// ---------------------------------------------------------------------------
// Sidebar
// ---------------------------------------------------------------------------
function ChatSidebar() {
  const {
    activeConversationId,
    conversations,
    createConversation,
    selectConversation,
    renameConversation,
    deleteConversation,
    isLoadingList,
  } = useChatContext();

  const router = useRouter();
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editTitle, setEditTitle] = useState('');

  const handleNew = async () => {
    const id = await createConversation('GENERAL');
    router.push(`/chat?id=${id}`, { scroll: false });
  };

  const handleSelect = (id: string) => {
    selectConversation(id);
    router.push(`/chat?id=${id}`, { scroll: false });
  };

  const handleRename = async (id: string) => {
    if (editTitle.trim()) {
      await renameConversation(id, editTitle.trim());
    }
    setEditingId(null);
  };

  const handleDelete = async (id: string) => {
    await deleteConversation(id);
    if (activeConversationId === id) {
      router.push('/chat', { scroll: false });
    }
  };

  const grouped = groupByDate(conversations);

  return (
    <aside className="w-72 border-r border-gray-200 bg-gray-50/80 flex flex-col h-full">
      {/* New Chat Button */}
      <div className="p-3">
        <button
          onClick={handleNew}
          className="w-full flex items-center justify-center gap-2 px-4 py-2.5 text-sm font-medium text-white bg-primary-600 hover:bg-primary-700 rounded-lg transition-colors"
        >
          <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
          </svg>
          New Chat
        </button>
      </div>

      {/* Conversation List */}
      <div className="flex-1 overflow-y-auto px-2 pb-4">
        {isLoadingList ? (
          <div className="space-y-2 p-2">
            {[1, 2, 3].map((i) => (
              <div key={i} className="h-10 bg-gray-200 rounded-lg animate-pulse" />
            ))}
          </div>
        ) : conversations.length === 0 ? (
          <div className="px-4 py-8 text-center text-sm text-gray-400">
            No conversations yet.
            <br />
            // eslint-disable-next-line react/no-unescaped-entities
            Start by clicking "New Chat".
          </div>
        ) : (
          grouped.map((group) => (
            <div key={group.label} className="mb-4">
              <p className="px-3 py-1 text-[10px] font-semibold text-gray-400 uppercase tracking-wider">
                {group.label}
              </p>
              {group.items.map((conv) => (
                <div
                  key={conv.conversation_id}
                  className={`group relative flex items-center gap-2 px-3 py-2 rounded-lg cursor-pointer text-sm transition-colors ${
                    activeConversationId === conv.conversation_id
                      ? 'bg-primary-50 text-primary-700 font-medium'
                      : 'text-gray-700 hover:bg-gray-100'
                  }`}
                  onClick={() => handleSelect(conv.conversation_id)}
                >
                  {editingId === conv.conversation_id ? (
                    <input
                      autoFocus
                      value={editTitle}
                      onChange={(e) => setEditTitle(e.target.value)}
                      onBlur={() => handleRename(conv.conversation_id)}
                      onKeyDown={(e) => {
                        if (e.key === 'Enter') handleRename(conv.conversation_id);
                        if (e.key === 'Escape') setEditingId(null);
                      }}
                      className="flex-1 text-sm bg-white border border-primary-300 rounded px-1.5 py-0.5 focus:outline-none"
                      onClick={(e) => e.stopPropagation()}
                    />
                  ) : (
                    <span className="flex-1 truncate">{conv.title}</span>
                  )}

                  {/* Actions (visible on hover) */}
                  <div className="hidden group-hover:flex items-center gap-1 shrink-0">
                    <button
                      onClick={(e) => {
                        e.stopPropagation();
                        setEditingId(conv.conversation_id);
                        setEditTitle(conv.title);
                      }}
                      className="p-1 rounded hover:bg-gray-200 text-gray-400 hover:text-gray-600"
                      title="Rename"
                    >
                      <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path
                          strokeLinecap="round"
                          strokeLinejoin="round"
                          strokeWidth={2}
                          d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z"
                        />
                      </svg>
                    </button>
                    <button
                      onClick={(e) => {
                        e.stopPropagation();
                        handleDelete(conv.conversation_id);
                      }}
                      className="p-1 rounded hover:bg-red-50 text-gray-400 hover:text-red-500"
                      title="Delete"
                    >
                      <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path
                          strokeLinecap="round"
                          strokeLinejoin="round"
                          strokeWidth={2}
                          d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"
                        />
                      </svg>
                    </button>
                  </div>
                </div>
              ))}
            </div>
          ))
        )}
      </div>
    </aside>
  );
}

// ---------------------------------------------------------------------------
// Main Chat Page Content
// ---------------------------------------------------------------------------
function ChatPageContent() {
  const { activeConversationId, createConversation, selectConversation } = useChatContext();
  const searchParams = useSearchParams();
  const router = useRouter();

  // Sync URL param with active conversation
  useEffect(() => {
    const idFromUrl = searchParams.get('id');
    if (idFromUrl && idFromUrl !== activeConversationId) {
      selectConversation(idFromUrl);
    }
  }, [searchParams, activeConversationId, selectConversation]);

  const handleNewChat = async () => {
    const id = await createConversation('GENERAL');
    router.push(`/chat?id=${id}`, { scroll: false });
  };

  return (
    <div className="flex h-[calc(100vh-64px)]">
      {/* Sidebar */}
      <ChatSidebar />

      {/* Main Chat Area */}
      <div className="flex-1 flex flex-col">
        {activeConversationId ? (
          <ConversationalSearch
            conversationId={activeConversationId}
            initialMode="GENERAL"
            hideModeSelector={false}
            className="flex-1 border-0 rounded-none shadow-none max-h-full"
          />
        ) : (
          <div className="flex-1 flex flex-col items-center justify-center text-center px-8">
            <div className="max-w-md space-y-6">
              <div className="w-16 h-16 mx-auto rounded-2xl bg-gradient-to-br from-primary-500 to-primary-700 flex items-center justify-center">
                <svg className="w-8 h-8 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path
                    strokeLinecap="round"
                    strokeLinejoin="round"
                    strokeWidth={1.5}
                    d="M8 10h.01M12 10h.01M16 10h.01M9 16H5a2 2 0 01-2-2V6a2 2 0 012-2h14a2 2 0 012 2v8a2 2 0 01-2 2h-5l-5 5v-5z"
                  />
                </svg>
              </div>
              <h2 className="text-2xl font-semibold text-gray-800">Tech News AI</h2>
              <p className="text-gray-500 text-sm leading-relaxed">
                Ask questions about tech news, compare topics, explore timelines, or get simple
                explanations. All answers are grounded in our article database.
              </p>
              <button
                onClick={handleNewChat}
                className="inline-flex items-center gap-2 px-6 py-3 text-sm font-medium text-white bg-primary-600 hover:bg-primary-700 rounded-lg transition-colors"
              >
                <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
                </svg>
                Start a Conversation
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

// ---------------------------------------------------------------------------
// Page (wrapped in ChatProvider)
// ---------------------------------------------------------------------------
export default function ChatPage() {
  return (
    <ChatProvider>
      <ChatPageContent />
    </ChatProvider>
  );
}

"use client";

import { useEffect, useState } from "react";
import { useParams } from "next/navigation";
import { apiFetch } from "@/lib/api/client";
import Link from "next/link";
import { ConversationalSearch } from "@/components/ai/ConversationalSearch";
import { NotebookEditor } from "@/components/workspace/NotebookEditor";

export default function WorkspaceDashboard() {
  const params = useParams();
  const workspaceId = parseInt(params.id as string, 10);

  const [workspace, setWorkspace] = useState<any>(null);
  const [loading, setLoading] = useState(true);
  const [activeTab, setActiveTab] = useState<'articles' | 'notes' | 'timeline' | 'digest' | 'chat'>('articles');
  const [timeline, setTimeline] = useState<any[]>([]);
  const [digests, setDigests] = useState<any[]>([]);
  const [activeDigestId, setActiveDigestId] = useState<number | null>(null);
  const [generatingDigest, setGeneratingDigest] = useState(false);
  const [streamingDigestContent, setStreamingDigestContent] = useState("");

  const [newNote, setNewNote] = useState("");
  const [activeNoteId, setActiveNoteId] = useState<number | null>(null);

  const [searchQuery, setSearchQuery] = useState("");
  const [searchResults, setSearchResults] = useState<any[] | null>(null);
  const [isSearching, setIsSearching] = useState(false);

  useEffect(() => {
    fetchWorkspace();
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [workspaceId]);

  useEffect(() => {
    if (activeTab === 'timeline') {
      fetchTimeline();
    } else if (activeTab === 'digest') {
      fetchDigests();
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [activeTab, workspaceId]);

  const fetchDigests = async () => {
    try {
      const data: any = await apiFetch(`/workspaces/${workspaceId}/digests`);
      setDigests(data);
      if (data.length > 0 && !activeDigestId) {
        setActiveDigestId(data[0].id);
      }
    } catch (err) {
      // eslint-disable-next-line no-console
      console.error(err);
    }
  };

  const fetchTimeline = async () => {
    try {
      const data = await apiFetch(`/workspaces/${workspaceId}/timeline`);
      setTimeline(data as any[]);
    } catch (err) {
      // eslint-disable-next-line no-console
      console.error(err);
    }
  };

  const fetchWorkspace = async () => {
    try {
      const data = await apiFetch(`/workspaces/${workspaceId}`);
      setWorkspace(data);
    } catch (err) {
      // eslint-disable-next-line no-console
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const handleAddNote = async () => {
    if (!newNote.trim()) return;
    try {
      await apiFetch(`/workspaces/${workspaceId}/notes`, {
        method: "POST",
        body: JSON.stringify({ content: newNote }),
      });
      setNewNote("");
      fetchWorkspace(); // Refresh
    } catch (err) {
      // eslint-disable-next-line no-console
      console.error(err);
    }
  };

  const handleUpdateNote = async (noteId: number, content: string, title: string) => {
    try {
      await apiFetch(`/workspaces/${workspaceId}/notes/${noteId}`, {
        method: "PUT",
        body: JSON.stringify({ content, title }),
      });
      fetchWorkspace(); // Refresh list to get updated titles/summaries
    } catch (err) {
      // eslint-disable-next-line no-console
      console.error(err);
    }
  };

  const handleSummarizeNote = async (noteId: number) => {
    try {
      await apiFetch(`/workspaces/${workspaceId}/notes/${noteId}/summarize`, {
        method: "POST"
      });
      fetchWorkspace();
    } catch (err) {
      // eslint-disable-next-line no-console
      console.error(err);
    }
  };

  const handleSearchNotes = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!searchQuery.trim()) {
      setSearchResults(null);
      return;
    }
    setIsSearching(true);
    try {
      const data = await apiFetch(`/workspaces/${workspaceId}/notes/search/query?q=${encodeURIComponent(searchQuery)}`);
      setSearchResults(data as any[]);
    } catch (err) {
      // eslint-disable-next-line no-console
      console.error(err);
    } finally {
      setIsSearching(false);
    }
  };

  const handleDeleteArticle = async (articleId: number) => {
    try {
      await apiFetch(`/workspaces/${workspaceId}/articles/${articleId}`, {
        method: "DELETE",
      });
      fetchWorkspace(); // Refresh
    } catch (err) {
      // eslint-disable-next-line no-console
      console.error(err);
    }
  };

  const handleDeleteNote = async (noteId: number) => {
    try {
      await apiFetch(`/workspaces/${workspaceId}/notes/${noteId}`, {
        method: "DELETE",
      });
      fetchWorkspace(); // Refresh
    } catch (err) {
      // eslint-disable-next-line no-console
      console.error(err);
    }
  };

  const generateNewDigest = async () => {
    setGeneratingDigest(true);
    setStreamingDigestContent("");
    setActiveDigestId(null); // Deselect so we show the streaming view

    try {
      const response = await fetch(`/api/v1/workspaces/${workspaceId}/digests`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({})
      });

      const reader = response.body?.getReader();
      const decoder = new TextDecoder();

      if (!reader) return;

      while (true) {
        const { done, value } = await reader.read();
        if (done) break;

        const chunk = decoder.decode(value, { stream: true });
        const lines = chunk.split('\n\n');

        for (const line of lines) {
          if (line.startsWith('event: token')) {
            const dataStr = line.replace('event: token\ndata: ', '');
            try {
              const data = JSON.parse(dataStr);
              setStreamingDigestContent(prev => prev + data.text);
            // eslint-disable-next-line @typescript-eslint/no-unused-vars
            } catch(e) {}
          } else if (line.startsWith('event: completed')) {
            fetchDigests();
            setGeneratingDigest(false);
          }
        }
      }
    } catch (e) {
      // eslint-disable-next-line no-console
      console.error(e);
      setGeneratingDigest(false);
    }
  };

  if (loading) {
    return <div className="p-8 max-w-7xl mx-auto font-mono text-gray-500">Loading workspace...</div>;
  }

  if (!workspace) {
    return <div className="p-8 max-w-7xl mx-auto text-red-500">Workspace not found.</div>;
  }

  return (
    <div className="flex h-[calc(100vh-64px)] bg-gray-50">
      {/* Left Pane: Content Management */}
      <div className="flex-1 flex flex-col min-w-[300px] border-r border-gray-200 bg-white overflow-hidden">

        {/* Header */}
        <div className="p-6 border-b border-gray-100 flex items-center justify-between">
          <div>
            <Link href="/workspaces" className="text-sm text-gray-500 hover:text-primary-600 flex items-center mb-2 font-mono">
              <svg className="w-4 h-4 mr-1" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 19l-7-7m0 0l7-7m-7 7h18"/></svg>
              Back to Workspaces
            </Link>
            <h1 className="text-2xl font-bold font-mono">{workspace.name}</h1>
            <p className="text-sm text-gray-500 mt-1">{workspace.description || "Research Workspace"}</p>
          </div>
        </div>

        {/* Tabs */}
        <div className="flex border-b border-gray-200 px-6 pt-4 space-x-6">
          <button 
            onClick={() => setActiveTab('articles')}
            className={`pb-3 text-sm font-medium border-b-2 transition-colors ${activeTab === 'articles' ? 'border-primary-600 text-primary-600' : 'border-transparent text-gray-500 hover:text-gray-700'}`}
          >
            Pinned Articles ({workspace.articles?.length || 0})
          </button>
          <button 
            onClick={() => setActiveTab('notes')}
            className={`pb-3 text-sm font-medium border-b-2 transition-colors ${activeTab === 'notes' ? 'border-primary-600 text-primary-600' : 'border-transparent text-gray-500 hover:text-gray-700'}`}
          >
            My Notes ({workspace.notes?.length || 0})
          </button>
          <button 
            onClick={() => setActiveTab('timeline')}
            className={`pb-3 text-sm font-medium border-b-2 transition-colors ${activeTab === 'timeline' ? 'border-primary-600 text-primary-600' : 'border-transparent text-gray-500 hover:text-gray-700'}`}
          >
            Timeline
          </button>
          <button 
            onClick={() => setActiveTab('digest')}
            className={`pb-3 text-sm font-medium border-b-2 transition-colors ${activeTab === 'digest' ? 'border-primary-600 text-primary-600' : 'border-transparent text-gray-500 hover:text-gray-700'}`}
          >
            Daily Digest
          </button>
          <button 
            onClick={() => setActiveTab('chat')}
            className={`pb-3 text-sm font-medium border-b-2 transition-colors md:hidden ${activeTab === 'chat' ? 'border-primary-600 text-primary-600' : 'border-transparent text-gray-500 hover:text-gray-700'}`}
          >
            AI Assistant
          </button>
        </div>

        {/* Content Area */}
        <div className="flex-1 overflow-y-auto p-6 bg-gray-50">

          {/* ARTICLES TAB */}
          {activeTab === 'articles' && (
            <div className="space-y-4">
              {workspace.articles?.length === 0 ? (
                <div className="text-center py-10 bg-white border border-dashed border-gray-300 rounded-lg">
                  <p className="text-gray-500 text-sm">No articles pinned yet.</p>
                  // eslint-disable-next-line react/no-unescaped-entities
                  <p className="text-xs text-gray-400 mt-1">Browse articles and click "Pin to Workspace" to save them here.</p>
                </div>
              ) : (
                workspace.articles?.map((wa: any) => (
                  <div key={wa.id} className="bg-white border border-gray-200 rounded-lg p-4 shadow-sm flex items-start justify-between group">
                    <div className="flex-1 min-w-0 pr-4">
                      <h3 className="font-semibold text-gray-900 truncate">
                        <Link href={`/articles/${wa.article.slug}`} className="hover:text-primary-600 transition-colors">
                          {wa.article.title}
                        </Link>
                      </h3>
                      <p className="text-xs text-gray-500 mt-1 line-clamp-2">{wa.article.summary}</p>
                    </div>
                    <button 
                      onClick={() => handleDeleteArticle(wa.article_id)}
                      className="text-gray-400 hover:text-red-500 p-1 opacity-0 group-hover:opacity-100 transition-opacity"
                      title="Remove from Workspace"
                    >
                      <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                    </button>
                  </div>
                ))
              )}
            </div>
          )}

          {/* NOTES TAB */}
          {activeTab === 'notes' && (
            <div className="h-full flex flex-col">
              {activeNoteId ? (
                <div className="flex-1 flex flex-col h-full space-y-4">
                  <div className="flex justify-between items-center">
                    <button 
                      onClick={() => setActiveNoteId(null)}
                      className="text-sm font-medium text-gray-500 hover:text-gray-800 flex items-center"
                    >
                      <svg className="w-4 h-4 mr-1" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" /></svg>
                      Back to Notes
                    </button>
                  </div>
                  {(() => {
                    const activeNote = workspace.notes.find((n: any) => n.id === activeNoteId);
                    if (!activeNote) return null;
                    return (
                      <NotebookEditor 
                        workspaceId={workspaceId}
                        noteId={activeNote.id}
                        initialContent={activeNote.content}
                        initialTitle={activeNote.title || "Untitled Note"}
                        onSave={handleUpdateNote}
                        onSummarize={handleSummarizeNote}
                        className="flex-1"
                      />
                    );
                  })()}
                </div>
              ) : (
                <div className="space-y-6">
                  {/* Add Note */}
                  <div className="bg-white border border-gray-200 rounded-lg p-4 shadow-sm flex gap-3 items-center">
                    <input
                      type="text"
                      value={newNote}
                      onChange={(e) => setNewNote(e.target.value)}
                      placeholder="Start a new research note..."
                      className="flex-1 border border-gray-200 rounded-md px-3 py-2 text-sm focus:outline-none focus:border-primary-500"
                      onKeyDown={(e) => { if(e.key === 'Enter') handleAddNote() }}
                    />
                    <button 
                      onClick={handleAddNote}
                      disabled={!newNote.trim()}
                      className="px-4 py-2 bg-primary-600 text-white rounded-md text-sm font-medium hover:bg-primary-700 transition-colors disabled:opacity-50"
                    >
                      Create Note
                    </button>
                  </div>

                  {/* Note List */}
                  <div className="space-y-4">
                    <div className="mb-6 flex flex-col gap-2">
                      <form onSubmit={handleSearchNotes} className="flex gap-2">
                        <div className="relative flex-1">
                          <input 
                            type="text"
                            value={searchQuery}
                            onChange={(e) => {
                              setSearchQuery(e.target.value);
                              if (!e.target.value) setSearchResults(null);
                            }}
                            placeholder="Semantic search your notes..."
                            className="w-full border border-gray-200 rounded-md pl-9 pr-3 py-2 text-sm focus:outline-none focus:border-primary-500"
                          />
                          <svg className="w-4 h-4 text-gray-400 absolute left-3 top-2.5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
                        </div>
                        <button type="submit" disabled={isSearching || !searchQuery.trim()} className="px-3 py-2 bg-gray-100 hover:bg-gray-200 text-gray-700 rounded-md text-sm font-medium transition-colors disabled:opacity-50">
                          {isSearching ? 'Searching...' : 'Search'}
                        </button>
                      </form>
                      {searchResults && (
                        <div className="flex justify-between items-center text-xs text-gray-500">
                          <span>Found {searchResults.length} results</span>
                          <button onClick={() => {setSearchQuery(''); setSearchResults(null)}} className="hover:text-primary-600">Clear Search</button>
                        </div>
                      )}
                    </div>

                    {(searchResults || workspace.notes)?.length === 0 ? (
                      <div className="text-center py-6">
                        <p className="text-gray-500 text-sm">{searchResults ? "No results found for your search." : "No notes added yet."}</p>
                      </div>
                    ) : (
                      <div className="grid grid-cols-1 gap-4">
                        {(searchResults || workspace.notes)?.map((note: any) => (
                          <div key={note.id} className="bg-white border border-gray-200 rounded-lg p-4 shadow-sm group relative flex flex-col hover:border-primary-300 transition-colors cursor-pointer" onClick={() => setActiveNoteId(note.id)}>
                            <div className="flex justify-between items-start mb-2">
                              <h3 className="font-semibold text-gray-900 truncate pr-8">
                                {note.title || "Untitled Note"}
                                {note.score !== undefined && (
                                  <span className="ml-2 text-[10px] bg-primary-100 text-primary-800 px-1.5 py-0.5 rounded-full inline-flex align-middle">
                                    {(note.score * 100).toFixed(0)}% match
                                  </span>
                                )}
                              </h3>
                            </div>
                            {note.excerpt ? (
                              // eslint-disable-next-line react/no-unescaped-entities
                              <p className="text-sm text-gray-700 mb-3 flex-1 italic bg-yellow-50 p-2 rounded">"...{note.excerpt}..."</p>
                            ) : (
                              <p className="text-sm text-gray-500 line-clamp-2 mb-3 flex-1">{note.summary || note.content}</p>
                            )}

                            <div className="flex items-center justify-between mt-auto pt-3 border-t border-gray-50">
                              <div className="text-xs text-gray-400 font-mono flex items-center gap-2">
                                <span>v{note.version_number}</span>
                                {note.updated_at && (
                                  <>
                                    <span>&bull;</span>
                                    <span>{new Date(note.updated_at).toLocaleDateString()}</span>
                                  </>
                                )}
                              </div>
                              <div className="flex items-center gap-2">
                                <button 
                                  onClick={(e) => { e.stopPropagation(); handleSummarizeNote(note.id); }}
                                  className="text-xs text-primary-600 hover:text-primary-800 hover:bg-primary-50 px-2 py-1 rounded transition-colors"
                                >
                                  ✨ Auto-Summary
                                </button>
                                <button 
                                  onClick={(e) => { e.stopPropagation(); handleDeleteNote(note.id); }}
                                  className="text-gray-400 hover:text-red-500 p-1 opacity-0 group-hover:opacity-100 transition-opacity"
                                  title="Delete Note"
                                >
                                  <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                                </button>
                              </div>
                            </div>
                          </div>
                        ))}
                      </div>
                    )}
                  </div>
                </div>
              )}
            </div>
          )}

          {/* TIMELINE TAB */}
          {activeTab === 'timeline' && (
            <div className="space-y-6">
              {timeline.length === 0 ? (
                <div className="text-center py-6">
                  <p className="text-gray-500 text-sm">No activity recorded yet.</p>
                </div>
              ) : (
                <div className="relative border-l border-gray-200 ml-3 pl-4 space-y-6">
                  {timeline.map((event) => {
                    const date = new Date(event.created_at);

                    let label = "Activity";
                    switch(event.event_type) {
                      case 'ARTICLE_PINNED': label = `Pinned Article: ${event.metadata?.article_id || ''}`; break;
                      case 'ARTICLE_UNPINNED': label = `Unpinned Article: ${event.metadata?.article_id || ''}`; break;
                      case 'NOTE_CREATED': label = `Added Note`; break;
                      case 'NOTE_UPDATED': label = `Updated Note`; break;
                      case 'NOTE_DELETED': label = `Deleted Note`; break;
                      case 'CHAT_STARTED': label = `Started Conversation`; break;
                      case 'WORKSPACE_CREATED': label = `Created Workspace`; break;
                      case 'WORKSPACE_RENAMED': label = `Renamed to ${event.metadata?.new_name || ''}`; break;
                    }

                    return (
                      <div key={event.id} className="relative">
                        <div className="absolute -left-[21px] top-1 w-2.5 h-2.5 bg-primary-400 rounded-full border border-white"></div>
                        <div className="flex flex-col">
                          <span className="text-xs text-gray-400 font-mono mb-0.5">
                            {date.toLocaleDateString()} at {date.toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
                          </span>
                          <span className="text-sm text-gray-800">{label}</span>
                          {event.metadata?.content_preview && (
                            <span className="text-xs text-gray-500 italic mt-1 line-clamp-1 border-l-2 border-gray-200 pl-2">
                              // eslint-disable-next-line react/no-unescaped-entities
                              "{event.metadata.content_preview}..."
                            </span>
                          )}
                        </div>
                      </div>
                    );
                  })}
                </div>
              )}
            </div>
          )}

          {/* DIGEST TAB */}
          {activeTab === 'digest' && (
            <div className="h-full flex gap-6">
              {/* Digest Sidebar */}
              <div className="w-1/3 border-r border-gray-200 pr-4 flex flex-col">
                <button 
                  onClick={generateNewDigest}
                  disabled={generatingDigest}
                  className="w-full mb-6 px-4 py-2 bg-primary-600 text-white rounded-md text-sm font-medium hover:bg-primary-700 transition-colors disabled:opacity-50"
                >
                  {generatingDigest ? "Generating..." : "Generate New Digest"}
                </button>
                <div className="flex-1 overflow-y-auto space-y-2">
                  {digests.map((d: any) => (
                    <button
                      key={d.id}
                      onClick={() => setActiveDigestId(d.id)}
                      className={`w-full text-left p-3 rounded-lg border text-sm transition-colors ${
                        activeDigestId === d.id ? 'bg-primary-50 border-primary-200 text-primary-900' : 'bg-white border-gray-200 text-gray-700 hover:border-gray-300'
                      }`}
                    >
                      <div className="font-semibold">{new Date(d.created_at).toLocaleDateString()}</div>
                      <div className="text-xs text-gray-500 mt-1">Since {new Date(d.since_time).toLocaleDateString()}</div>
                    </button>
                  ))}
                  {digests.length === 0 && !generatingDigest && (
                    <p className="text-sm text-gray-500 text-center py-4">No digests generated yet.</p>
                  )}
                </div>
              </div>

              {/* Digest Content */}
              <div className="flex-1 overflow-y-auto pl-2">
                {generatingDigest ? (
                  <div className="bg-white border border-gray-200 rounded-lg p-6 shadow-sm">
                    <div className="flex items-center gap-2 mb-4">
                      <div className="w-2 h-2 bg-primary-500 rounded-full animate-pulse"></div>
                      <span className="text-sm font-mono text-gray-500 uppercase tracking-wider">Generating Digest...</span>
                    </div>
                    <div className="prose prose-sm max-w-none font-sans text-gray-800 whitespace-pre-wrap">
                      {streamingDigestContent}
                    </div>
                  </div>
                ) : activeDigestId ? (
                  <div className="bg-white border border-gray-200 rounded-lg p-6 shadow-sm relative group">
                    <button 
                      onClick={async () => {
                        const digest = digests.find(d => d.id === activeDigestId);
                        if (digest) {
                          await apiFetch(`/workspaces/${workspaceId}/notes`, {
                            method: 'POST',
                            body: JSON.stringify({
                              title: `Digest: ${new Date(digest.created_at).toLocaleDateString()}`,
                              content: `![[Digest:${new Date(digest.created_at).toLocaleDateString()}]]\n\n${digest.content}`
                            })
                          });
                          fetchWorkspace();
                          setActiveTab('notes');
                        }
                      }}
                      className="absolute top-4 right-4 text-xs font-medium bg-gray-100 hover:bg-gray-200 text-gray-700 px-3 py-1.5 rounded opacity-0 group-hover:opacity-100 transition-opacity"
                    >
                      Save as Note
                    </button>
                    {(() => {
                      const digest = digests.find(d => d.id === activeDigestId);
                      if (!digest) return null;
                      return (
                        <>
                          <div className="mb-6 pb-4 border-b border-gray-100">
                            <h2 className="text-xl font-bold mb-2">Daily Digest</h2>
                            <div className="text-sm text-gray-500 flex gap-4">
                              <span>Generated: {new Date(digest.created_at).toLocaleString()}</span>
                              <span>•</span>
                              <span>Since: {new Date(digest.since_time).toLocaleString()}</span>
                            </div>
                          </div>

                          {/* Rich rendering of the markdown content would ideally go through ReactMarkdown,
                              but for now we just render it with pre-wrap for structure */}
                          <div className="prose prose-sm max-w-none font-sans text-gray-800 whitespace-pre-wrap">
                            {digest.content}
                          </div>
                        </>
                      );
                    })()}
                  </div>
                ) : (
                  <div className="text-center py-20">
                    <p className="text-gray-500">Select a digest or generate a new one.</p>
                  </div>
                )}
              </div>
            </div>
          )}

          {/* Mobile Chat Tab (hidden on desktop) */}
          <div className={`md:hidden ${activeTab === 'chat' ? 'block' : 'hidden'} h-full`}>
             <div className="h-[600px] border border-gray-200 rounded-xl overflow-hidden bg-white">
              <ConversationalSearch 
                conversationId={null}
                initialMode="WORKSPACE" 
                workspaceId={workspaceId} 
              />
            </div>
          </div>

        </div>
      </div>

      {/* Right Pane: AI Assistant (Hidden on mobile when not active tab) */}
      <div className={`hidden md:flex md:w-[450px] lg:w-[500px] flex-col bg-white border-l border-gray-200 shadow-[-4px_0_15px_-3px_rgba(0,0,0,0.05)] z-10`}>
        <div className="p-4 border-b border-gray-100 bg-gray-50/50 flex items-center justify-between">
          <div className="flex items-center">
            <div className="w-2 h-2 bg-green-500 rounded-full mr-2"></div>
            <h2 className="font-semibold text-sm font-mono text-gray-700">Workspace Assistant</h2>
          </div>
          <div className="text-xs bg-primary-100 text-primary-700 px-2 py-1 rounded font-medium">
            WORKSPACE MODE
          </div>
        </div>

        <div className="flex-1 overflow-hidden">
          <ConversationalSearch 
            conversationId={null}
            initialMode="WORKSPACE" 
            workspaceId={workspaceId} 
          />
        </div>
      </div>

    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import { useSearchParams, useRouter } from "next/navigation";
import { apiFetch } from "../../../services/api";
import { Cpu, CircleDollarSign, RefreshCw, AlertCircle } from "lucide-react";

import { getAiJobs, getAiCosts, testAiPrompt, AIJob, CostAggregation } from "../../../services/api/admin";

export default function AdminAIPage() {
  const searchParams = useSearchParams();
  const router = useRouter();
  const activeTab = searchParams.get("tab") === "costs" ? "costs" : searchParams.get("tab") === "test" ? "test" : "queue";

  const [jobs, setJobs] = useState<AIJob[]>([]);
  const [costs, setCosts] = useState<CostAggregation | null>(null);
  const [loading, setLoading] = useState(true);
  const [refreshing, setRefreshing] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Prompt tester state
  const [testPromptVersion, setTestPromptVersion] = useState("summary_v2");
  const [testModel, setTestModel] = useState("gpt-4o-mini");
  const [testText, setTestText] = useState("");
  const [testResult, setTestResult] = useState<any>(null);
  const [testing, setTesting] = useState(false);

  const handleTestPrompt = async () => {
    if (!testText.trim()) return;
    setTesting(true);
    setTestResult(null);
    try {
      const res = await testAiPrompt({
        prompt_version: testPromptVersion,
        model: testModel,
        text: testText
      });
      setTestResult(res);
    } catch (err: any) {
      setTestResult({ status: "error", message: err.message });
    } finally {
      setTesting(false);
    }
  };

  const fetchAIOps = async (isSilent = false) => {
    if (activeTab === "test") {
      setLoading(false);
      setRefreshing(false);
      return;
    }
    if (!isSilent) setLoading(true);
    else setRefreshing(true);
    try {
      if (activeTab === "queue") {
        const data = await getAiJobs();
        setJobs(data);
      } else if (activeTab === "costs") {
        const data = await getAiCosts();
        setCosts(data);
      }
      setError(null);
    } catch (err: any) {
      setError(err.message || "Failed to load AI Operations stats.");
    } finally {
      setLoading(false);
      setRefreshing(false);
    }
  };

  useEffect(() => {
    fetchAIOps();
  }, [activeTab]);

  const switchTab = (tabName: "queue" | "costs" | "test") => {
    router.push(`/admin/ai?tab=${tabName}`);
  };

  if (loading) {
    return (
      <div className="space-y-4 font-mono text-[11px]">
        <div className="flex gap-2 border-b border-[#1a1a1a] pb-2">
          <div className="h-6 w-24 bg-neutral-900 animate-pulse" />
          <div className="h-6 w-24 bg-neutral-900 animate-pulse" />
        </div>
        <div className="border border-[#1a1a1a] bg-black p-4 h-64 animate-pulse" />
      </div>
    );
  }

  return (
    <div className="space-y-4">
      {/* Tabs / Header */}
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-3 border-b border-[#1a1a1a] pb-1">
        <div className="flex gap-1.5 font-mono text-[10px]">
          <button
            onClick={() => switchTab("queue")}
            className={`px-3 py-1.5 border border-b-0 border-[#1a1a1a] uppercase font-bold tracking-wider transition-colors ${
              activeTab === "queue"
                ? "bg-[#0c0c0c] text-white border-b-2 border-b-white"
                : "text-[#555] hover:text-[#ccc]"
            }`}
          >
            AI Ingestion Queue
          </button>
          <button
            onClick={() => switchTab("costs")}
            className={`px-3 py-1.5 border border-b-0 border-[#1a1a1a] uppercase font-bold tracking-wider transition-colors ${
              activeTab === "costs"
                ? "bg-[#0c0c0c] text-white border-b-2 border-b-white"
                : "text-[#555] hover:text-[#ccc]"
            }`}
          >
            Cost Analytics
          </button>
          <button
            onClick={() => switchTab("test")}
            className={`px-3 py-1.5 border border-b-0 border-[#1a1a1a] uppercase font-bold tracking-wider transition-colors ${
              activeTab === "test"
                ? "bg-[#0c0c0c] text-white border-b-2 border-b-white"
                : "text-[#555] hover:text-[#ccc]"
            }`}
          >
            Prompt Tester
          </button>
        </div>
        <button
          onClick={() => fetchAIOps(true)}
          disabled={refreshing}
          className="flex items-center gap-1.5 font-mono text-[9px] tracking-widest uppercase text-[#888] hover:text-white transition-colors disabled:opacity-50 self-end sm:self-center"
        >
          <RefreshCw className={`w-3 h-3 ${refreshing ? "animate-spin" : ""}`} />
          REFRESH
        </button>
      </div>

      {error && (
        <div className="border border-red-500/30 bg-red-500/5 px-3 py-2 flex items-center gap-2">
          <AlertCircle className="w-3.5 h-3.5 text-red-400 shrink-0" />
          <p className="font-mono text-[10px] text-red-400">{error}</p>
        </div>
      )}

      {/* Main Content */}
      {activeTab === "queue" ? (
        <div className="border border-[#1a1a1a] bg-black overflow-x-auto">
          <table className="w-full text-left font-mono text-[11px]">
            <thead>
              <tr className="border-b border-[#1a1a1a] bg-[#0c0c0c] text-[#555] select-none text-[9px]">
                <th className="p-3">JOB ID</th>
                <th className="p-3">ARTICLE ID</th>
                <th className="p-3">PROVIDER</th>
                <th className="p-3">MODEL</th>
                <th className="p-3">TOKENS (P/C)</th>
                <th className="p-3">COST</th>
                <th className="p-3">STATUS</th>
                <th className="p-3 text-right">COMPLETED</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-[#111]">
              {jobs.map((j) => (
                <tr key={j.id} className="hover:bg-[#060606] transition-colors">
                  <td className="p-3 text-[#555]">{j.id}</td>
                  <td className="p-3 text-[#ccc]">{j.raw_article_id}</td>
                  <td className="p-3 text-[#888] uppercase">{j.provider}</td>
                  <td className="p-3 text-[#888]">{j.model_name}</td>
                  <td className="p-3 text-[#ccc]">
                    {j.tokens_prompt} / {j.tokens_completion}
                  </td>
                  <td className="p-3 text-emerald-400">${j.cost_usd.toFixed(5)}</td>
                  <td className="p-3">
                    <span
                      className={`inline-flex items-center px-1.5 py-0.5 text-[8px] font-bold tracking-wider uppercase border ${
                        j.status === "completed"
                          ? "border-emerald-500/20 bg-emerald-500/5 text-emerald-400"
                          : j.status === "failed"
                          ? "border-red-500/20 bg-red-500/5 text-red-400"
                          : "border-blue-500/20 bg-blue-500/5 text-blue-400 animate-pulse"
                      }`}
                    >
                      {j.status}
                    </span>
                  </td>
                  <td className="p-3 text-right text-[#555]">
                    {j.completed_at ? new Date(j.completed_at).toLocaleTimeString() : "-"}
                  </td>
                </tr>
              ))}
              {jobs.length === 0 && (
                <tr>
                  <td colSpan={8} className="p-8 text-center text-[#555]">
                    No AI jobs processed in queue yet.
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      ) : activeTab === "costs" ? (
        costs && (
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            {/* Aggregate summary */}
            <div className="border border-[#1a1a1a] bg-[#0c0c0c] p-4 col-span-1 space-y-4">
              <h3 className="font-mono text-[9px] tracking-widest uppercase text-[#888] font-bold">
                FINANCIAL SUMMARY
              </h3>
              <div className="border border-[#1a1a1a] bg-black p-3.5">
                <p className="font-mono text-[8px] text-[#555] tracking-wider uppercase mb-1">
                  Total System Cost
                </p>
                <p className="font-mono text-3xl font-bold text-emerald-400">
                  ${costs.aggregated.total_cost_usd.toFixed(4)}
                </p>
              </div>
              <div className="grid grid-cols-2 gap-2 font-mono text-[10px]">
                <div className="border border-[#1a1a1a] bg-black p-2">
                  <p className="text-[#555] text-[7px] uppercase tracking-wider mb-1">
                    Prompt Tokens
                  </p>
                  <p className="text-[#ccc] font-bold">{costs.aggregated.prompt_tokens}</p>
                </div>
                <div className="border border-[#1a1a1a] bg-black p-2">
                  <p className="text-[#555] text-[7px] uppercase tracking-wider mb-1">
                    Completion Tokens
                  </p>
                  <p className="text-[#ccc] font-bold">{costs.aggregated.completion_tokens}</p>
                </div>
              </div>
            </div>

            {/* Model Breakdown */}
            <div className="border border-[#1a1a1a] bg-black p-4 col-span-2 overflow-x-auto">
              <h3 className="font-mono text-[9px] tracking-widest uppercase text-[#888] font-bold mb-3">
                EXPENSES BY MODEL TYPE
              </h3>
              <table className="w-full text-left font-mono text-[11px]">
                <thead>
                  <tr className="border-b border-[#1a1a1a] text-[#555] select-none text-[8px]">
                    <th className="pb-2">MODEL IDENTIFIER</th>
                    <th className="pb-2 text-right">TOTAL EXPENSES</th>
                    <th className="pb-2 text-right">TOTAL INGESTED JOBS</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-[#111]">
                  {costs.models_breakdown.map((m) => (
                    <tr key={m.model}>
                      <td className="py-2.5 text-[#ccc] font-semibold">{m.model}</td>
                      <td className="py-2.5 text-right text-emerald-400 font-bold">
                        ${m.cost.toFixed(4)}
                      </td>
                      <td className="py-2.5 text-right text-[#888]">{m.jobs_count}</td>
                    </tr>
                  ))}
                  {costs.models_breakdown.length === 0 && (
                    <tr>
                      <td colSpan={3} className="py-4 text-center text-[#555]">
                        No metrics registered yet.
                      </td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>
          </div>
        )
      ) : activeTab === "test" ? (
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          {/* Prompt Editor */}
          <div className="border border-[#1a1a1a] bg-black p-4 space-y-4">
            <h3 className="font-mono text-[9px] tracking-widest uppercase text-[#888] font-bold">
              PROMPT EDITOR & CONFIG
            </h3>
            <div className="space-y-3">
              <div>
                <label className="block text-[10px] text-[#555] uppercase tracking-wider mb-1">
                  Prompt Version
                </label>
                <input
                  type="text"
                  value={testPromptVersion}
                  onChange={(e) => setTestPromptVersion(e.target.value)}
                  className="w-full bg-[#0c0c0c] border border-[#1a1a1a] text-[#ccc] p-2 text-[11px] font-mono focus:outline-none focus:border-white transition-colors"
                />
              </div>
              <div>
                <label className="block text-[10px] text-[#555] uppercase tracking-wider mb-1">
                  Target Model
                </label>
                <select
                  value={testModel}
                  onChange={(e) => setTestModel(e.target.value)}
                  className="w-full bg-[#0c0c0c] border border-[#1a1a1a] text-[#ccc] p-2 text-[11px] font-mono focus:outline-none focus:border-white transition-colors"
                >
                  <option value="gpt-4o-mini">GPT-4o Mini</option>
                  <option value="gpt-4o">GPT-4o</option>
                  <option value="claude-3-haiku-20240307">Claude 3 Haiku</option>
                  <option value="claude-3-5-sonnet-20240620">Claude 3.5 Sonnet</option>
                </select>
              </div>
              <div>
                <label className="block text-[10px] text-[#555] uppercase tracking-wider mb-1">
                  Input Article Content
                </label>
                <textarea
                  value={testText}
                  onChange={(e) => setTestText(e.target.value)}
                  placeholder="Paste raw article content to summarize..."
                  className="w-full bg-[#0c0c0c] border border-[#1a1a1a] text-[#ccc] p-2 h-40 text-[11px] font-mono focus:outline-none focus:border-white transition-colors resize-none"
                />
              </div>
              <button
                onClick={handleTestPrompt}
                disabled={testing || !testText.trim()}
                className="w-full bg-white text-black font-bold uppercase tracking-wider text-[11px] py-2 hover:bg-[#ccc] transition-colors disabled:opacity-50"
              >
                {testing ? "Testing Prompt..." : "Execute Test"}
              </button>
            </div>
          </div>

          {/* Test Results */}
          <div className="border border-[#1a1a1a] bg-black p-4 space-y-4">
            <h3 className="font-mono text-[9px] tracking-widest uppercase text-[#888] font-bold">
              EXECUTION RESULTS
            </h3>
            {testResult ? (
              <div className="space-y-3">
                {testResult.status === "success" ? (
                  <>
                    <div className="grid grid-cols-3 gap-2 font-mono text-[9px] uppercase tracking-wider">
                      <div className="border border-[#1a1a1a] bg-[#0c0c0c] p-2">
                        <p className="text-[#555] mb-1">Tokens (P/C)</p>
                        <p className="text-[#ccc] font-bold">
                          {testResult.raw_response?.usage?.prompt_tokens || 0} /{" "}
                          {testResult.raw_response?.usage?.completion_tokens || 0}
                        </p>
                      </div>
                      <div className="border border-[#1a1a1a] bg-[#0c0c0c] p-2">
                        <p className="text-[#555] mb-1">Latency</p>
                        <p className="text-[#ccc] font-bold">
                          {testResult.raw_response?.latency_ms || 0} ms
                        </p>
                      </div>
                      <div className="border border-emerald-500/20 bg-emerald-500/5 p-2">
                        <p className="text-emerald-500 mb-1">Cache Hit</p>
                        <p className="text-emerald-400 font-bold">
                          {testResult.raw_response?.cache_hit ? "YES" : "NO"}
                        </p>
                      </div>
                    </div>
                    <div>
                      <label className="block text-[10px] text-[#555] uppercase tracking-wider mb-1 mt-2">
                        System Prompt
                      </label>
                      <div className="bg-[#0c0c0c] border border-[#1a1a1a] p-3 max-h-32 overflow-y-auto">
                        <pre className="text-[10px] text-[#888] whitespace-pre-wrap font-mono">
                          {testResult.system_prompt || "-"}
                        </pre>
                      </div>

                      <label className="block text-[10px] text-[#555] uppercase tracking-wider mb-1 mt-3">
                        User Prompt
                      </label>
                      <div className="bg-[#0c0c0c] border border-[#1a1a1a] p-3 max-h-32 overflow-y-auto">
                        <pre className="text-[10px] text-[#888] whitespace-pre-wrap font-mono">
                          {testResult.user_prompt || "-"}
                        </pre>
                      </div>

                      <label className="block text-[10px] text-[#555] uppercase tracking-wider mb-1 mt-3">
                        Generated Output Payload
                      </label>
                      <div className="bg-[#0c0c0c] border border-[#1a1a1a] p-3 max-h-60 overflow-y-auto">
                        <pre className="text-[10px] text-emerald-400 whitespace-pre-wrap font-mono">
                          {JSON.stringify(testResult.raw_response?.payload, null, 2)}
                        </pre>
                      </div>
                    </div>
                  </>
                ) : (
                  <div className="border border-red-500/30 bg-red-500/5 p-3">
                    <p className="text-red-400 text-[11px] font-mono whitespace-pre-wrap">
                      {testResult.message}
                    </p>
                  </div>
                )}
              </div>
            ) : (
              <div className="h-full flex items-center justify-center text-[#555] font-mono text-[11px] italic">
                Awaiting execution...
              </div>
            )}
          </div>
        </div>
      ) : null}
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import { apiFetch } from "../../../services/api";
import { ScrollText, RefreshCw, AlertCircle, ChevronLeft, ChevronRight } from "lucide-react";

interface AuditLog {
  id: number;
  user_email: string;
  action: string;
  resource: string;
  metadata: any;
  ip_address: string | null;
  device: string | null;
  created_at: string;
}

interface PaginatedAuditLogs {
  data: AuditLog[];
  pagination: {
    next_cursor: string | null;
    has_more: boolean;
    limit: number;
  };
}

export default function AdminAuditPage() {
  const [logs, setLogs] = useState<AuditLog[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [refreshing, setRefreshing] = useState(false);
  const [cursorStack, setCursorStack] = useState<(string | null)[]>([null]);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [hasMore, setHasMore] = useState(false);

  // Filters State
  const [actionFilter, setActionFilter] = useState("");
  const [userFilterInput, setUserFilterInput] = useState("");
  const [userFilter, setUserFilter] = useState("");
  const [startDate, setStartDate] = useState("");
  const [endDate, setEndDate] = useState("");

  // Debounce Operator filter text input
  useEffect(() => {
    const delayDebounce = setTimeout(() => {
      setUserFilter(userFilterInput);
    }, 400);
    return () => clearTimeout(delayDebounce);
  }, [userFilterInput]);

  const fetchLogs = async (cursor: string | null = null, isSilent = false) => {
    if (!isSilent) setLoading(true);
    else setRefreshing(true);
    try {
      const params: Record<string, string> = { limit: "30" };
      if (cursor) params.cursor = cursor;
      if (actionFilter) params.action_filter = actionFilter;
      if (userFilter.trim()) params.user_filter = userFilter.trim();
      if (startDate) params.start_date = startDate;
      if (endDate) params.end_date = endDate;

      const res = await apiFetch<PaginatedAuditLogs>("/admin/audit-logs", { params });
      setLogs(res && Array.isArray(res.data) ? res.data : []);
      setHasMore(res && res.pagination ? !!res.pagination.has_more : false);
      
      // Update cursors for pagination
      if (res && res.pagination && res.pagination.next_cursor) {
        if (!cursorStack.includes(res.pagination.next_cursor)) {
          setCursorStack((prev) => [...prev, res.pagination.next_cursor]);
        }
      }
      setError(null);
    } catch (err: any) {
      setError(err.message || "Failed to retrieve historical audit logs.");
    } finally {
      setLoading(false);
      setRefreshing(false);
    }
  };

  useEffect(() => {
    fetchLogs(cursorStack[currentIndex]);
  }, [currentIndex]);

  // Reset pagination when filters change
  useEffect(() => {
    setCursorStack([null]);
    if (currentIndex === 0) {
      fetchLogs(null);
    } else {
      setCurrentIndex(0);
    }
  }, [actionFilter, userFilter, startDate, endDate]);

  const handleNext = () => {
    if (hasMore) {
      setCurrentIndex((prev) => prev + 1);
    }
  };

  const handlePrev = () => {
    if (currentIndex > 0) {
      setCurrentIndex((prev) => prev - 1);
    }
  };

  if (loading) {
    return (
      <div className="space-y-4 font-mono text-[11px]">
        <div className="h-4 bg-neutral-900 w-48 animate-pulse" />
        <div className="border border-[#1a1a1a] bg-black p-4 space-y-4">
          <div className="h-8 bg-neutral-950 animate-pulse w-full border-b border-[#111]" />
          <div className="h-8 bg-neutral-950 animate-pulse w-full" />
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-4">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-2">
          <ScrollText className="w-3.5 h-3.5 text-[#888]" />
          <h1 className="font-mono text-[11px] tracking-widest uppercase text-white font-bold">
            PLATFORM OPERATIONS AUDIT LOGS
          </h1>
        </div>
        <button
          onClick={() => fetchLogs(cursorStack[currentIndex], true)}
          disabled={refreshing}
          className="flex items-center gap-1.5 font-mono text-[9px] tracking-widest uppercase text-[#888] hover:text-white transition-colors disabled:opacity-50"
        >
          <RefreshCw className={`w-3 h-3 ${refreshing ? "animate-spin" : ""}`} />
          REFRESH
        </button>
      </div>

      {/* Filters Bar */}
      <div className="border border-[#1a1a1a] bg-[#0c0c0c] p-3 grid grid-cols-1 md:grid-cols-4 gap-3">
        <div className="flex flex-col gap-1.5">
          <label className="font-mono text-[9px] tracking-widest uppercase text-[#555] select-none">
            ACTION EVENT
          </label>
          <select
            value={actionFilter}
            onChange={(e) => setActionFilter(e.target.value)}
            className="w-full bg-black border border-[#1a1a1a] px-2.5 py-1.5 font-mono text-[11px] text-white focus:outline-none focus:border-white transition-colors"
          >
            <option value="">ALL EVENTS</option>
            <option value="UPDATE_SOURCE">UPDATE_SOURCE</option>
            <option value="DELETE_SOURCE">DELETE_SOURCE</option>
            <option value="RESTORE_SOURCE">RESTORE_SOURCE</option>
            <option value="TOGGLE_SOURCE">TOGGLE_SOURCE</option>
            <option value="TRIGGER_CRAWL">TRIGGER_CRAWL</option>
            <option value="MODERATE_ARTICLE">MODERATE_ARTICLE</option>
            <option value="UPDATE_USER_ROLE">UPDATE_USER_ROLE</option>
            <option value="UPDATE_USER_STATUS">UPDATE_USER_STATUS</option>
            <option value="TOGGLE_FEATURE_FLAG">TOGGLE_FEATURE_FLAG</option>
            <option value="TOGGLE_EMERGENCY_CUTOFF">TOGGLE_EMERGENCY_CUTOFF</option>
            <option value="UPDATE_ARTICLE">UPDATE_ARTICLE</option>
            <option value="ROLLBACK_ARTICLE">ROLLBACK_ARTICLE</option>
          </select>
        </div>

        <div className="flex flex-col gap-1.5">
          <label className="font-mono text-[9px] tracking-widest uppercase text-[#555] select-none">
            OPERATOR EMAIL/ID
          </label>
          <input
            type="text"
            value={userFilterInput}
            onChange={(e) => setUserFilterInput(e.target.value)}
            placeholder="EMAIL OR ID..."
            className="w-full bg-black border border-[#1a1a1a] px-2.5 py-1.5 font-mono text-[11px] text-white focus:outline-none focus:border-white placeholder-neutral-700 transition-colors"
          />
        </div>

        <div className="flex flex-col gap-1.5">
          <label className="font-mono text-[9px] tracking-widest uppercase text-[#555] select-none">
            START DATE
          </label>
          <input
            type="date"
            value={startDate}
            onChange={(e) => setStartDate(e.target.value)}
            className="w-full bg-black border border-[#1a1a1a] px-2.5 py-1.5 font-mono text-[11px] text-white focus:outline-none focus:border-white transition-colors"
          />
        </div>

        <div className="flex flex-col gap-1.5">
          <label className="font-mono text-[9px] tracking-widest uppercase text-[#555] select-none">
            END DATE
          </label>
          <div className="flex gap-2">
            <input
              type="date"
              value={endDate}
              onChange={(e) => setEndDate(e.target.value)}
              className="flex-1 bg-black border border-[#1a1a1a] px-2.5 py-1.5 font-mono text-[11px] text-white focus:outline-none focus:border-white transition-colors"
            />
            {(actionFilter || userFilterInput || startDate || endDate) && (
              <button
                onClick={() => {
                  setActionFilter("");
                  setUserFilterInput("");
                  setStartDate("");
                  setEndDate("");
                }}
                className="font-mono text-[9px] tracking-widest uppercase text-[#888] hover:text-white transition-colors border border-[#1a1a1a] px-2.5 py-1.5 bg-black text-center shrink-0"
              >
                RESET
              </button>
            )}
          </div>
        </div>
      </div>

      {error && (
        <div className="border border-red-500/30 bg-red-500/5 px-3 py-2 flex items-center gap-2">
          <AlertCircle className="w-3.5 h-3.5 text-red-400 shrink-0" />
          <p className="font-mono text-[10px] text-red-400">{error}</p>
        </div>
      )}

      {/* Logs Table */}
      <div className="border border-[#1a1a1a] bg-black overflow-x-auto">
        <table className="w-full text-left font-mono text-[11px]">
          <thead>
            <tr className="border-b border-[#1a1a1a] bg-[#0c0c0c] text-[#555] select-none text-[9px]">
              <th className="p-3">TIMESTAMP</th>
              <th className="p-3">OPERATOR / EMAIL</th>
              <th className="p-3">ACTION EVENT</th>
              <th className="p-3">TARGET RESOURCE</th>
              <th className="p-3">IP ADDRESS</th>
              <th className="p-3 text-right">PAYLOAD METADATA</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-[#111]">
            {logs.map((l) => (
              <tr key={l.id} className="hover:bg-[#060606] transition-colors leading-relaxed">
                <td className="p-3 text-[#555]">{new Date(l.created_at).toLocaleString()}</td>
                <td className="p-3 text-white font-semibold">{l.user_email}</td>
                <td className="p-3">
                  <span className="inline-flex items-center px-1.5 py-0.5 text-[8px] font-bold tracking-wider uppercase border border-neutral-700 bg-neutral-900 text-[#ccc]">
                    {l.action}
                  </span>
                </td>
                <td className="p-3 text-[#888]">{l.resource}</td>
                <td className="p-3 text-[#555]">{l.ip_address || "System"}</td>
                <td className="p-3 text-right max-w-[200px] truncate text-[9px] text-[#888]" title={JSON.stringify(l.metadata)}>
                  {JSON.stringify(l.metadata)}
                </td>
              </tr>
            ))}
            {logs.length === 0 && (
              <tr>
                <td colSpan={6} className="p-8 text-center text-[#555]">
                  No administrative audit records logged.
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>

      {/* Pagination Controls */}
      <div className="flex justify-between items-center font-mono text-[9px] tracking-widest uppercase text-[#555] pt-2">
        <button
          onClick={handlePrev}
          disabled={currentIndex === 0}
          className="flex items-center gap-1 hover:text-white disabled:opacity-30 disabled:hover:text-[#555] transition-colors"
        >
          <ChevronLeft className="w-3.5 h-3.5" />
          PREVIOUS
        </button>
        <span>PAGE {currentIndex + 1}</span>
        <button
          onClick={handleNext}
          disabled={!hasMore}
          className="flex items-center gap-1 hover:text-white disabled:opacity-30 disabled:hover:text-[#555] transition-colors"
        >
          NEXT
          <ChevronRight className="w-3.5 h-3.5" />
        </button>
      </div>
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import { apiFetch } from "../../../services/api";
import { ShieldAlert, AlertCircle, RefreshCw, Radio } from "lucide-react";

export default function AdminEmergencyPage() {
  const [cutoffActive, setCutoffActive] = useState(false);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [refreshing, setRefreshing] = useState(false);
  const [acting, setActing] = useState(false);
  const [message, setMessage] = useState<string | null>(null);

  const fetchSwitch = async (isSilent = false) => {
    if (!isSilent) setLoading(true);
    else setRefreshing(true);
    try {
      const res: any = await apiFetch("/admin/emergency-switch");
      setCutoffActive(res.cutoff_active);
      setError(null);
    } catch (err: any) {
      setError(err.message || "Failed to retrieve emergency cutoff configuration.");
    } finally {
      setLoading(false);
      setRefreshing(false);
    }
  };

  useEffect(() => {
    fetchSwitch();
  }, []);

  const handleToggle = async (targetState: boolean) => {
    setActing(true);
    setMessage(null);
    try {
      const res: any = await apiFetch("/admin/emergency-switch/toggle", {
        method: "POST",
        body: JSON.stringify({ state: targetState }),
      });
      setCutoffActive(res.cutoff_active);
      setMessage(res.message);
    } catch (err: any) {
      setError(err.message || "Failed to update emergency cutoff state.");
    } finally {
      setActing(false);
    }
  };

  if (loading) {
    return (
      <div className="space-y-4 font-mono text-[11px]">
        <div className="h-4 bg-neutral-900 w-48 animate-pulse" />
        <div className="border border-red-500/10 bg-red-500/5 p-8 h-48 animate-pulse" />
      </div>
    );
  }

  return (
    <div className="space-y-4">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-2">
          <ShieldAlert className="w-3.5 h-3.5 text-red-500" />
          <h1 className="font-mono text-[11px] tracking-widest uppercase text-white font-bold">
            GLOBAL EMERGENCY CUTOFF
          </h1>
        </div>
        <button
          onClick={() => fetchSwitch(true)}
          disabled={refreshing}
          className="flex items-center gap-1.5 font-mono text-[9px] tracking-widest uppercase text-[#888] hover:text-white transition-colors disabled:opacity-50"
        >
          <RefreshCw className={`w-3 h-3 ${refreshing ? "animate-spin" : ""}`} />
          REFRESH
        </button>
      </div>

      {/* banners */}
      {error && (
        <div className="border border-red-500/30 bg-red-500/5 px-3 py-2 flex items-center gap-2">
          <AlertCircle className="w-3.5 h-3.5 text-red-400 shrink-0" />
          <p className="font-mono text-[10px] text-red-400">{error}</p>
        </div>
      )}

      {message && (
        <div className="border border-emerald-500/30 bg-emerald-500/5 px-3 py-2">
          <p className="font-mono text-[10px] text-emerald-400">{message}</p>
        </div>
      )}

      {/* Main warning control block */}
      <div className="border border-red-500/30 bg-black/60 p-6 space-y-6">
        <div className="space-y-2">
          <h3 className="font-mono text-xs font-bold text-red-400 tracking-wider uppercase">
            GLOBAL PIPELINE CUTOFF CONTROLLER
          </h3>
          <p className="font-sans text-[11px] text-[#888] leading-relaxed">
            Activating the global cutoff immediately halts all background crawl engines, Redis
            scraping queue workers, and AI ingestion scripts. Use this control in case of scraper malfunctions, rate-limit bans, or database maintenance cycles.
          </p>
        </div>

        <div className="border-t border-[#1a1a1a] pt-6 flex flex-col sm:flex-row items-center justify-between gap-4">
          <div className="flex items-center gap-3">
            <span
              className={`h-3 w-3 shrink-0 rounded-full ${
                cutoffActive ? "bg-red-500 animate-pulse" : "bg-emerald-500"
              }`}
            />
            <span className="font-mono text-xs font-bold text-white tracking-widest uppercase">
              CUTOFF STATUS: {cutoffActive ? "ACTIVE (PIPELINE STOPPED)" : "INACTIVE (RUNNING)"}
            </span>
          </div>

          <button
            onClick={() => handleToggle(!cutoffActive)}
            disabled={acting}
            className={`font-mono text-[10px] tracking-widest uppercase font-bold px-4 py-2 hover:bg-neutral-300 transition-all ${
              cutoffActive
                ? "bg-emerald-500 text-black hover:bg-emerald-400"
                : "bg-red-500 text-black hover:bg-red-400"
            } disabled:opacity-50`}
          >
            {acting
              ? "EXECUTING SHUTDOWN..."
              : cutoffActive
              ? "RESUME INGESTION ENGINE"
              : "CUTOFF ALL ENGINES"}
          </button>
        </div>
      </div>
    </div>
  );
}

"use client";

import { useEffect, useState, useRef } from "react";
import { apiFetch } from "../../services/api";
import {
  Activity,
  Database,
  Radio,
  Cpu,
  Server,
  AlertCircle,
  RefreshCw,
} from "lucide-react";

interface ServiceState {
  service: string;
  status: "ONLINE" | "DEGRADED" | "OFFLINE" | "UNKNOWN";
  latency_ms: number;
  last_checked: string;
  last_success?: string;
  error?: string;
}

interface HistorySample {
  timestamp: string;
  status: string;
  latency_ms: number;
}

interface ServiceContainer {
  snapshot: ServiceState;
  history: HistorySample[];
}

interface InfraPayload {
  health_score: {
    score: number;
    grade: string;
    calculated_at: string;
  };
  services: {
    postgres: ServiceContainer;
    redis: ServiceContainer;
    worker: ServiceContainer;
    beat: ServiceContainer;
    backend: ServiceContainer;
    nginx: ServiceContainer;
  };
}

interface QueuePayload {
  status: string;
  last_checked: string;
  metrics: {
    queue_depth: number;
    processing_rate_jobs_min: number;
    growth_rate_jobs_5s: number;
  };
}

interface OverviewPayload {
  source_health: {
    total: number;
    healthy: number;
    degraded: number;
    failed: number;
  };
  article_pipeline: {
    raw: number;
    processed: number;
    published: number;
    draft: number;
    rejected: number;
  };
  ai_queue: {
    queued: number;
    processing: number;
    completed: number;
    failed: number;
    retry: number;
  };
  emergency_cutoff_active: boolean;
}

interface LiveEvent {
  time: string;
  agent: string;
  msg: string;
  status?: string;
}

function MetricBox({
  label,
  value,
  color = "text-white",
  pulse = false,
}: {
  label: string;
  value: number | string;
  color?: string;
  pulse?: boolean;
}) {
  return (
    <div className="border border-[#1a1a1a] bg-[#080808] p-3">
      <p className="font-mono text-[8px] tracking-widest uppercase text-[#555] mb-1">{label}</p>
      <p className={`font-mono text-xl font-bold ${color} ${pulse ? "animate-pulse" : ""}`}>
        {value}
      </p>
    </div>
  );
}

function InfraStatus({
  label,
  status,
  latency,
  last_checked,
  last_success,
  history = [],
}: {
  label: string;
  status?: string;
  latency?: number;
  last_checked?: string;
  last_success?: string;
  history?: HistorySample[];
}) {
  const normStatus = (status || "").toUpperCase();
  const isOnline = normStatus === "ONLINE";
  const isDegraded = normStatus === "DEGRADED";
  const isOffline = normStatus === "OFFLINE";

  let dotColor = "bg-[#888]";
  let textColor = "text-[#888]";
  let labelText = "UNKNOWN";

  if (isOnline) {
    dotColor = "bg-emerald-500";
    textColor = "text-emerald-400";
    labelText = "ONLINE";
  } else if (isDegraded) {
    dotColor = "bg-amber-500";
    textColor = "text-amber-400";
    labelText = "DEGRADED";
  } else if (isOffline) {
    dotColor = "bg-red-500";
    textColor = "text-red-500";
    labelText = "OFFLINE";
  }

  const tooltip = `Service: ${label}
Status: ${labelText}
Latency: ${latency !== undefined ? latency + 'ms' : 'N/A'}
Last Checked: ${last_checked ? new Date(last_checked).toLocaleString() : 'N/A'}
Last Success: ${last_success ? new Date(last_success).toLocaleString() : 'N/A'}`;

  return (
    <div className="border-b border-[#111] py-2 cursor-help" title={tooltip}>
      <div className="flex items-center gap-2">
        <span className={`h-2 w-2 shrink-0 ${dotColor}`} />
        <span className="font-mono text-[10px] text-[#ccc]">{label}</span>
        {latency !== undefined && latency !== null && latency > 0 && (
          <span className="font-mono text-[8px] text-[#555]">({latency}ms)</span>
        )}
        <span
          className={`ml-auto font-mono text-[8px] tracking-widest uppercase ${textColor}`}
        >
          {labelText}
        </span>
      </div>
      
      {/* 10-sample rolling history dots */}
      {history && history.length > 0 && (
        <div className="flex items-center gap-1 mt-1 pl-4">
          <span className="font-mono text-[7px] text-[#444] mr-1">HIST:</span>
          {[...history].reverse().map((h, i) => {
            const hStatus = (h.status || "").toUpperCase();
            let c = "bg-[#333]";
            if (hStatus === "ONLINE") c = "bg-emerald-500/60";
            else if (hStatus === "DEGRADED") c = "bg-amber-500/60";
            else if (hStatus === "OFFLINE") c = "bg-red-500/60";
            return (
              <span
                key={i}
                className={`h-1 w-1 rounded-sm ${c}`}
                title={`Checked: ${new Date(h.timestamp).toLocaleTimeString()}
Latency: ${h.latency_ms}ms
Status: ${hStatus}`}
              />
            );
          })}
        </div>
      )}
    </div>
  );
}

function SkeletonCard() {
  return (
    <div className="border border-[#1a1a1a] bg-[#0c0c0c] p-4 animate-pulse">
      <div className="h-3 bg-neutral-900 w-1/3 mb-3" />
      <div className="grid grid-cols-2 gap-2">
        <div className="h-14 bg-neutral-900" />
        <div className="h-14 bg-neutral-900" />
        <div className="h-14 bg-neutral-900" />
        <div className="h-14 bg-neutral-900" />
      </div>
    </div>
  );
}

export default function AdminDashboardPage() {
  const [overview, setOverview] = useState<OverviewPayload | null>(null);
  const [infra, setInfra] = useState<InfraPayload | null>(null);
  const [queue, setQueue] = useState<QueuePayload | null>(null);

  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [events, setEvents] = useState<LiveEvent[]>([]);
  const [refreshing, setRefreshing] = useState(false);
  const feedRef = useRef<HTMLDivElement>(null);

  const fetchOverview = async () => {
    try {
      const result = await apiFetch<any>("/admin/overview");
      console.log("DEBUG: fetchOverview returned", result);
      if (result && result.data) {
        console.log("DEBUG: fetchOverview setting overview to", result.data);
        setOverview(result.data);
      } else {
        console.warn("DEBUG: fetchOverview result.data is missing!");
      }
    } catch (err: any) {
      console.error("Failed to load overview:", err);
      setError("Failed to connect to monitoring platform API.");
    }
  };

  const fetchInfra = async () => {
    try {
      const result = await apiFetch<any>("/admin/infrastructure");
      console.log("DEBUG: fetchInfra returned", result);
      if (result && result.data) {
        console.log("DEBUG: fetchInfra setting infra to", result.data);
        setInfra(result.data);
      } else {
        console.warn("DEBUG: fetchInfra result.data is missing!");
      }
    } catch (err: any) {
      console.error("Failed to load infrastructure:", err);
    }
  };

  const fetchQueue = async () => {
    try {
      const result = await apiFetch<any>("/admin/queue");
      console.log("DEBUG: fetchQueue returned", result);
      if (result && result.data) {
        console.log("DEBUG: fetchQueue setting queue to", result.data);
        setQueue(result.data);
      } else {
        console.warn("DEBUG: fetchQueue result.data is missing!");
      }
    } catch (err: any) {
      console.error("Failed to load queue telemetry:", err);
    }
  };

  const fetchLogs = async () => {
    try {
      const result = await apiFetch<any[]>("/admin/logs");
      if (result && Array.isArray(result)) {
        const initialEvents = result.map((parsed: any) => ({
          time: parsed.timestamp || new Date().toLocaleTimeString("en-US", { hour12: false, hour: "2-digit", minute: "2-digit" }),
          agent: parsed.agent,
          msg: parsed.msg,
          status: parsed.status,
        }));
        setEvents(initialEvents);
      }
    } catch (err) {
      console.error("Failed to load logs:", err);
    }
  };

  const handleManualRefresh = async () => {
    setRefreshing(true);
    try {
      await Promise.all([fetchOverview(), fetchInfra(), fetchQueue(), fetchLogs()]);
      setError(null);
    } catch (err: any) {
      setError(err.message || "Failed to load dashboard data.");
    } finally {
      setRefreshing(false);
    }
  };

  useEffect(() => {
    const init = async () => {
      try {
        await Promise.all([fetchOverview(), fetchInfra(), fetchQueue(), fetchLogs()]);
      } catch (e) {
        // Catch gracefully
      } finally {
        setLoading(false);
      }
    };

    init();

    // Independent polling rates
    const queueInterval = setInterval(fetchQueue, 5000); // Queue is 5s
    const infraInterval = setInterval(fetchInfra, 10000); // Infra checks is 10s
    const overviewInterval = setInterval(fetchOverview, 60000); // Overview checks is 60s

    return () => {
      clearInterval(queueInterval);
      clearInterval(infraInterval);
      clearInterval(overviewInterval);
    };
  }, []);

  // SSE for live operations feed (Initial Load then stream forever)
  useEffect(() => {
    const apiBase = process.env.NEXT_PUBLIC_API_URL || "/api/v1";
    let sseUrl = `${apiBase}/events/stream`;
    if (typeof window !== "undefined") {
      if (sseUrl.startsWith("/")) {
        sseUrl = `${window.location.protocol}//${window.location.host}${sseUrl}`;
      }
      if (sseUrl.includes(":3000")) {
        sseUrl = sseUrl.replace(":3000", "");
      }
    }

    let eventSource: EventSource | null = null;
    let reconnectDelay = 1000;
    let reconnectTimer: NodeJS.Timeout | null = null;

    const connect = () => {
      if (eventSource) eventSource.close();
      if (reconnectTimer) clearTimeout(reconnectTimer);

      eventSource = new EventSource(sseUrl);

      eventSource.onmessage = (event) => {
        try {
          const parsed = JSON.parse(event.data);
          if (parsed.agent && parsed.msg) {
            const entry: LiveEvent = {
              time: parsed.time || new Date().toLocaleTimeString("en-US", { hour12: false, hour: "2-digit", minute: "2-digit" }),
              agent: parsed.agent,
              msg: parsed.msg,
              status: parsed.status,
            };
            setEvents((prev) => [entry, ...prev.slice(0, 49)]);
          }
        } catch {
          // Skip non-JSON keepalives
        }
      };

      eventSource.onerror = () => {
        eventSource?.close();
        reconnectTimer = setTimeout(() => {
          reconnectDelay = Math.min(reconnectDelay * 2, 30000);
          connect();
        }, reconnectDelay);
      };

      eventSource.onopen = () => {
        reconnectDelay = 1000;
      };
    };

    connect();

    return () => {
      if (eventSource) eventSource.close();
      if (reconnectTimer) clearTimeout(reconnectTimer);
    };
  }, []);

  const healthScore = infra?.health_score;

  if (loading) {
    return (
      <div className="space-y-4">
        <div className="flex items-center justify-between">
          <div className="h-5 bg-neutral-900 w-48 animate-pulse" />
        </div>
        <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-4 gap-4">
          <SkeletonCard />
          <SkeletonCard />
          <SkeletonCard />
          <SkeletonCard />
        </div>
        <div className="border border-[#1a1a1a] bg-black p-4 h-64 animate-pulse" />
      </div>
    );
  }

  return (
    <div className="space-y-4">
      {/* Header with high level grade and score */}
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-2">
          <span className={`h-2 w-2 ${healthScore && healthScore.score < 80 ? "bg-red-500" : "bg-emerald-500"} animate-pulse`} />
          <h1 className="font-mono text-[11px] tracking-widest uppercase text-white font-bold">
            COMMAND CENTER {healthScore && `| HEALTH: ${healthScore.score}% (${healthScore.grade})`}
          </h1>
        </div>
        <button
          onClick={handleManualRefresh}
          disabled={refreshing}
          className="flex items-center gap-1.5 font-mono text-[9px] tracking-widest uppercase text-[#888] hover:text-white transition-colors disabled:opacity-50"
        >
          <RefreshCw className={`w-3 h-3 ${refreshing ? "animate-spin" : ""}`} />
          REFRESH
        </button>
      </div>

      {/* Error banner */}
      {error && (
        <div className="border border-red-500/30 bg-red-500/5 px-3 py-2 flex items-center gap-2">
          <AlertCircle className="w-3.5 h-3.5 text-red-400 shrink-0" />
          <p className="font-mono text-[10px] text-red-400">{error}</p>
        </div>
      )}

      {overview && (
        <>
          {/* Metrics Grid */}
          <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-4 gap-4">
            {/* SOURCE HEALTH */}
            <div className="border border-[#1a1a1a] bg-[#0c0c0c] p-4">
              <div className="flex items-center gap-2 mb-3">
                <Radio className="w-3.5 h-3.5 text-[#888]" />
                <h3 className="font-mono text-[9px] tracking-widest uppercase text-[#888] font-bold">
                  SOURCE HEALTH
                </h3>
              </div>
              <div className="grid grid-cols-2 gap-2">
                <MetricBox label="Total" value={overview.source_health.total} />
                <MetricBox label="Healthy" value={overview.source_health.healthy} color="text-emerald-400" />
                <MetricBox label="Degraded" value={overview.source_health.degraded} color="text-amber-400" />
                <MetricBox label="Failed" value={overview.source_health.failed} color="text-red-400" />
              </div>
            </div>

            {/* ARTICLE PIPELINE */}
            <div className="border border-[#1a1a1a] bg-[#0c0c0c] p-4">
              <div className="flex items-center gap-2 mb-3">
                <Database className="w-3.5 h-3.5 text-[#888]" />
                <h3 className="font-mono text-[9px] tracking-widest uppercase text-[#888] font-bold">
                  ARTICLE PIPELINE
                </h3>
              </div>
              <div className="grid grid-cols-2 gap-2">
                <MetricBox label="Raw" value={overview.article_pipeline.raw} />
                <MetricBox label="Processed" value={overview.article_pipeline.processed} />
                <MetricBox label="Published" value={overview.article_pipeline.published} color="text-emerald-400" />
                <MetricBox label="Rejected" value={overview.article_pipeline.rejected} color="text-red-400" />
              </div>
            </div>

            {/* AI QUEUE */}
            <div className="border border-[#1a1a1a] bg-[#0c0c0c] p-4">
              <div className="flex items-center gap-2 mb-3">
                <Cpu className="w-3.5 h-3.5 text-[#888]" />
                <h3 className="font-mono text-[9px] tracking-widest uppercase text-[#888] font-bold">
                  AI QUEUE
                </h3>
              </div>
              <div className="grid grid-cols-2 gap-2">
                <MetricBox label="Queued" value={overview.ai_queue.queued} />
                <MetricBox label="Processing" value={overview.ai_queue.processing} color="text-blue-400" pulse={overview.ai_queue.processing > 0} />
                <MetricBox label="Completed" value={overview.ai_queue.completed} color="text-emerald-400" />
                <MetricBox label="Failed" value={overview.ai_queue.failed} color="text-red-400" />
              </div>
            </div>

            {/* INFRASTRUCTURE */}
            <div className="border border-[#1a1a1a] bg-[#0c0c0c] p-4">
              <div className="flex items-center gap-2 mb-3">
                <Server className="w-3.5 h-3.5 text-[#888]" />
                <h3 className="font-mono text-[9px] tracking-widest uppercase text-[#888] font-bold">
                  INFRASTRUCTURE
                </h3>
              </div>
              <div className="space-y-0.5">
                <InfraStatus
                  label="PostgreSQL"
                  status={infra?.services?.postgres?.snapshot?.status}
                  latency={infra?.services?.postgres?.snapshot?.latency_ms}
                  last_checked={infra?.services?.postgres?.snapshot?.last_checked}
                  last_success={infra?.services?.postgres?.snapshot?.last_success}
                  history={infra?.services?.postgres?.history}
                />
                <InfraStatus
                  label="Redis"
                  status={infra?.services?.redis?.snapshot?.status}
                  latency={infra?.services?.redis?.snapshot?.latency_ms}
                  last_checked={infra?.services?.redis?.snapshot?.last_checked}
                  last_success={infra?.services?.redis?.snapshot?.last_success}
                  history={infra?.services?.redis?.history}
                />
                <InfraStatus
                  label="Worker Engine"
                  status={infra?.services?.worker?.snapshot?.status}
                  latency={infra?.services?.worker?.snapshot?.latency_ms}
                  last_checked={infra?.services?.worker?.snapshot?.last_checked}
                  last_success={infra?.services?.worker?.snapshot?.last_success}
                  history={infra?.services?.worker?.history}
                />
                <InfraStatus
                  label="Scheduler Beat"
                  status={infra?.services?.beat?.snapshot?.status}
                  latency={infra?.services?.beat?.snapshot?.latency_ms}
                  last_checked={infra?.services?.beat?.snapshot?.last_checked}
                  last_success={infra?.services?.beat?.snapshot?.last_success}
                  history={infra?.services?.beat?.history}
                />
                <InfraStatus
                  label="Backend API"
                  status={infra?.services?.backend?.snapshot?.status}
                  latency={infra?.services?.backend?.snapshot?.latency_ms}
                  last_checked={infra?.services?.backend?.snapshot?.last_checked}
                  last_success={infra?.services?.backend?.snapshot?.last_success}
                  history={infra?.services?.backend?.history}
                />
                <InfraStatus
                  label="Nginx Gateway"
                  status={infra?.services?.nginx?.snapshot?.status}
                  latency={infra?.services?.nginx?.snapshot?.latency_ms}
                  last_checked={infra?.services?.nginx?.snapshot?.last_checked}
                  last_success={infra?.services?.nginx?.snapshot?.last_success}
                  history={infra?.services?.nginx?.history}
                />
                <InfraStatus
                  label="Celery Queue"
                  status={queue?.status}
                  latency={queue?.metrics?.queue_depth}
                  last_checked={queue?.last_checked}
                  last_success={queue?.last_checked}
                />
              </div>
            </div>
          </div>

          {/* LIVE OPERATIONS FEED */}
          <div className="border border-[#1a1a1a] bg-black">
            <div className="px-4 py-2.5 border-b border-[#1a1a1a] flex items-center gap-2">
              <span className="h-1.5 w-1.5 bg-emerald-500 animate-pulse" />
              <h3 className="font-mono text-[9px] tracking-widest uppercase text-[#888] font-bold">
                LIVE OPERATIONS FEED
              </h3>
              <span className="font-mono text-[8px] text-[#333] ml-auto">
                {events.length} EVENTS
              </span>
            </div>
            <div
              ref={feedRef}
              className="h-64 overflow-y-auto p-3 space-y-0.5"
            >
              {events.length === 0 ? (
                <div className="flex items-center justify-center h-full">
                  <p className="font-mono text-[10px] text-[#333]">
                    Awaiting event stream connection...
                  </p>
                </div>
              ) : (
                events.map((event, idx) => (
                  <div key={idx} className="flex items-start gap-2 font-mono text-[11px] leading-relaxed">
                    <span className="text-[#555] shrink-0" suppressHydrationWarning>
                      [{event.time}]
                    </span>
                    <span className="text-emerald-400 shrink-0">{event.agent}:</span>
                    <span className="text-[#ccc]">{event.msg}</span>
                  </div>
                ))
              )}
            </div>
          </div>
        </>
      )}
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import { apiFetch } from "../../../services/api";
import {
  Radio,
  Play,
  ToggleLeft,
  ToggleRight,
  AlertCircle,
  RefreshCw,
} from "lucide-react";

interface Source {
  id: number;
  name: string;
  category: string;
  method: string;
  url: string;
  credibility_score: number;
  crawl_interval: number;
  enabled: boolean;
  health_state: string;
  total_crawls: number;
  successful_crawls: number;
  reliability_score: number;
  last_crawl_at: string | null;
  is_deleted: boolean;
  created_at: string;
}

export default function AdminSourcesPage() {
  const [sources, setSources] = useState<Source[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [togglingId, setTogglingId] = useState<number | null>(null);
  const [triggeringId, setTriggeringId] = useState<number | null>(null);
  const [refreshing, setRefreshing] = useState(false);
  const [message, setMessage] = useState<string | null>(null);

  // Soft Delete & Restore State
  const [showDeleted, setShowDeleted] = useState(false);
  const [deletingId, setDeletingId] = useState<number | null>(null);

  // Edit Modal State
  const [editingSource, setEditingSource] = useState<Source | null>(null);
  const [editName, setEditName] = useState("");
  const [editUrl, setEditUrl] = useState("");
  const [editCategory, setEditCategory] = useState("");
  const [editCredibility, setEditCredibility] = useState(50);
  const [editInterval, setEditInterval] = useState(3600);
  const [savingEdit, setSavingEdit] = useState(false);

  const fetchSources = async (isSilent = false) => {
    if (!isSilent) setLoading(true);
    else setRefreshing(true);
    try {
      const data = await apiFetch<Source[]>("/admin/sources", {
        params: { show_deleted: showDeleted ? "true" : "false" },
      });
      setSources(Array.isArray(data) ? data : []);
      setError(null);
    } catch (err: any) {
      setError(err.message || "Failed to load sources registry.");
    } finally {
      setLoading(false);
      setRefreshing(false);
    }
  };

  useEffect(() => {
    fetchSources();
  }, [showDeleted]);

  const handleToggle = async (id: number) => {
    setTogglingId(id);
    setMessage(null);
    try {
      const res: any = await apiFetch(`/admin/sources/${id}/toggle`, {
        method: "POST",
      });
      setSources((prev) =>
        (Array.isArray(prev) ? prev : []).map((s) => (s.id === id ? { ...s, enabled: res.enabled } : s))
      );
      setMessage(res.message);
    } catch (err: any) {
      setError(err.message || "Failed to update source active state.");
    } finally {
      setTogglingId(null);
    }
  };

  const handleTrigger = async (id: number) => {
    setTriggeringId(id);
    setMessage(null);
    try {
      const res: any = await apiFetch(`/admin/sources/${id}/trigger`, {
        method: "POST",
      });
      setMessage(res.message);
      fetchSources(true);
    } catch (err: any) {
      setError(err.message || "Scraping session failed or timed out.");
    } finally {
      setTriggeringId(null);
    }
  };

  const handleEditOpen = (s: Source) => {
    setEditingSource(s);
    setEditName(s.name);
    setEditUrl(s.url);
    setEditCategory(s.category);
    setEditCredibility(s.credibility_score);
    setEditInterval(s.crawl_interval);
  };

  const handleEditSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingSource) return;
    setSavingEdit(true);
    setMessage(null);
    try {
      const res: any = await apiFetch(`/admin/sources/${editingSource.id}`, {
        method: "PATCH",
        body: JSON.stringify({
          name: editName,
          url: editUrl,
          category: editCategory,
          credibility_score: Number(editCredibility),
          crawl_interval: Number(editInterval),
        }),
      });
      setMessage(res.message);
      setEditingSource(null);
      fetchSources(true);
    } catch (err: any) {
      setError(err.message || "Failed to update source configuration.");
    } finally {
      setSavingEdit(false);
    }
  };

  const handleDelete = async (id: number) => {
    if (!confirm("Are you sure you want to soft-delete this news source?")) return;
    setDeletingId(id);
    setMessage(null);
    try {
      const res: any = await apiFetch(`/admin/sources/${id}`, {
        method: "DELETE",
      });
      setMessage(res.message);
      fetchSources(true);
    } catch (err: any) {
      setError(err.message || "Failed to soft-delete source.");
    } finally {
      setDeletingId(null);
    }
  };

  const handleRestore = async (id: number) => {
    setDeletingId(id);
    setMessage(null);
    try {
      const res: any = await apiFetch(`/admin/sources/${id}/restore`, {
        method: "POST",
      });
      setMessage(res.message);
      fetchSources(true);
    } catch (err: any) {
      setError(err.message || "Failed to restore source.");
    } finally {
      setDeletingId(null);
    }
  };

  if (loading) {
    return (
      <div className="space-y-4 font-mono text-[11px]">
        <div className="flex items-center justify-between">
          <div className="h-4 bg-neutral-900 w-48 animate-pulse" />
        </div>
        <div className="border border-[#1a1a1a] bg-black p-4 space-y-4">
          {[1, 2, 3, 4].map((i) => (
            <div key={i} className="h-8 bg-neutral-950 animate-pulse w-full border-b border-[#111]" />
          ))}
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-4">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-2">
          <Radio className="w-3.5 h-3.5 text-[#888]" />
          <h1 className="font-mono text-[11px] tracking-widest uppercase text-white font-bold">
            NEWSROOM SOURCES REGISTRY
          </h1>
        </div>
        <div className="flex items-center gap-4">
          <label className="flex items-center gap-2 cursor-pointer select-none font-mono text-[9px] tracking-widest uppercase text-[#888] hover:text-white transition-colors">
            <input
              type="checkbox"
              checked={showDeleted}
              onChange={(e) => setShowDeleted(e.target.checked)}
              className="accent-white cursor-pointer"
            />
            SHOW DELETED
          </label>
          <button
            onClick={() => fetchSources(true)}
            disabled={refreshing}
            className="flex items-center gap-1.5 font-mono text-[9px] tracking-widest uppercase text-[#888] hover:text-white transition-colors disabled:opacity-50"
          >
            <RefreshCw className={`w-3 h-3 ${refreshing ? "animate-spin" : ""}`} />
            REFRESH
          </button>
        </div>
      </div>

      {/* Message & Error banners */}
      {error && (
        <div className="border border-red-500/30 bg-red-500/5 px-3 py-2 flex items-center gap-2">
          <AlertCircle className="w-3.5 h-3.5 text-red-400 shrink-0" />
          <p className="font-mono text-[10px] text-red-400">{error}</p>
        </div>
      )}

      {message && (
        <div className="border border-emerald-500/30 bg-emerald-500/5 px-3 py-2">
          <p className="font-mono text-[10px] text-emerald-400">{message}</p>
        </div>
      )}

      {/* Main Table */}
      <div className="border border-[#1a1a1a] bg-black overflow-x-auto">
        <table className="w-full text-left font-mono text-[11px]">
          <thead>
            <tr className="border-b border-[#1a1a1a] bg-[#0c0c0c] text-[#555] select-none text-[9px]">
              <th className="p-3">ID</th>
              <th className="p-3">SOURCE NAME</th>
              <th className="p-3">METHOD</th>
              <th className="p-3">CATEGORY</th>
              <th className="p-3">RELIABILITY</th>
              <th className="p-3">HEALTH</th>
              <th className="p-3">STATUS</th>
              <th className="p-3 text-right">ACTIONS</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-[#111]">
            {sources.map((s) => (
              <tr key={s.id} className={`hover:bg-[#060606] transition-colors ${s.is_deleted ? "opacity-45" : ""}`}>
                <td className="p-3 text-[#555]">{s.id}</td>
                <td className="p-3 font-semibold text-[#ccc]">
                  <div>{s.name}</div>
                  <div className="text-[9px] text-[#555] truncate max-w-[250px]">{s.url}</div>
                </td>
                <td className="p-3 text-[#888] uppercase">{s.method}</td>
                <td className="p-3 text-[#888]">{s.category}</td>
                <td className="p-3">
                  <span
                    className={
                      s.reliability_score >= 80
                        ? "text-emerald-400"
                        : s.reliability_score >= 50
                        ? "text-amber-400"
                        : "text-red-400"
                    }
                  >
                    {s.reliability_score}%
                  </span>
                </td>
                <td className="p-3">
                  <span
                    className={`inline-flex items-center px-1.5 py-0.5 text-[8px] font-bold tracking-wider uppercase border ${
                      s.health_state === "healthy"
                        ? "border-emerald-500/20 bg-emerald-500/5 text-emerald-400"
                        : s.health_state === "degraded"
                        ? "border-amber-500/20 bg-amber-500/5 text-amber-400"
                        : "border-red-500/20 bg-red-500/5 text-red-400"
                    }`}
                  >
                    {s.health_state}
                  </span>
                </td>
                <td className="p-3">
                  <button
                    onClick={() => handleToggle(s.id)}
                    disabled={togglingId !== null || s.is_deleted}
                    className="flex items-center gap-1.5 focus:outline-none disabled:opacity-50"
                  >
                    {s.enabled ? (
                      <ToggleRight className="w-5 h-5 text-emerald-400" />
                    ) : (
                      <ToggleLeft className="w-5 h-5 text-[#333]" />
                    )}
                  </button>
                </td>
                <td className="p-3 text-right">
                  <div className="inline-flex gap-1.5">
                    {s.is_deleted ? (
                      <button
                        onClick={() => handleRestore(s.id)}
                        disabled={deletingId !== null}
                        className="font-mono text-[9px] font-bold tracking-wider uppercase bg-emerald-500 text-black px-2.5 py-1 hover:bg-emerald-400 transition-colors"
                      >
                        RESTORE
                      </button>
                    ) : (
                      <>
                        <button
                          onClick={() => handleTrigger(s.id)}
                          disabled={triggeringId !== null || !s.enabled}
                          className="inline-flex items-center gap-1 font-mono text-[9px] tracking-wider uppercase bg-foreground text-background px-2.5 py-1 hover:bg-neutral-300 disabled:opacity-30 disabled:hover:bg-foreground transition-colors"
                        >
                          <Play className="w-2.5 h-2.5 fill-current" />
                          CRAWL
                        </button>
                        <button
                          onClick={() => handleEditOpen(s)}
                          className="font-mono text-[9px] tracking-wider uppercase border border-[#333] hover:border-[#555] px-2.5 py-1 text-[#ccc] hover:text-white transition-colors"
                        >
                          EDIT
                        </button>
                        <button
                          onClick={() => handleDelete(s.id)}
                          disabled={deletingId !== null}
                          className="font-mono text-[9px] tracking-wider uppercase bg-red-950/40 hover:bg-red-950 text-red-400 border border-red-950/60 px-2.5 py-1 transition-colors disabled:opacity-30"
                        >
                          DELETE
                        </button>
                      </>
                    )}
                  </div>
                </td>
              </tr>
            ))}
            {sources.length === 0 && (
              <tr>
                <td colSpan={8} className="p-8 text-center text-[#555]">
                  No sources matching active registry filters found.
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>

      {/* Edit Modal */}
      {editingSource && (
        <div className="fixed inset-0 bg-black/80 flex items-center justify-center z-50 p-4">
          <div className="w-full max-w-md bg-[#0c0c0c] border border-[#1a1a1a] p-6 space-y-4">
            <div className="border-b border-[#1a1a1a] pb-2 flex items-center justify-between">
              <h2 className="font-mono text-[10px] tracking-widest uppercase text-white font-bold">
                EDIT CRAWLER SOURCE #{editingSource.id}
              </h2>
              <span className="font-mono text-[8px] text-[#555] uppercase">
                {editingSource.method}
              </span>
            </div>
            <form onSubmit={handleEditSubmit} className="space-y-4 font-mono text-[11px]">
              <div>
                <label className="block text-[#555] text-[9px] tracking-wider uppercase mb-1">SOURCE NAME</label>
                <input
                  type="text"
                  required
                  value={editName}
                  onChange={(e) => setEditName(e.target.value)}
                  className="w-full bg-[#080808] border border-[#1a1a1a] px-2.5 py-2 text-white focus:outline-none focus:border-white transition-colors"
                />
              </div>
              <div>
                <label className="block text-[#555] text-[9px] tracking-wider uppercase mb-1">ENDPOINT URL</label>
                <input
                  type="url"
                  required
                  value={editUrl}
                  onChange={(e) => setEditUrl(e.target.value)}
                  className="w-full bg-[#080808] border border-[#1a1a1a] px-2.5 py-2 text-white focus:outline-none focus:border-white transition-colors"
                />
              </div>
              <div className="grid grid-cols-2 gap-2">
                <div>
                  <label className="block text-[#555] text-[9px] tracking-wider uppercase mb-1">CATEGORY</label>
                  <select
                    value={editCategory}
                    onChange={(e) => setEditCategory(e.target.value)}
                    className="w-full bg-[#080808] border border-[#1a1a1a] px-2 py-2 text-[#ccc] focus:outline-none focus:border-white transition-colors"
                  >
                    <option value="official">official</option>
                    <option value="editorial">editorial</option>
                    <option value="community">community</option>
                    <option value="social">social</option>
                  </select>
                </div>
                <div>
                  <label className="block text-[#555] text-[9px] tracking-wider uppercase mb-1">CREDIBILITY (0-100)</label>
                  <input
                    type="number"
                    min="0"
                    max="100"
                    required
                    value={editCredibility}
                    onChange={(e) => setEditCredibility(Number(e.target.value))}
                    className="w-full bg-[#080808] border border-[#1a1a1a] px-2.5 py-2 text-white focus:outline-none focus:border-white transition-colors"
                  />
                </div>
              </div>
              <div>
                <label className="block text-[#555] text-[9px] tracking-wider uppercase mb-1">CRAWL INTERVAL (SECONDS)</label>
                <input
                  type="number"
                  min="60"
                  required
                  value={editInterval}
                  onChange={(e) => setEditInterval(Number(e.target.value))}
                  className="w-full bg-[#080808] border border-[#1a1a1a] px-2.5 py-2 text-white focus:outline-none focus:border-white transition-colors"
                />
              </div>
              <div className="flex justify-end gap-2 pt-3 border-t border-[#1a1a1a]">
                <button
                  type="button"
                  onClick={() => setEditingSource(null)}
                  className="border border-[#333] text-[#ccc] hover:text-white px-4 py-2 uppercase text-[9px] tracking-wider transition-colors"
                >
                  CANCEL
                </button>
                <button
                  type="submit"
                  disabled={savingEdit}
                  className="bg-white text-black hover:bg-neutral-200 px-4 py-2 uppercase text-[9px] font-bold tracking-wider disabled:opacity-50 transition-colors"
                >
                  {savingEdit ? "SAVING..." : "SAVE CHANGES"}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import { Activity, AlertCircle, Cpu, ShieldCheck } from "lucide-react";

interface TelemetrySnapshot {
  timestamp: string;
  ingestion_rate_sec: number;
  total_articles_ingested: number;
  total_articles_published: number;
  active_crawl_count: number;
  queue_depth: number;
  source_health: {
    total_registered: number;
    healthy: number;
    degraded: number;
    offline: number;
    avg_reliability_score: number;
    avg_credibility_score: number;
  };
  lifecycle_states: Record<string, number>;
  thumbnail_metrics?: {
    success_rate: number;
    download_failures: number;
    processing_queue: number;
    source_distribution?: Record<string, number>;
  };
  ranking_metrics?: {
    articles_evaluated: number;
    active_articles: number;
    expired_articles: number;
    avg_impact_score: number;
    avg_final_score: number;
    last_run: string | null;
    next_run: string | null;
  };
  ai_metrics?: {
    provider: { name: string; model: string; enabled: boolean; healthy: boolean; last_success: string | null; sdk_version: string };
    queue: { depth: number; oldest_age_sec: number; average_wait_sec: number; average_retry_count: number; failed_today: number; recovered_today: number };
    performance: { success_rate: number; fallback_rate: number; failure_rate: number; latency: { p50: number; p95: number; max: number; avg: number } };
    cost: { tokens: { prompt: number; completion: number; total: number }; usd: { today: number; yesterday: number; last_7d: number }; average_cost_per_article: number; cache_hit_rate: number };
    recovery: { recovered_total: number; failed_total: number; recovery_rate: number };
  };
}

const fallbackSnapshot: TelemetrySnapshot = {
  timestamp: new Date().toISOString(),
  ingestion_rate_sec: 0,
  total_articles_ingested: 0,
  total_articles_published: 0,
  active_crawl_count: 0,
  queue_depth: 0,
  source_health: {
    total_registered: 0,
    healthy: 0,
    degraded: 0,
    offline: 0,
    avg_reliability_score: 0,
    avg_credibility_score: 0,
  },
  lifecycle_states: {
    discovered: 0,
    queued: 0,
    fetched: 0,
    filtered: 0,
    deduplicated: 0,
    trend_scored: 0,
    ai_queued: 0,
    processed: 0,
    published: 0,
    failed: 0,
  },
  thumbnail_metrics: {
    success_rate: 0.0,
    download_failures: 0,
    processing_queue: 0,
    source_distribution: {},
  },
  ranking_metrics: {
    articles_evaluated: 0,
    active_articles: 0,
    expired_articles: 0,
    avg_impact_score: 0.0,
    avg_final_score: 0.0,
    last_run: null,
    next_run: null,
  },
  ai_metrics: {
    provider: { name: "unknown", model: "unknown", enabled: false, healthy: false, last_success: null, sdk_version: "unknown" },
    queue: { depth: 0, oldest_age_sec: 0, average_wait_sec: 0, average_retry_count: 0, failed_today: 0, recovered_today: 0 },
    performance: { success_rate: 0, fallback_rate: 0, failure_rate: 0, latency: { p50: 0, p95: 0, max: 0, avg: 0 } },
    cost: { tokens: { prompt: 0, completion: 0, total: 0 }, usd: { today: 0, yesterday: 0, last_7d: 0 }, average_cost_per_article: 0, cache_hit_rate: 0 },
    recovery: { recovered_total: 0, failed_total: 0, recovery_rate: 0 }
  },
};

export default function AdminTelemetryPage() {
  const [snapshot, setSnapshot] = useState<TelemetrySnapshot | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [connected, setConnected] = useState(false);
  const [retryTrigger, setRetryTrigger] = useState(0);

  useEffect(() => {
    const apiBase = process.env.NEXT_PUBLIC_API_URL || "/api/v1";
    let sseUrl = `${apiBase}/telemetry/sse`;
    if (typeof window !== "undefined") {
      if (sseUrl.startsWith("/")) {
        sseUrl = `${window.location.protocol}//${window.location.host}${sseUrl}`;
      }
      if (sseUrl.includes(":3000")) {
        sseUrl = sseUrl.replace(":3000", "");
      }
    }

    let eventSource: EventSource | null = null;
    let reconnectDelay = 1000;
    let reconnectTimer: NodeJS.Timeout | null = null;

    // Safety timeout: stop infinite skeleton loaders after 5 seconds if connection is offline
    const timeoutTimer = setTimeout(() => {
      setLoading(false);
      setError("Real-time telemetry stream currently offline. Standby for auto-reconnect...");
    }, 5000);

    const connect = () => {
      if (eventSource) eventSource.close();
      if (reconnectTimer) clearTimeout(reconnectTimer);

      eventSource = new EventSource(sseUrl);

      eventSource.onmessage = (event) => {
        try {
          const parsed = JSON.parse(event.data);
          setSnapshot(parsed);
          setConnected(true);
          setLoading(false);
          setError(null);
          clearTimeout(timeoutTimer);
        } catch (err) {
          // ignore keepalives
        }
      };

      eventSource.onerror = () => {
        setConnected(false);
        eventSource?.close();
        reconnectTimer = setTimeout(() => {
          reconnectDelay = Math.min(reconnectDelay * 2, 30000);
          connect();
        }, reconnectDelay);
      };

      eventSource.onopen = () => {
        reconnectDelay = 1000;
      };
    };

    connect();

    return () => {
      if (eventSource) eventSource.close();
      if (reconnectTimer) clearTimeout(reconnectTimer);
      clearTimeout(timeoutTimer);
    };
  }, [retryTrigger]);

  if (loading) {
    return (
      <div className="space-y-4 font-mono text-[11px]">
        <div className="h-4 bg-neutral-900 w-48 animate-pulse" />
        <div className="border border-[#1a1a1a] bg-black p-4 h-64 animate-pulse" />
      </div>
    );
  }

  const displaySnapshot = snapshot || fallbackSnapshot;

  return (
    <div className="space-y-4">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-2">
          <Activity className="w-3.5 h-3.5 text-[#888]" />
          <h1 className="font-mono text-[11px] tracking-widest uppercase text-white font-bold">
            REAL-TIME PIPELINE TELEMETRY
          </h1>
        </div>
        <div className="flex items-center gap-2 font-mono text-[8px] tracking-widest uppercase">
          <span
            className={`h-2 w-2 shrink-0 ${
              connected ? "bg-emerald-500 animate-pulse" : "bg-amber-500"
            }`}
          />
          <span className={connected ? "text-emerald-400" : "text-amber-400"}>
            {connected ? "LIVE METRICS ACTIVE" : "OFFLINE / RECONNECTING"}
          </span>
        </div>
      </div>

      {error && (
        <div className="border border-red-500/30 bg-red-500/5 px-3 py-2 flex items-center justify-between gap-2">
          <div className="flex items-center gap-2">
            <AlertCircle className="w-3.5 h-3.5 text-red-400 shrink-0" />
            <p className="font-mono text-[10px] text-red-400">{error}</p>
          </div>
          <button
            onClick={() => {
              setLoading(true);
              setError(null);
              setRetryTrigger((prev) => prev + 1);
            }}
            className="font-mono text-[9px] tracking-widest uppercase bg-white text-black px-2.5 py-0.5 hover:bg-neutral-200 transition-colors"
          >
            Retry
          </button>
        </div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-4 gap-4">
        {/* pipeline throughput */}
        <div className="border border-[#1a1a1a] bg-[#0c0c0c] p-4 space-y-4 flex flex-col justify-between">
          <div className="space-y-4">
            <h3 className="font-mono text-[9px] tracking-widest uppercase text-[#888] font-bold">
              PIPELINE THROUGHPUT
            </h3>
            <div className="border border-[#1a1a1a] bg-black p-3.5">
              <p className="font-mono text-[8px] text-[#555] tracking-wider uppercase mb-1">
                Ingestion Rate
              </p>
              <p className="font-mono text-3xl font-bold text-white">
                {displaySnapshot.ingestion_rate_sec.toFixed(3)}
                <span className="text-[10px] text-[#555] font-normal ml-1">/sec</span>
              </p>
            </div>
            <div className="grid grid-cols-2 gap-2 font-mono text-[10px]">
              <div className="border border-[#1a1a1a] bg-black p-2">
                <p className="text-[#555] text-[7px] uppercase tracking-wider mb-1">
                  Active Crawlers
                </p>
                <p className="text-white font-bold">{displaySnapshot.active_crawl_count}</p>
              </div>
              <div className="border border-[#1a1a1a] bg-black p-2">
                <p className="text-[#555] text-[7px] uppercase tracking-wider mb-1">
                  Celery Depth
                </p>
                <p className="text-white font-bold">{displaySnapshot.queue_depth}</p>
              </div>
            </div>
          </div>
        </div>

        {/* thumbnail pipeline metrics */}
        <div className="border border-[#1a1a1a] bg-[#0c0c0c] p-4 space-y-4 flex flex-col justify-between">
          <div className="space-y-4">
            <h3 className="font-mono text-[9px] tracking-widest uppercase text-[#888] font-bold">
              THUMBNAIL PIPELINE METRICS
            </h3>
            <div className="border border-[#1a1a1a] bg-black p-3.5">
              <p className="font-mono text-[8px] text-[#555] tracking-wider uppercase mb-1">
                Extraction Success Rate
              </p>
              <p className="font-mono text-3xl font-bold text-white">
                {(displaySnapshot.thumbnail_metrics?.success_rate ?? 0.0).toFixed(1)}
                <span className="text-[10px] text-[#555] font-normal ml-1">%</span>
              </p>
            </div>
            <div className="grid grid-cols-2 gap-2 font-mono text-[10px]">
              <div className="border border-[#1a1a1a] bg-black p-2">
                <p className="text-[#555] text-[7px] uppercase tracking-wider mb-1">
                  Download Failures
                </p>
                <p className="text-red-500 font-bold">{displaySnapshot.thumbnail_metrics?.download_failures ?? 0}</p>
              </div>
              <div className="border border-[#1a1a1a] bg-black p-2">
                <p className="text-[#555] text-[7px] uppercase tracking-wider mb-1">
                  Pending Queue
                </p>
                <p className="text-amber-500 font-bold">{displaySnapshot.thumbnail_metrics?.processing_queue ?? 0}</p>
              </div>
            </div>
            {displaySnapshot.thumbnail_metrics?.source_distribution && 
             Object.keys(displaySnapshot.thumbnail_metrics.source_distribution).length > 0 && (
              <div className="border border-[#1a1a1a] bg-black p-2 font-mono text-[8px] space-y-1 text-neutral-400 mt-2">
                <p className="text-[#555] text-[7px] uppercase tracking-wider mb-1 font-bold">SOURCE DISTRIBUTION</p>
                {Object.entries(displaySnapshot.thumbnail_metrics.source_distribution).map(([source, count]) => (
                  <div key={source} className="flex justify-between">
                    <span className="uppercase text-[7px]">{source}:</span>
                    <span className="font-bold text-white">{count}</span>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>

        {/* ranking engine panel */}
        <div className="border border-[#1a1a1a] bg-[#0c0c0c] p-4 space-y-4 flex flex-col justify-between">
          <div className="space-y-4">
            <h3 className="font-mono text-[9px] tracking-widest uppercase text-[#888] font-bold">
              RANKING ENGINE PANEL
            </h3>
            <div className="border border-[#1a1a1a] bg-black p-3.5">
              <p className="font-mono text-[8px] text-[#555] tracking-wider uppercase mb-1">
                Average Final Score
              </p>
              <p className="font-mono text-3xl font-bold text-white">
                {(displaySnapshot.ranking_metrics?.avg_final_score ?? 0.0).toFixed(1)}
                <span className="text-[10px] text-[#555] font-normal ml-1">/100</span>
              </p>
            </div>
            <div className="grid grid-cols-2 gap-2 font-mono text-[10px]">
              <div className="border border-[#1a1a1a] bg-black p-2">
                <p className="text-[#555] text-[7px] uppercase tracking-wider mb-1">
                  Evaluated
                </p>
                <p className="text-white font-bold">{displaySnapshot.ranking_metrics?.articles_evaluated ?? 0}</p>
              </div>
              <div className="border border-[#1a1a1a] bg-black p-2">
                <p className="text-[#555] text-[7px] uppercase tracking-wider mb-1">
                  Active Signals
                </p>
                <p className="text-white font-bold">{displaySnapshot.ranking_metrics?.active_articles ?? 0}</p>
              </div>
              <div className="border border-[#1a1a1a] bg-black p-2">
                <p className="text-[#555] text-[7px] uppercase tracking-wider mb-1">
                  Expired Signals
                </p>
                <p className="text-red-500 font-bold">{displaySnapshot.ranking_metrics?.expired_articles ?? 0}</p>
              </div>
              <div className="border border-[#1a1a1a] bg-black p-2">
                <p className="text-[#555] text-[7px] uppercase tracking-wider mb-1">
                  Avg Impact
                </p>
                <p className="text-white font-bold">{(displaySnapshot.ranking_metrics?.avg_impact_score ?? 0.0).toFixed(1)}</p>
              </div>
            </div>
          </div>
          <div className="border border-[#1a1a1a] bg-black p-2 font-mono text-[7px] space-y-1 text-neutral-400 mt-2 shrink-0">
            <div className="flex justify-between">
              <span>LAST RUN:</span>
              <span className="font-bold text-white">
                {displaySnapshot.ranking_metrics?.last_run
                  ? new Date(displaySnapshot.ranking_metrics.last_run).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
                  : "NEVER"}
              </span>
            </div>
            <div className="flex justify-between">
              <span>NEXT RUN:</span>
              <span className="font-bold text-white">
                {displaySnapshot.ranking_metrics?.next_run
                  ? new Date(displaySnapshot.ranking_metrics.next_run).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
                  : "NEVER"}
              </span>
            </div>
          </div>
        </div>

        {/* AI ENGINE panel */}
        {displaySnapshot.ai_metrics && (
        <div className="border border-[#1a1a1a] bg-[#0c0c0c] p-4 space-y-4 flex flex-col justify-between">
          <div className="space-y-4">
            <h3 className="font-mono text-[9px] tracking-widest uppercase text-[#888] font-bold flex justify-between items-center">
              <span>AI ENGINE</span>
              <span className={`px-2 py-0.5 rounded text-[8px] font-bold ${displaySnapshot.ai_metrics.provider.healthy ? 'bg-emerald-500/20 text-emerald-400 border border-emerald-500/30' : 'bg-red-500/20 text-red-400 border border-red-500/30'}`}>
                {displaySnapshot.ai_metrics.provider.healthy ? '🟢 HEALTHY' : '🔴 OFFLINE'}
              </span>
            </h3>
            <div className="border border-[#1a1a1a] bg-black p-3.5">
              <p className="font-mono text-[8px] text-[#555] tracking-wider uppercase mb-1">Provider & Model</p>
              <p className="font-mono text-lg font-bold text-white uppercase">{displaySnapshot.ai_metrics.provider.name}</p>
              <p className="font-mono text-[10px] text-emerald-400 mt-1">{displaySnapshot.ai_metrics.provider.model}</p>
              <div className="mt-2 text-[8px] flex justify-between text-[#888]">
                <span>Flag: <span className={displaySnapshot.ai_metrics.provider.enabled ? "text-emerald-400" : "text-red-400"}>{displaySnapshot.ai_metrics.provider.enabled ? "ENABLED" : "DISABLED"}</span></span>
                <span>SDK: {displaySnapshot.ai_metrics.provider.sdk_version}</span>
              </div>
            </div>
            
            <div className="grid grid-cols-2 gap-2 font-mono text-[10px]">
              {/* Queue Sub-section */}
              <div className="border border-[#1a1a1a] bg-black p-2 col-span-2">
                <p className="text-[#555] text-[7px] uppercase tracking-wider mb-1 font-bold">QUEUE METRICS</p>
                <div className="flex justify-between items-center mt-1">
                  <span className="text-[9px] text-[#888]">Depth: <span className="text-white font-bold">{displaySnapshot.ai_metrics.queue.depth}</span></span>
                  <span className="text-[9px] text-[#888]">Wait: <span className="text-amber-400 font-bold">{displaySnapshot.ai_metrics.queue.average_wait_sec.toFixed(1)}s</span></span>
                  <span className="text-[9px] text-[#888]">Retries: <span className="text-white font-bold">{displaySnapshot.ai_metrics.queue.average_retry_count.toFixed(1)}</span></span>
                </div>
              </div>
              
              {/* Performance Sub-section */}
              <div className="border border-[#1a1a1a] bg-black p-2 col-span-2">
                <p className="text-[#555] text-[7px] uppercase tracking-wider mb-1 font-bold">PERFORMANCE (24h)</p>
                <div className="flex justify-between items-center mt-1">
                  <span className="text-[9px] text-[#888]">Success: <span className="text-emerald-400 font-bold">{(displaySnapshot.ai_metrics.performance.success_rate * 100).toFixed(1)}%</span></span>
                  <span className="text-[9px] text-[#888]">Fallback: <span className="text-amber-400 font-bold">{(displaySnapshot.ai_metrics.performance.fallback_rate * 100).toFixed(1)}%</span></span>
                  <span className="text-[9px] text-[#888]">Lat(p95): <span className="text-white font-bold">{(displaySnapshot.ai_metrics.performance.latency.p95 / 1000).toFixed(1)}s</span></span>
                </div>
              </div>

              {/* Cost Sub-section */}
              <div className="border border-[#1a1a1a] bg-black p-2 col-span-2">
                <p className="text-[#555] text-[7px] uppercase tracking-wider mb-1 font-bold">COST & TOKENS (24h)</p>
                <div className="flex justify-between items-center mt-1">
                  <span className="text-[9px] text-[#888]">Total: <span className="text-white font-bold">{displaySnapshot.ai_metrics.cost.tokens.total.toLocaleString()}</span></span>
                  <span className="text-[9px] text-[#888]">USD: <span className="text-emerald-400 font-bold">${displaySnapshot.ai_metrics.cost.usd.today.toFixed(2)}</span></span>
                  <span className="text-[9px] text-[#888]">Cache: <span className="text-white font-bold">{(displaySnapshot.ai_metrics.cost.cache_hit_rate * 100).toFixed(1)}%</span></span>
                </div>
              </div>
            </div>
          </div>
        </div>
        )}
      </div>

      {/* processing states map */}
      <div className="border border-[#1a1a1a] bg-black p-4 w-full">
        <h3 className="font-mono text-[9px] tracking-widest uppercase text-[#888] font-bold mb-3">
          PROCESSING LIFECYCLE STATES MAP
        </h3>
        <div className="grid grid-cols-2 sm:grid-cols-5 gap-2 text-center font-mono">
          {Object.entries(displaySnapshot.lifecycle_states).map(([state, count]) => (
            <div key={state} className="border border-[#1a1a1a] bg-[#080808] p-2.5">
              <p className="text-[#555] text-[8px] uppercase tracking-widest truncate">{state}</p>
              <p className="text-[#ccc] text-lg font-bold mt-1">{count}</p>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import { apiFetch } from "../../../services/api";
import { useAppStore } from "../../../store/useStore";
import { Users, AlertCircle, RefreshCw, ShieldAlert, ShieldCheck } from "lucide-react";

interface UserRecord {
  id: number;
  name: string;
  email: string;
  role: string | null;
  status: string;
  created_at: string;
}

export default function AdminUsersPage() {
  const { user: currentUser } = useAppStore();
  const [users, setUsers] = useState<UserRecord[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [message, setMessage] = useState<string | null>(null);
  const [refreshing, setRefreshing] = useState(false);
  const [actingUserId, setActingUserId] = useState<number | null>(null);
  
  // Search query states
  const [searchQuery, setSearchQuery] = useState("");
  const [isFirstLoad, setIsFirstLoad] = useState(true);

  const fetchUsers = async (isSilent = false) => {
    if (!isSilent) setLoading(true);
    else setRefreshing(true);
    try {
      const params: Record<string, string> = {};
      if (searchQuery.trim()) {
        params.q = searchQuery.trim();
      }
      const data = await apiFetch<UserRecord[]>("/admin/users", { params });
      setUsers(Array.isArray(data) ? data : []);
      setError(null);
    } catch (err: any) {
      setError(err.message || "Failed to load platform user index.");
    } finally {
      setLoading(false);
      setRefreshing(false);
    }
  };

  useEffect(() => {
    if (isFirstLoad) {
      fetchUsers(false);
      setIsFirstLoad(false);
      return;
    }
    const delayDebounce = setTimeout(() => {
      fetchUsers(true);
    }, 300);
    return () => clearTimeout(delayDebounce);
  }, [searchQuery]);

  const handleRoleChange = async (userId: number, role: string) => {
    setActingUserId(userId);
    setMessage(null);
    try {
      const res: any = await apiFetch(`/admin/users/${userId}/role`, {
        method: "PUT",
        body: JSON.stringify({ role }),
      });
      setUsers((prev) =>
        (Array.isArray(prev) ? prev : []).map((u) => (u.id === userId ? { ...u, role } : u))
      );
      setMessage(res.message);
    } catch (err: any) {
      setError(err.message || "Role promotion failed.");
    } finally {
      setActingUserId(null);
    }
  };

  const handleStatusChange = async (userId: number, status: string) => {
    setActingUserId(userId);
    setMessage(null);
    try {
      const res: any = await apiFetch(`/admin/users/${userId}/status`, {
        method: "PUT",
        body: JSON.stringify({ status }),
      });
      setUsers((prev) =>
        (Array.isArray(prev) ? prev : []).map((u) => (u.id === userId ? { ...u, status } : u))
      );
      setMessage(res.message);
    } catch (err: any) {
      setError(err.message || "Status change failed.");
    } finally {
      setActingUserId(null);
    }
  };

  if (loading) {
    return (
      <div className="space-y-4 font-mono text-[11px]">
        <div className="h-4 bg-neutral-900 w-48 animate-pulse" />
        <div className="border border-[#1a1a1a] bg-black p-4 space-y-4">
          <div className="h-8 bg-neutral-950 animate-pulse w-full border-b border-[#111]" />
          <div className="h-8 bg-neutral-950 animate-pulse w-full" />
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-4">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-2">
          <Users className="w-3.5 h-3.5 text-[#888]" />
          <h1 className="font-mono text-[11px] tracking-widest uppercase text-white font-bold">
            PLATFORM USER ACCOUNTS
          </h1>
        </div>
        <button
          onClick={() => fetchUsers(true)}
          disabled={refreshing}
          className="flex items-center gap-1.5 font-mono text-[9px] tracking-widest uppercase text-[#888] hover:text-white transition-colors disabled:opacity-50"
        >
          <RefreshCw className={`w-3 h-3 ${refreshing ? "animate-spin" : ""}`} />
          REFRESH
        </button>
      </div>

      {/* Search Filter */}
      <div className="border border-[#1a1a1a] bg-[#0c0c0c] p-3 flex items-center gap-3">
        <span className="font-mono text-[9px] tracking-widest uppercase text-[#555] select-none shrink-0">
          SEARCH USERS:
        </span>
        <input
          type="text"
          value={searchQuery}
          onChange={(e) => setSearchQuery(e.target.value)}
          placeholder="ENTER OPERATOR NAME OR EMAIL ADDRESS..."
          className="flex-1 bg-black border border-[#1a1a1a] px-2.5 py-1.5 font-mono text-[11px] text-white focus:outline-none focus:border-white placeholder-neutral-700 transition-colors"
        />
        {searchQuery && (
          <button
            onClick={() => setSearchQuery("")}
            className="font-mono text-[9px] tracking-widest uppercase text-[#888] hover:text-white transition-colors border border-[#1a1a1a] px-2.5 py-1.5 bg-black"
          >
            CLEAR
          </button>
        )}
      </div>

      {/* banners */}
      {error && (
        <div className="border border-red-500/30 bg-red-500/5 px-3 py-2 flex items-center gap-2">
          <AlertCircle className="w-3.5 h-3.5 text-red-400 shrink-0" />
          <p className="font-mono text-[10px] text-red-400">{error}</p>
        </div>
      )}

      {message && (
        <div className="border border-emerald-500/30 bg-emerald-500/5 px-3 py-2">
          <p className="font-mono text-[10px] text-emerald-400">{message}</p>
        </div>
      )}

      {/* Users table */}
      <div className="border border-[#1a1a1a] bg-black overflow-x-auto">
        <table className="w-full text-left font-mono text-[11px]">
          <thead>
            <tr className="border-b border-[#1a1a1a] bg-[#0c0c0c] text-[#555] select-none text-[9px]">
              <th className="p-3">ID</th>
              <th className="p-3">USER NAME</th>
              <th className="p-3">EMAIL ADDRESS</th>
              <th className="p-3">ROLE AUTHORITY</th>
              <th className="p-3">ACCOUNT STATE</th>
              <th className="p-3 text-right">TOGGLE STATE</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-[#111]">
            {users.map((u) => (
              <tr key={u.id} className="hover:bg-[#060606] transition-colors">
                <td className="p-3 text-[#555]">{u.id}</td>
                <td className="p-3 text-white font-semibold">{u.name}</td>
                <td className="p-3 text-[#888]">{u.email}</td>
                <td className="p-3">
                  <select
                    value={u.role || ""}
                    disabled={actingUserId !== null || currentUser?.role !== "super_admin"}
                    onChange={(e) => handleRoleChange(u.id, e.target.value)}
                    className="bg-[#080808] border border-[#1a1a1a] text-[#ccc] py-0.5 px-1.5 focus:outline-none focus:border-white text-[10px] disabled:opacity-50"
                  >
                    <option value="reader">reader</option>
                    <option value="editor">editor</option>
                    <option value="admin">admin</option>
                    <option value="super_admin">super_admin</option>
                  </select>
                </td>
                <td className="p-3">
                  <span
                    className={`inline-flex items-center px-1.5 py-0.5 text-[8px] font-bold tracking-wider uppercase border ${
                      u.status === "active"
                        ? "border-emerald-500/20 bg-emerald-500/5 text-emerald-400"
                        : "border-red-500/20 bg-red-500/5 text-red-400"
                    }`}
                  >
                    {u.status}
                  </span>
                </td>
                <td className="p-3 text-right">
                  <button
                    onClick={() =>
                      handleStatusChange(u.id, u.status === "active" ? "disabled" : "active")
                    }
                    disabled={
                      actingUserId !== null ||
                      (currentUser?.role === "admin" && (u.role === "admin" || u.role === "super_admin"))
                    }
                    className="font-mono text-[9px] tracking-wider uppercase bg-foreground text-background px-2.5 py-1 hover:bg-neutral-300 disabled:opacity-30 transition-colors"
                  >
                    {u.status === "active" ? "SUSPEND" : "ACTIVATE"}
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

"use client";

import { useEffect, useState, use, useRef } from "react";
import Image from "next/image";
import Link from "next/link";
import { apiFetch } from "../../../services/api";
import { useAppStore } from "../../../store/useStore";
import AdLayout from "../../../components/AdLayout";
import { 
  ShieldCheck, ArrowLeft, Clock, Calendar, AlertCircle, Share2, 
  BookOpen, Star, Radio, Activity, TerminalSquare, CheckCircle2
} from "lucide-react";

interface SourceInfo {
  id: number | null;
  name: string;
  url: string;
  credibility_score: number;
  reliability_score: number;
  health_state: string;
}

interface RelatedArticle {
  id: number;
  title: string;
  slug: string;
  summary: string;
  hero_image: string | null;
  source_name: string;
  published_at: string;
}

interface ArticleDetail {
  id: number;
  title: string;
  slug: string;
  summary: string;
  content: string;
  clean_html: string;
  hero_image: string | null;
  tags: string[];
  published_at: string;
  ai_confidence: number;
  reading_time: number;
  category: string;
  source: SourceInfo;
  metadata: {
    seo_title: string;
    seo_keywords: string;
    readability_score: number;
    response_time_ms?: number;
    paragraph_count?: number;
    unique_ratio?: number;
    word_count?: number;
  };
  related_articles: RelatedArticle[];
  thumbnail_url?: string;
  thumbnail_local?: string;
  thumbnail_status?: string;
}

export default function ArticlePage({ params }: { params: Promise<{ slug: string }> }) {
  const resolvedParams = use(params);
  const slug = resolvedParams.slug;

  const { user, logoutUser } = useAppStore();

  const [article, setArticle] = useState<ArticleDetail | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [mounted, setMounted] = useState(false);
  const [copied, setCopied] = useState(false);
  const [userMenuOpen, setUserMenuOpen] = useState(false);
  const [imageError, setImageError] = useState(false);
  const [expanded, setExpanded] = useState(false);
  const [hasMore, setHasMore] = useState(false);
  const articleContentRef = useRef<HTMLDivElement>(null);

  const handleLogout = async () => {
    try {
      await apiFetch("/auth/logout", { method: "POST" });
    } catch {
      // Ignore and flush state
    }
    logoutUser();
    setUserMenuOpen(false);
    if (user && user.role !== "reader") {
      window.location.href = "/login";
    } else {
      window.location.href = "/";
    }
  };

  // Client-side initialization gating (prevents SSR hydration offset warnings)
  useEffect(() => {
    setMounted(true);
  }, []);

  useEffect(() => {
    if (!mounted) return;

    const fetchArticleDetails = async () => {
      setLoading(true);
      try {
        const payload = await apiFetch<ArticleDetail>(`/articles/${slug}`);
        setArticle(payload);
        setError(null);
      } catch (err: any) {
        console.warn("Articles Detail: Failed to load article payload:", err);
        setError(err.message || "Failed to load article detail from autonomous registry.");
      } finally {
        setLoading(false);
      }
    };

    fetchArticleDetails();
  }, [slug, mounted]);

  // Handle Dynamic SEO Metadata titles on mount
  useEffect(() => {
    if (article) {
      document.title = article.metadata.seo_title || `${article.title} - Tech News Today`;
    }
  }, [article]);

  useEffect(() => {
    if (article && articleContentRef.current) {
      const bodyDiv = articleContentRef.current.querySelector(".article-body-content");
      if (bodyDiv) {
        setHasMore(bodyDiv.children.length > 3);
      }
    } else {
      setHasMore(false);
    }
  }, [article]);

  const handleShareLink = () => {
    if (typeof window !== "undefined") {
      navigator.clipboard.writeText(window.location.href);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    }
  };

  // Renders immersive category-specific vector artwork
  const renderHeroGraphic = (category: string) => {
    const cat = category.toLowerCase();
    if (cat.includes("intelligence") || cat.includes("ai")) {
      return (
        <svg className="absolute inset-0 w-full h-full opacity-40 text-[#f0abfc] max-w-sm mx-auto" fill="none" viewBox="0 0 100 100" stroke="currentColor" strokeWidth="0.5">
          <circle cx="50" cy="50" r="32" strokeDasharray="2 3" />
          <circle cx="50" cy="50" r="16" />
          <line x1="20" y1="50" x2="80" y2="50" />
          <line x1="50" y1="20" x2="50" y2="80" />
          <circle cx="50" cy="50" r="5.5" fill="currentColor" className="animate-pulse" />
          <circle cx="20" cy="50" r="3.5" fill="currentColor" />
          <circle cx="80" cy="50" r="3.5" fill="currentColor" />
        </svg>
      );
    }
    if (cat.includes("robot") || cat.includes("robotic")) {
      return (
        <svg className="absolute inset-0 w-full h-full opacity-35 text-[#fef08a] max-w-sm mx-auto" fill="none" viewBox="0 0 100 100" stroke="currentColor" strokeWidth="0.5">
          <rect x="25" y="25" width="50" height="50" strokeDasharray="3 2" />
          <circle cx="50" cy="50" r="14" />
          <line x1="10" y1="10" x2="90" y2="90" />
          <line x1="90" y1="10" x2="10" y2="90" />
          <circle cx="50" cy="50" r="2.5" fill="currentColor" />
        </svg>
      );
    }
    if (cat.includes("startup")) {
      return (
        <svg className="absolute inset-0 w-full h-full opacity-40 text-[#22d3ee] max-w-sm mx-auto" fill="none" viewBox="0 0 100 100" stroke="currentColor" strokeWidth="0.5">
          <path d="M10,85 C30,75 35,40 60,60 T90,15" strokeWidth="0.75" />
          <line x1="10" y1="85" x2="90" y2="85" />
          <circle cx="90" cy="15" r="4.5" fill="currentColor" className="animate-pulse" />
        </svg>
      );
    }
    return (
      <svg className="absolute inset-0 w-full h-full opacity-40 text-[#f87171] max-w-sm mx-auto" fill="none" viewBox="0 0 100 100" stroke="currentColor" strokeWidth="0.5">
        <polygon points="50,12 80,24 80,56 50,85 20,56 20,24" />
        <circle cx="50" cy="40" r="5" fill="currentColor" />
      </svg>
    );
  };

  const getGradientForCategory = (category: string) => {
    const cat = category.toLowerCase();
    if (cat.includes("intelligence") || cat.includes("ai")) {
      return "from-[#0a060d] via-[#100713] to-[#05060b] border-fuchsia-950/60";
    }
    if (cat.includes("robot") || cat.includes("robotic")) {
      return "from-[#0a0705] via-[#110f05] to-[#040905] border-yellow-950/60";
    }
    if (cat.includes("startup")) {
      return "from-[#040909] via-[#040e0e] to-[#04080a] border-cyan-950/60";
    }
    return "from-[#0a0505] via-[#130606] to-[#0a040b] border-red-950/60";
  };

  if (!mounted) {
    return null;
  }

  return (
    <div className="flex flex-col min-h-screen bg-background text-foreground font-sans">
      {/* Top Cyberpunk Accent Bar */}
      <div className="w-full bg-neutral-950 text-white border-b border-border py-1.5 px-4 flex items-center justify-between font-mono text-[9px] tracking-[0.22em] uppercase font-semibold">
        <div className="flex items-center gap-1.5">
          <span className="h-1.5 w-1.5 rounded-full bg-emerald-500 animate-pulse inline-block"></span>
          <span>LIVE TECHNOLOGY INTELLIGENCE</span>
        </div>
        <div className="flex items-center gap-4">
          <Link href="/" className="hover:text-neutral-300 transition-colors">
            ← BACK TO NEWSROOM STREAM
          </Link>
          <span className="text-neutral-700 hidden sm:inline">|</span>
          {/* User Dropdown / Login Button */}
          {user ? (
            <div className="relative">
              <button
                onClick={() => setUserMenuOpen(!userMenuOpen)}
                className="hover:text-foreground transition-colors flex items-center gap-1 uppercase font-bold text-foreground border border-border px-2 py-0.5 bg-card hover:bg-neutral-900 text-[8px]"
              >
                {user.role === "reader" ? "USER" : "ADMIN"} ▼
              </button>
              {userMenuOpen && (
                <div className="absolute right-0 top-full mt-1.5 w-48 border border-border bg-card z-50 shadow-xl font-mono text-[9px] tracking-wider text-left">
                  <div className="px-3 py-2 border-b border-border text-neutral-500 uppercase font-semibold text-[8px]">
                    Role: {user.role.replace("_", " ")}
                  </div>
                  {user.role === "reader" ? (
                    <>
                      <button className="w-full text-left px-3 py-2 text-neutral-400 border-b border-[#141414] opacity-50 cursor-not-allowed">
                        Profile (P5)
                      </button>
                      <button className="w-full text-left px-3 py-2 text-neutral-400 border-b border-[#141414] opacity-50 cursor-not-allowed">
                        Bookmarks (P5)
                      </button>
                      <button className="w-full text-left px-3 py-2 text-neutral-400 border-b border-[#141414] opacity-50 cursor-not-allowed">
                        Settings (P5)
                      </button>
                    </>
                  ) : (
                    <Link href="/admin" className="block px-3 py-2 text-neutral-400 hover:text-white hover:bg-[#111] transition-colors border-b border-[#141414]">
                      Dashboard
                    </Link>
                  )}
                  <button
                    onClick={handleLogout}
                    className="w-full text-left px-3 py-2 text-red-400 hover:text-red-300 hover:bg-[#111] transition-colors font-bold"
                  >
                    Logout
