                </div>
              )}
            </div>
          ) : (
            <Link
              href="/login"
              className="bg-foreground text-background font-bold px-2 py-0.5 hover:bg-neutral-300 transition-colors tracking-widest text-[8px] uppercase"
            >
              Login
            </Link>
          )}
        </div>
      </div>

      {/* Reusable monetization AdLayout wrapping dynamic article page */}
      <AdLayout>
        <div className="max-w-7xl w-full mx-auto px-4 sm:px-6 lg:px-8 py-6 flex-1 flex flex-col lg:flex-row gap-8">
          
          {/* Left Side: Article Reading Space */}
          <div className="flex-1 min-w-0">
            
            {/* Back Navigation & Breadcrumb */}
            <div className="mb-6 flex items-center justify-between">
              <Link 
                href="/" 
                className="inline-flex items-center gap-1.5 font-mono text-[10px] uppercase tracking-wider text-muted hover:text-foreground transition-colors border border-border px-3 py-1.5 bg-card hover:bg-neutral-900"
              >
                <ArrowLeft className="h-3 w-3" /> RETURN TO STREAM
              </Link>
              
              {article && (
                <span className="font-mono text-[10px] uppercase tracking-widest bg-neutral-900 px-2.5 py-1 text-neutral-400 border border-neutral-800">
                  Category: {article.category}
                </span>
              )}
            </div>

            {loading ? (
              /* Immersive Skeleton Loader */
              <div className="space-y-6 animate-pulse">
                <div className="h-4 bg-neutral-900 w-24"></div>
                <div className="h-12 bg-neutral-900 w-3/4"></div>
                <div className="h-5 bg-neutral-900 w-1/3"></div>
                <div className="h-[300px] bg-neutral-900 w-full"></div>
                <div className="space-y-3">
                  <div className="h-4 bg-neutral-900 w-full"></div>
                  <div className="h-4 bg-neutral-900 w-5/6"></div>
                  <div className="h-4 bg-neutral-900 w-4/5"></div>
                </div>
              </div>
            ) : error ? (
              /* Error & 404 state panels */
              <div className="border border-red-900/60 p-8 text-center bg-[#0d0707] max-w-xl mx-auto my-12">
                <AlertCircle className="h-8 w-8 text-red-500 mx-auto mb-3 animate-pulse" />
