                </Link>
              </div>
            ) : article ? (
              <article className="space-y-6">
                
                {/* Category tag and reading metadata block */}
                <div>
                  <h1 className="font-sans text-3xl sm:text-4xl md:text-5xl font-extrabold tracking-tighter leading-[1.15] text-white mb-4">
                    {article.title}
                  </h1>
                  
                  {/* Immersive metadata ribbon with text contrast boost */}
                  <div className="font-mono text-[10px] sm:text-xs text-neutral-300 uppercase tracking-wider flex flex-wrap items-center gap-4 py-3 border-t border-b border-border/80 mb-6 bg-card px-4">
                    <span className="flex items-center gap-1 font-bold text-emerald-400 bg-emerald-950/20 border border-emerald-900/60 px-2 py-0.5 rounded-sm text-[9px] tracking-widest">
                      <ShieldCheck className="h-3.5 w-3.5 text-emerald-400" />
                      VETTED SIGNAL: {(article.ai_confidence).toFixed(1)}% CONF
                    </span>
                    <span className="text-neutral-700 font-normal">•</span>
                    <span className="flex items-center gap-1">
                      <Clock className="h-3.5 w-3.5 text-neutral-500" />
                      {article.reading_time} MIN READ
                    </span>
                    <span className="text-neutral-700 font-normal">•</span>
                    <span className="flex items-center gap-1">
                      <Calendar className="h-3.5 w-3.5 text-neutral-500" />
                      {new Date(article.published_at).toLocaleDateString([], { month: 'short', day: 'numeric', year: 'numeric' })}
                    </span>
                    <button 
                      onClick={handleShareLink} 
                      className="hover:text-white transition-colors flex items-center gap-1 ml-auto font-bold uppercase text-[10px]"
                    >
                      <Share2 className="h-3.5 w-3.5 inline text-neutral-400" />
                      {copied ? "COPIED URL!" : "SHARE LINK"}
                    </button>
                  </div>
                </div>

                {/* Dynamic Abstract Hero Image Placeholder */}
                <div className={`w-full h-48 sm:h-64 border border-border bg-gradient-to-br ${getGradientForCategory(article.category)} flex flex-col items-center justify-center relative overflow-hidden shrink-0`}>
                  <div className="absolute inset-0 opacity-15 bg-[radial-gradient(#fff_1px,transparent_1px)] [background-size:12px_12px] mix-blend-overlay"></div>
                  {renderHeroGraphic(article.category)}

                  {/* Real source thumbnail image */}
                  {(article.thumbnail_local || article.thumbnail_url) && !imageError && (
                    <Image
                      src={(article.thumbnail_local || article.thumbnail_url) as string}
                      alt={article.title}
                      fill
                      sizes="(max-width: 768px) 100vw, 1200px"
                      className="object-cover z-20"
                      unoptimized={true}
                      onError={() => setImageError(true)}
                    />
                  )}

                  {/* Readability Overlay Ribbon */}
                  {(article.thumbnail_local || article.thumbnail_url) && !imageError && (
                    <div className="absolute inset-0 bg-black/75 z-20 pointer-events-none" />
                  )}

                  <span className="font-mono text-[9px] text-white/40 tracking-[0.25em] uppercase mt-2 z-30">
                    {article.source.name} • TRUSTED SIGNAL WIRE
                  </span>
                </div>

                {/* Sanity Cleaned & Extracted Article Body - Collapsible Read More */}
                <div className="max-w-[65ch] mx-auto pt-4 article-detail-body tracking-[0.01em]" ref={articleContentRef}>
                  <div className="relative">
                    <div 
                      className={`font-sans text-base sm:text-lg text-neutral-300 leading-relaxed sm:leading-8 article-body-content ${
                        expanded ? "expanded" : "collapsed"
                      }`}
                      dangerouslySetInnerHTML={{ __html: article.clean_html || "" }}
                    />
                    {hasMore && !expanded && (
                      <div className="absolute bottom-0 left-0 right-0 h-32 article-fade-overlay pointer-events-none" />
                    )}
                  </div>
                  
                  {hasMore && (
                    <div className={`border-b border-neutral-900 pb-10 ${!expanded ? "mt-4" : "mt-8"}`}>
                      {!expanded && (
                        <button
                          onClick={() => setExpanded(true)}
                          className="block mx-auto font-mono uppercase tracking-[0.12em] text-[#00d4aa] border-b border-[#00d4aa] hover:opacity-80 transition-opacity bg-transparent"
                        >
                          Read More →
                        </button>
                      )}
                      {expanded && (
                        <button
                          onClick={() => {
                            setExpanded(false);
                            articleContentRef.current?.scrollIntoView({ behavior: "smooth", block: "start" });
                          }}
                          className="block mx-auto font-mono uppercase tracking-[0.12em] text-[#00d4aa] border-b border-[#00d4aa] hover:opacity-80 transition-opacity bg-transparent"
                        >
                          ← Show Less
                        </button>
                      )}
                    </div>
                  )}
                  {!hasMore && <div className="border-b border-neutral-900 pb-10" />}
                </div>

                {/* Category tags block */}
                {article.tags.length > 0 && (
                  <div className="flex flex-wrap gap-1.5 pt-4 max-w-3xl mx-auto font-mono text-[9px] uppercase">
                    <span className="text-muted mr-1 self-center">TAGS:</span>
                    {article.tags.map((tag, idx) => (
                      <span key={idx} className="bg-neutral-950 border border-neutral-800 text-neutral-400 px-2 py-0.5">
                        #{tag}
                      </span>
                    ))}
                  </div>
                )}
              </article>
            ) : null}
          </div>

          {/* Right Side: Dense Telemetry & Related Stories Sidebar */}
          <aside className="w-full lg:w-80 space-y-5 shrink-0">
            
            {/* Related Stories Stream */}
            <div className="border border-border p-4 bg-card relative">
              <div className="absolute top-0 right-0 border-l border-b border-border bg-card px-2 py-0.5 font-mono text-[7px] tracking-widest text-[#888888]">
                WIRE-NODE
              </div>
              <h3 className="font-mono text-[10px] font-bold uppercase tracking-widest border-b border-border pb-2.5 mb-3.5 text-foreground flex items-center gap-1.5">
                <BookOpen className="h-3.5 w-3.5 text-[#22d3ee]" />
                Related Stories
              </h3>
              
              {loading ? (
                <div className="space-y-3">
                  {[1, 2].map((i) => (
                    <div key={i} className="h-16 bg-neutral-900 animate-pulse w-full"></div>
                  ))}
                </div>
              ) : article && article.related_articles.length > 0 ? (
                <div className="space-y-4">
                  {article.related_articles.map((rel) => (
                    <Link 
                      key={rel.id} 
                      href={`/articles/${rel.slug}`}
                      className="block border border-border/60 hover:border-neutral-400 p-2.5 bg-neutral-950/40 hover:bg-neutral-950 transition-all duration-300 group"
                    >
                      <div className="flex items-center gap-2 mb-1.5 font-mono text-[8px] text-neutral-400">
                        <span className="text-neutral-200 font-bold border border-border/80 px-1 py-0.2 uppercase text-[7px]">
                          {rel.source_name}
                        </span>
                        <span>
                          {new Date(rel.published_at).toLocaleDateString([], { month: 'short', day: 'numeric' })}
                        </span>
                      </div>
                      <h4 className="font-sans text-[11px] sm:text-xs font-extrabold tracking-tight text-neutral-200 leading-snug group-hover:underline line-clamp-2">
                        {rel.title}
                      </h4>
                    </Link>
                  ))}
                </div>
              ) : (
                <p className="font-mono text-[9px] text-muted text-center py-4">No related tech stories compiled yet.</p>
              )}
            </div>

            {/* Dynamic Source Attribution Card */}
            {article && (
              <div className="border border-border p-4 bg-card relative">
                <div className="absolute top-0 right-0 border-l border-b border-border bg-card px-2 py-0.5 font-mono text-[7px] tracking-widest text-[#888888]">
                  TRUST-DEEP
                </div>
                <h3 className="font-mono text-[10px] font-bold uppercase tracking-widest border-b border-border pb-2.5 mb-3.5 text-foreground flex items-center gap-1.5">
                  <ShieldCheck className="h-4 w-4 text-emerald-500" />
                  Source Intelligence
                </h3>
                
                <ul className="space-y-2.5 font-mono text-[10px] leading-relaxed">
                  <li className="flex justify-between items-center border-b border-neutral-900 pb-1.5">
                    <span className="text-muted">Domain Provider:</span>
                    <span className="font-bold text-foreground truncate max-w-[150px]">{article.source.name}</span>
                  </li>
                  <li className="flex justify-between items-center border-b border-neutral-900 pb-1.5">
                    <span className="text-muted">Credibility Score:</span>
                    <span className={`font-bold ${article.source.credibility_score >= 80 ? "text-emerald-500" : "text-amber-500"}`}>
                      {article.source.credibility_score}/100
                    </span>
                  </li>
                  <li className="flex justify-between items-center border-b border-neutral-900 pb-1.5">
                    <span className="text-muted">Crawl Reliability:</span>
                    <span className="font-bold text-foreground">{(article.source.reliability_score).toFixed(1)}%</span>
                  </li>
                  <li className="flex justify-between items-center border-b border-neutral-900 pb-1.5">
                    <span className="text-muted">Readability Grade:</span>
                    <span className="font-bold text-foreground">{article.metadata?.readability_score ?? 60}/100</span>
                  </li>
                  <li className="flex justify-between items-center border-b border-neutral-900 pb-1.5">
                    <span className="text-muted">Crawl Latency:</span>
                    <span className="font-bold text-foreground">{article.metadata?.response_time_ms ?? 350}ms</span>
                  </li>
                  <li className="flex justify-between items-center border-b border-neutral-900 pb-1.5">
                    <span className="text-muted">Paragraph Count:</span>
                    <span className="font-bold text-foreground">{article.metadata?.paragraph_count ?? 4}</span>
                  </li>
                  <li className="flex justify-between items-center border-b border-neutral-900 pb-1.5">
                    <span className="text-muted">Boilerplate Density:</span>
                    <span className="font-bold text-foreground">
                      {article.metadata?.unique_ratio 
                        ? ((1.0 - article.metadata.unique_ratio) * 100).toFixed(0) 
                        : "45"}%
                    </span>
                  </li>
                  <li className="flex justify-between items-center border-b border-neutral-900 pb-1.5">
                    <span className="text-muted">Clean Word Count:</span>
                    <span className="font-bold text-foreground">
                      {article.metadata?.word_count ?? (article.content ? article.content.split(/\s+/).length : 150)}
                    </span>
                  </li>
                  <li className="flex justify-between items-center">
                    <span className="text-muted">Signal Status:</span>
                    <span className="text-emerald-500 font-bold flex items-center gap-1">
                      <span className="h-1 w-1 rounded-full bg-emerald-500 animate-ping"></span>
                      SECURE LINK
                    </span>
                  </li>
                </ul>
              </div>
            )}
          </aside>
        </div>
      </AdLayout>
    </div>
  );
}

