"use client";

import { useState, useEffect, FormEvent, useCallback } from "react";
import { useRouter } from "next/navigation";
import Link from "next/link";
import { GoogleLogin } from "@react-oauth/google";
import { useAppStore } from "../../store/useStore";
import { apiFetch, APIClientError } from "../../services/api";

const API_BASE = process.env.NEXT_PUBLIC_API_URL || "/api/v1";

interface AuthResponse {
  access_token: string;
  token_type: string;
  user: {
    id: number;
    name: string;
    email: string;
    role: string;
    permissions: string[];
  };
}

export default function LoginPage() {
  const router = useRouter();
  const { user, loginUser } = useAppStore();

  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [showPassword, setShowPassword] = useState(false);
  const [rememberMe, setRememberMe] = useState(false);
  const [loading, setLoading] = useState(false);
  const [googleLoading, setGoogleLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [mounted, setMounted] = useState(false);

  useEffect(() => {
    setMounted(true);
  }, []);

  // If already authenticated, redirect
  useEffect(() => {
    if (mounted && user) {
      redirectByRole(user.role);
    }
  }, [mounted, user]);

  const redirectByRole = useCallback(
    (role: string) => {
      if (role === "reader") {
        router.push("/");
      } else {
        router.push("/admin");
      }
    },
    [router]
  );

  const handleLogin = async (e: FormEvent) => {
    e.preventDefault();
    if (!email.trim() || !password.trim()) {
      setError("Email and password are required.");
      return;
    }
    setError(null);
    setLoading(true);

    try {
      const data = await apiFetch<AuthResponse>("/auth/login", {
        method: "POST",
        body: JSON.stringify({ email: email.trim(), password, remember_me: rememberMe }),
      });

      loginUser(data.user, data.access_token);
      redirectByRole(data.user.role);
    } catch (err: any) {
      if (err instanceof APIClientError) {
        if (err.status === 401) {
          setError("Invalid credentials. Check your email and password.");
        } else if (err.status === 403) {
          setError("Account suspended. Contact system administrator.");
        } else if (err.status === 429) {
          setError("Too many attempts. Try again in a few minutes.");
        } else {
          setError(err.message || "Authentication failed.");
        }
      } else {
        setError("Connection error. Verify the API gateway is online.");
      }
    } finally {
      setLoading(false);
    }
  };

  const handleGoogleSuccess = async (credentialResponse: any) => {
    setError(null);
    setGoogleLoading(true);
    try {
      const data = await apiFetch<AuthResponse>("/auth/google", {
        method: "POST",
        body: JSON.stringify({ credential: credentialResponse.credential }),
      });
      loginUser(data.user, data.access_token);
      redirectByRole(data.user.role);
    } catch (err: any) {
      setError(err.message || "Google authentication failed.");
    } finally {
      setGoogleLoading(false);
    }
  };

  const handleGoogleError = () => {
    setError("Google Sign-In failed.");
  };

  if (!mounted) {
    return (
      <div className="min-h-screen bg-[#080808] flex items-center justify-center">
        <div className="w-6 h-6 border border-white/20 border-t-white animate-spin" />
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#080808] flex flex-col items-center justify-center px-4 relative overflow-hidden">
      {/* Subtle background grid */}
      <div className="absolute inset-0 border-grid opacity-[0.03]" />

      {/* System status bar */}
      <div className="fixed top-0 left-0 right-0 z-50 bg-neutral-950 border-b border-[#1a1a1a] py-1.5 px-4">
        <div className="flex items-center justify-center gap-2 font-mono text-[9px] tracking-[0.25em] uppercase text-neutral-400">
          <span className="h-1.5 w-1.5 bg-emerald-500 animate-pulse inline-block" />
          <span>TECH NEWS TODAY • AUTONOMOUS NEWSROOM ACCESS</span>
        </div>
      </div>

      {/* Login card */}
      <div className="w-full max-w-md relative z-10">
        {/* Logo header */}
        <div className="text-center mb-8">
          <h1 className="text-3xl font-extrabold tracking-tighter text-white font-sans uppercase">
            TECH NEWS TODAY
          </h1>
          <p className="font-mono text-[10px] tracking-[0.3em] uppercase text-[#888] mt-2">
            Secure Operations Portal
          </p>
        </div>

        {/* Main card */}
        <div
          className={`border bg-[#0c0c0c] p-6 transition-colors duration-300 ${
            error ? "border-red-500/60" : "border-[#1a1a1a]"
          }`}
        >
          {/* Error banner */}
          {error && (
            <div className="mb-4 border border-red-500/30 bg-red-500/5 px-3 py-2 flex items-start gap-2">
              <svg className="w-3.5 h-3.5 text-red-400 mt-0.5 shrink-0" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                <circle cx="12" cy="12" r="10" />
                <line x1="12" y1="8" x2="12" y2="12" />
                <line x1="12" y1="16" x2="12.01" y2="16" />
              </svg>
              <p className="font-mono text-[10px] text-red-400 leading-relaxed">{error}</p>
            </div>
          )}

          <form onSubmit={handleLogin} className="space-y-4">
            {/* Email */}
            <div>
              <label
                htmlFor="login-email"
                className="block font-mono text-[9px] tracking-widest uppercase text-[#888] mb-1.5"
              >
                EMAIL ADDRESS
              </label>
              <input
                id="login-email"
                type="email"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                autoComplete="email"
                placeholder="operator@technews.today"
                className="w-full bg-[#080808] border border-[#1a1a1a] px-3 py-2.5 font-mono text-[12px] text-white placeholder-neutral-600 focus:outline-none focus:border-white transition-colors"
              />
            </div>

            {/* Password */}
            <div>
              <label
                htmlFor="login-password"
                className="block font-mono text-[9px] tracking-widest uppercase text-[#888] mb-1.5"
              >
                PASSWORD
              </label>
              <div className="relative">
                <input
                  id="login-password"
                  type={showPassword ? "text" : "password"}
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  autoComplete="current-password"
                  placeholder="••••••••••••"
                  className="w-full bg-[#080808] border border-[#1a1a1a] px-3 py-2.5 pr-16 font-mono text-[12px] text-white placeholder-neutral-600 focus:outline-none focus:border-white transition-colors"
                />
                <button
                  type="button"
                  onClick={() => setShowPassword(!showPassword)}
                  className="absolute right-3 top-1/2 -translate-y-1/2 font-mono text-[8px] tracking-widest uppercase text-[#555] hover:text-white transition-colors"
                >
                  {showPassword ? "HIDE" : "SHOW"}
                </button>
              </div>
            </div>

            {/* Remember me + Forgot password */}
            <div className="flex items-center justify-between">
              <label className="flex items-center gap-2 cursor-pointer group" htmlFor="login-remember">
                <div className="relative">
                  <input
                    id="login-remember"
                    type="checkbox"
                    checked={rememberMe}
                    onChange={(e) => setRememberMe(e.target.checked)}
                    className="sr-only"
                  />
                  <div
                    className={`w-3.5 h-3.5 border transition-colors ${
                      rememberMe
                        ? "bg-white border-white"
                        : "border-[#333] group-hover:border-[#555]"
                    }`}
                  >
                    {rememberMe && (
                      <svg className="w-3.5 h-3.5 text-black" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3">
                        <polyline points="20 6 9 17 4 12" />
                      </svg>
                    )}
                  </div>
                </div>
                <span className="font-mono text-[9px] tracking-wider uppercase text-[#888] group-hover:text-white transition-colors">
                  Remember Session
                </span>
              </label>
              <button
                type="button"
                className="font-mono text-[9px] tracking-wider text-[#888] hover:text-white transition-colors uppercase"
              >
                Forgot Password?
              </button>
            </div>

            {/* Login Button */}
            <button
              id="login-submit"
              type="submit"
              disabled={loading}
              className="w-full bg-white text-black font-mono text-[11px] uppercase tracking-[0.2em] py-3 hover:bg-neutral-200 transition-colors disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2"
            >
              {loading ? (
                <>
                  <svg className="animate-spin h-3.5 w-3.5" viewBox="0 0 24 24" fill="none">
                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" />
                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8v4a4 4 0 00-4 4H4z" />
                  </svg>
                  <span>AUTHENTICATING</span>
                </>
              ) : (
                <span>SECURE LOGIN</span>
              )}
            </button>
          </form>

          {/* Divider */}
          <div className="flex items-center gap-3 my-5">
            <div className="flex-1 h-px bg-[#1a1a1a]" />
            <span className="font-mono text-[9px] text-[#555] tracking-widest">OR</span>
            <div className="flex-1 h-px bg-[#1a1a1a]" />
          </div>

          {/* Google Sign In */}
          <div className="w-full flex justify-center">
            {googleLoading ? (
              <div className="w-full border border-[#333] bg-transparent text-white py-3 flex items-center justify-center">
                <svg className="animate-spin h-3.5 w-3.5" viewBox="0 0 24 24" fill="none">
                  <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" />
                  <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8v4a4 4 0 00-4 4H4z" />
                </svg>
              </div>
            ) : (
              <div className="w-full relative [&>div]:!w-full [&>div>div]:!w-full [&_iframe]:!w-full">
                <GoogleLogin
                  onSuccess={handleGoogleSuccess}
                  onError={handleGoogleError}
                  theme="filled_black"
                  shape="rectangular"
                  text="signin_with"
                  size="large"
                />
              </div>
            )}
          </div>

          {/* Sign Up Redirect */}
          <div className="mt-5 text-center font-mono text-[10px] tracking-wider text-[#666] border-t border-[#1a1a1a] pt-4 select-none">
            Don&apos;t have an account?{" "}
            <Link
              href="/signup"
              className="text-white hover:underline uppercase font-bold transition-colors"
            >
              Create Account
            </Link>
          </div>
        </div>

        {/* Footer system status */}
        <div className="mt-6 flex items-center justify-center gap-2">
          <span className="h-1.5 w-1.5 bg-emerald-500 inline-block" />
          <span className="font-mono text-[9px] tracking-[0.2em] uppercase text-[#555]">
            System Status: Operational
          </span>
        </div>
      </div>
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import Image from "next/image";
import Link from "next/link";
import { useAppStore } from "../store/useStore";
import { apiFetch } from "../services/api";
import { searchArticles, Article } from "../services/api/news";
import AdLayout from "../components/AdLayout";
import { 
  ShieldCheck, Search, Moon, Sun, Cpu, Database, RefreshCw, Layers, 
  Terminal, Activity, Radio, ArrowUpRight, Clock, AlertCircle, 
  TerminalSquare, Server, CpuIcon, CheckCircle2, Orbit 
} from "lucide-react";

interface Category {
  id: number;
  name: string;
  slug: string;
}



// 1. Sleek Monochromatic Loading Skeleton Component
// Used during initial server-side render (SSR) and client hydration.
// Contains zero inputs or buttons to guarantee no browser auto-fills (like fdprocessedid) cause hydration mismatches.
function LoadingSkeleton() {
  return (
    <div className="dashboard-shell">
      <div className="dashboard-header">
        <div className="w-full bg-neutral-900 py-1.5 px-4 text-center font-mono text-[9px] tracking-[0.25em] uppercase font-semibold text-white">
          Syncing with Autonomous Agents...
        </div>
      </div>

      <div className="dashboard-grid">
        <div className="dashboard-feed p-4 space-y-4">
          <div className="h-6 bg-neutral-900 w-1/3 animate-pulse"></div>
          {[1, 2, 3, 4].map((i) => (
            <div key={i} className="border border-[#1a1a1a] p-4 bg-[#0c0c0c] animate-pulse space-y-3">
              <div className="h-3.5 bg-neutral-900 w-1/4"></div>
              <div className="h-5 bg-neutral-900 w-3/4"></div>
              <div className="h-3.5 bg-neutral-900 w-5/6"></div>
            </div>
          ))}
        </div>

        <div className="dashboard-sidebar hidden lg:block p-4 space-y-4">
          <div className="border border-[#1a1a1a] p-4 bg-[#0c0c0c] animate-pulse space-y-3">
            <div className="h-3.5 bg-neutral-900 w-1/2"></div>
            <div className="h-3 bg-neutral-900 w-full"></div>
            <div className="h-3 bg-neutral-900 w-3/4"></div>
          </div>
          <div className="border border-[#1a1a1a] p-4 bg-[#0c0c0c] animate-pulse space-y-3">
            <div className="h-3.5 bg-neutral-900 w-1/2"></div>
            <div className="h-3 bg-neutral-900 w-full"></div>
            <div className="h-3 bg-neutral-900 w-3/4"></div>
            <div className="h-3 bg-neutral-900 w-2/3"></div>
          </div>
        </div>
      </div>
    </div>
  );
}

export default function HomePage() {
  const {
    theme,
    toggleTheme,
    selectedCategory,
    setCategory,
    searchQuery,
    setSearchQuery,
    cachedArticles,
    setCachedArticles,
    user,
    logoutUser
  } = useAppStore();

  // Component States
  const [categories, setCategories] = useState<Category[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [imageErrors, setImageErrors] = useState<Record<number, boolean>>({});
  const [backendStatus, setBackendStatus] = useState<"loading" | "online" | "offline" | "proxy_error" | "sse_disconnected">("loading");
  const [userMenuOpen, setUserMenuOpen] = useState(false);

  const handleLogout = async () => {
    try {
      await apiFetch("/auth/logout", { method: "POST" });
    } catch {
      // Ignore and flush state
    }
    logoutUser();
    setUserMenuOpen(false);
    if (user && user.role !== "reader") {
      window.location.href = "/login";
    } else {
      window.location.href = "/";
    }
  };

  // Probes live/ready endpoints to determine server & database state
  const probeBackendStatus = async () => {
    const apiBase = process.env.NEXT_PUBLIC_API_URL || "/api/v1";
    try {
      const liveRes = await fetch(`${apiBase}/health/live`);
      if (liveRes.status === 200) {
        try {
          const readyRes = await fetch(`${apiBase}/health/ready`);
          if (readyRes.status === 200) {
            setBackendStatus("online");
          } else {
            setBackendStatus("offline");
          }
        } catch (dbErr) {
          setBackendStatus("offline");
        }
      } else if (liveRes.status === 502 || liveRes.status === 504 || liveRes.status === 503) {
        setBackendStatus("proxy_error");
      } else {
        setBackendStatus("sse_disconnected");
      }
    } catch (netErr: any) {
      setBackendStatus("proxy_error");
    }
  };

  // Gating state to prevent SSR / Hydration mismatch errors on browser autocompletes
  const [mounted, setMounted] = useState(false);

  // Diagnostics States
  const [backendLatency, setBackendLatency] = useState<number | null>(null);
  const [dbLatency, setDbLatency] = useState<number | null>(null);
  const [redisLatency, setRedisLatency] = useState<number | null>(null);
  const [diagnosticsRunning, setDiagnosticsRunning] = useState(false);

  // Collapsible state for Diagnostics panel
  const [diagnosticsExpanded, setDiagnosticsExpanded] = useState(false);

  // Initialize liveLogs as empty to prevent client-server mismatched initial render state
  const [liveLogs, setLiveLogs] = useState<Array<{ time: string; agent: string; msg: string; status: "info" | "success" | "warn" }>>([]);

  // Dynamic Telemetry Snapshot State
  const [telemetry, setTelemetry] = useState<any>(null);

  // Mobile sidebar toggle
  const [sidebarOpen, setSidebarOpen] = useState(false);

  // Search state for server-side full-text search
  const [searchResults, setSearchResults] = useState<Article[] | null>(null);
  const [searchLoading, setSearchLoading] = useState(false);

  // Real-Time Ingestion Transitions State
  const [realtimeIncomingIds, setRealtimeIncomingIds] = useState<number[]>([]);

  // Advanced Search & Filter States
  const [filterSourceCategory, setFilterSourceCategory] = useState<string>("");
  const [sortBy, setSortBy] = useState<string>("relevance");

  // Trend Explorer Overlay State
  const [selectedTrend, setSelectedTrend] = useState<string | null>(null);
  const [trendDetails, setTrendDetails] = useState<any | null>(null);
  const [trendLoading, setTrendLoading] = useState<boolean>(false);

  // Source Health Diagnostics Sidebar States
  const [sourcesTelemetry, setSourcesTelemetry] = useState<any[]>([]);
  const [sourcesLoading, setSourcesLoading] = useState<boolean>(false);
  const [sourcesExpanded, setSourcesExpanded] = useState<boolean>(false);

  // Password-Gated Admin Controls State
  const [adminExpanded, setAdminExpanded] = useState<boolean>(false);
  const [adminPassword, setAdminPassword] = useState<string>("");
  const [adminUnlocked, setAdminUnlocked] = useState<boolean>(false);
  const [adminSources, setAdminSources] = useState<any[]>([]);
  const [adminLoading, setAdminLoading] = useState<boolean>(false);
  const [adminStatusMsg, setAdminStatusMsg] = useState<string | null>(null);

  // Dynamic Ticker Headlines (derived from real telemetry)
  const tickerHeadlines = telemetry ? [
    `MONITOR AGENTS: ${telemetry.source_health?.total_registered || 0} sources registered, ${telemetry.source_health?.healthy || 0} healthy •`,
    `INGESTION RATE: Processing at ${(telemetry.ingestion_rate_sec * 60).toFixed(1)} art/min •`,
    `TOTAL INGESTED: ${telemetry.total_articles_ingested || 0} raw articles parsed •`,
    `PUBLISHED: ${telemetry.total_articles_published || 0} editorial articles live •`,
    `QUEUE DEPTH: ${telemetry.queue_depth || 0} tasks pending execution •`
  ] : [
    "SYSTEM INITIALIZING: Connecting to autonomous agent network •",
    "LOADING: Fetching telemetry snapshot from backend •"
  ];

  // Client-side initialization block
  useEffect(() => {
    setMounted(true);
  }, []);

  // Resolve API base to absolute URL for EventSource (which requires absolute URLs)
  const resolveSSEUrl = (path: string): string => {
    const apiBase = process.env.NEXT_PUBLIC_API_URL || "/api/v1";
    const url = `${apiBase}${path}`;
    if (url.startsWith("/")) {
      return `${window.location.protocol}//${window.location.host}${url}`;
    }
    return url;
  };

  // Connect to REAL agent event SSE stream (replaces simulated logs)
  useEffect(() => {
    if (!mounted) return;

    const eventsUrl = resolveSSEUrl("/events/stream");

    let eventSource: EventSource | null = null;
    let reconnectDelay = 1000;
    const maxReconnectDelay = 30000;
    let keepaliveTimer: NodeJS.Timeout | null = null;
    let reconnectTimer: NodeJS.Timeout | null = null;

    const resetKeepalive = () => {
      if (keepaliveTimer) clearTimeout(keepaliveTimer);
      // Wait for 45s of silence before triggering reconnect
      keepaliveTimer = setTimeout(() => {
        console.warn("EventSource events: 45s keepalive timeout exceeded. Reconnecting...");
        setBackendStatus("sse_disconnected");
        connect();
      }, 45000);
    };

    const connect = () => {
      if (eventSource) {
        eventSource.close();
      }
      if (reconnectTimer) clearTimeout(reconnectTimer);

      eventSource = new EventSource(eventsUrl);

      eventSource.onopen = () => {
        reconnectDelay = 1000;
        setBackendStatus("online");
        resetKeepalive();
      };

      eventSource.onmessage = (event) => {
        resetKeepalive();
        try {
          const data = JSON.parse(event.data);
          setBackendStatus("online");
          if (data.agent && data.msg) {
            setLiveLogs((prev) => [data, ...prev.slice(0, 7)]);
          }
          if (data.agent === "INGESTION" && data.meta) {
            const newArt = data.meta;
            setCachedArticles((prev) => {
              if (prev.some((a) => a.slug === newArt.slug || a.id === newArt.id)) {
                return prev;
              }
              return [newArt, ...prev];
            });
            setRealtimeIncomingIds((prev) => [...prev, newArt.id]);
            setTimeout(() => {
              setRealtimeIncomingIds((prev) => prev.filter((id) => id !== newArt.id));
            }, 5000);
          }
        } catch (err) {
          // Ignore comments (like keepalive comments)
        }
      };

      eventSource.onerror = async () => {
        if (keepaliveTimer) clearTimeout(keepaliveTimer);
        eventSource?.close();

        await probeBackendStatus();

        reconnectTimer = setTimeout(() => {
          reconnectDelay = Math.min(reconnectDelay * 2, maxReconnectDelay);
          connect();
        }, reconnectDelay);
      };
    };

    connect();

    return () => {
      if (eventSource) eventSource.close();
      if (keepaliveTimer) clearTimeout(keepaliveTimer);
      if (reconnectTimer) clearTimeout(reconnectTimer);
    };
  }, [mounted, setCachedArticles]);

  // Debounced server-side search sensitive to tags, source categories and freshness sorting
  useEffect(() => {
    if (!mounted) return;
    if (!searchQuery && !filterSourceCategory) {
      setSearchResults(null);
      return;
    }

    const debounceTimer = setTimeout(async () => {
      setSearchLoading(true);
      try {
        const results = await searchArticles(searchQuery, filterSourceCategory, sortBy, 15);
        setSearchResults(results);
      } catch (err) {
        setSearchResults(null);
      } finally {
        setSearchLoading(false);
      }
    }, 400);

    return () => clearTimeout(debounceTimer);
  }, [searchQuery, filterSourceCategory, sortBy, mounted]);

  // Fetch detailed trend briefings for Live Trend Explorer
  const loadTrendDetails = async (topic: string) => {
    setTrendLoading(true);
    setSelectedTrend(topic);
    try {
      const data = await apiFetch<any>(`/telemetry/trends/${encodeURIComponent(topic)}/explorer`);
      setTrendDetails(data);
    } catch (err) {
      console.warn("Telemetry Trend Explorer: Failed to load trend metrics:", err);
      setTrendDetails(null);
    } finally {
      setTrendLoading(false);
    }
  };

  // Fetch registered source health statistics
  const fetchSourcesTelemetry = async () => {
    setSourcesLoading(true);
    try {
      const data = await apiFetch<any[]>("/telemetry/sources");
      setSourcesTelemetry(data);
    } catch (err) {
      console.warn("Telemetry Sources Audit: Offline fallback:", err);
      setSourcesTelemetry([]);
    } finally {
      setSourcesLoading(false);
    }
  };

  // Fetch admin sources panel
  const fetchAdminSources = async () => {
    setAdminLoading(true);
    try {
      const data = await apiFetch<any[]>("/admin/sources");
      setAdminSources(data);
    } catch (err) {
      console.warn("Admin Controls: Failed to fetch sources:", err);
      setAdminSources([]);
    } finally {
      setAdminLoading(false);
    }
  };

  // Toggle single source enable status
  const toggleSourceState = async (sourceId: number) => {
    try {
      await apiFetch<any>(`/admin/sources/${sourceId}/toggle`, { method: "POST" });
      setAdminStatusMsg("Source scheduling toggled successfully.");
      setTimeout(() => setAdminStatusMsg(null), 3000);
      fetchAdminSources();
      fetchSourcesTelemetry();
    } catch (err: any) {
      setAdminStatusMsg(`Toggle failed: ${err.message || "error"}`);
      setTimeout(() => setAdminStatusMsg(null), 3000);
    }
  };

  // Force crawl single source immediately
  const triggerSourceForceCrawl = async (sourceId: number) => {
    setAdminStatusMsg("Manually forcing crawl... (this runs crawler synchronously)");
    try {
      const res = await apiFetch<any>(`/admin/sources/${sourceId}/trigger`, { method: "POST" });
      setAdminStatusMsg(`Force crawl completed. Discovered: ${res.articles_discovered}, Saved: ${res.articles_saved}`);
      setTimeout(() => setAdminStatusMsg(null), 4000);
      fetchAdminSources();
      fetchSourcesTelemetry();
      
      // Reload main page articles
      const articlesData = await apiFetch<Article[]>("/news");
      setCachedArticles(articlesData);
    } catch (err: any) {
      setAdminStatusMsg(`Force crawl failed: ${err.message || "error"}`);
      setTimeout(() => setAdminStatusMsg(null), 4000);
    }
  };

  useEffect(() => {
    if (sourcesExpanded) {
      fetchSourcesTelemetry();
    }
  }, [sourcesExpanded]);

  useEffect(() => {
    if (adminUnlocked && adminExpanded) {
      fetchAdminSources();
    }
  }, [adminUnlocked, adminExpanded]);

  // Connect to live telemetry SSE stream
  useEffect(() => {
    if (!mounted) return;
    
    const sseUrl = resolveSSEUrl("/telemetry/sse");
    
    let eventSource: EventSource | null = null;
    let reconnectDelay = 1000;
    const maxReconnectDelay = 30000;
    let keepaliveTimer: NodeJS.Timeout | null = null;
    let reconnectTimer: NodeJS.Timeout | null = null;

    const resetKeepalive = () => {
      if (keepaliveTimer) clearTimeout(keepaliveTimer);
      keepaliveTimer = setTimeout(() => {
        console.warn("EventSource telemetry: 45s keepalive timeout exceeded. Reconnecting...");
        connect();
      }, 45000);
    };

    const connect = () => {
      if (eventSource) {
        eventSource.close();
      }
      if (reconnectTimer) clearTimeout(reconnectTimer);

      eventSource = new EventSource(sseUrl);

      eventSource.onopen = () => {
        reconnectDelay = 1000;
        resetKeepalive();
      };

      eventSource.onmessage = (event) => {
        resetKeepalive();
        try {
          const data = JSON.parse(event.data);
          setTelemetry(data);
          setBackendStatus("online");
        } catch (err) {
          console.warn("Telemetry SSE parse error:", err);
        }
      };

      eventSource.onerror = async () => {
        if (keepaliveTimer) clearTimeout(keepaliveTimer);
        eventSource?.close();

        await probeBackendStatus();

        reconnectTimer = setTimeout(() => {
          reconnectDelay = Math.min(reconnectDelay * 2, maxReconnectDelay);
          connect();
        }, reconnectDelay);
      };
    };

    connect();
    
    return () => {
      if (eventSource) eventSource.close();
      if (keepaliveTimer) clearTimeout(keepaliveTimer);
      if (reconnectTimer) clearTimeout(reconnectTimer);
    };
  }, [mounted]);

  // Run dynamic metrics against our backend endpoints
  const runDiagnostics = async () => {
    setDiagnosticsRunning(true);
    try {
      const startBackend = performance.now();
      await apiFetch<any>("/health/live");
      setBackendLatency(Math.round(performance.now() - startBackend));

      const readyData = await apiFetch<any>("/health/ready");
      setDbLatency(readyData.dependencies?.postgres?.latency_ms || null);
      setRedisLatency(readyData.dependencies?.redis?.latency_ms || null);
      
      setError(null);
    } catch (err: any) {
      console.warn("Diagnostics check offline fallback:", err);
      setBackendLatency(null);
      setDbLatency(null);
      setRedisLatency(null);
    } finally {
      setDiagnosticsRunning(false);
    }
  };

  useEffect(() => {
    if (typeof window !== "undefined") {
      document.documentElement.classList.add("dark");
    }

    const loadInitialData = async () => {
      setLoading(true);
      try {
        const results = await Promise.allSettled([
          apiFetch<Category[]>("/categories"),
          apiFetch<Article[]>("/news")
        ]);

        let hasSuccess = false;

        const categoriesResult = results[0];
        if (categoriesResult.status === "fulfilled") {
          setCategories(categoriesResult.value);
          hasSuccess = true;
        } else {
          console.warn("Failed to load categories:", categoriesResult.reason);
          setCategories([
            { id: 1, name: "Artificial Intelligence", slug: "artificial-intelligence" },
            { id: 2, name: "Robotics", slug: "robotics" },
            { id: 3, name: "Startups", slug: "startups" },
            { id: 4, name: "Cybersecurity", slug: "cybersecurity" },
            { id: 5, name: "Software Development", slug: "software-development" },
            { id: 6, name: "Space & Science", slug: "space-science" }
          ]);
        }

        const newsResult = results[1];
        if (newsResult.status === "fulfilled") {
          setCachedArticles(newsResult.value);
          hasSuccess = true;
        } else {
          console.warn("Failed to load news articles:", newsResult.reason);
          setCachedArticles([]);
        }

        if (hasSuccess) {
          setBackendStatus("online");
          setError(null);
        } else {
          throw new Error("Both categories and news endpoints failed to load.");
        }
      } catch (err: any) {
        console.warn("Failed to connect to API. Newsroom running in offline mode.", err);
        setCategories([
          { id: 1, name: "Artificial Intelligence", slug: "artificial-intelligence" },
          { id: 2, name: "Robotics", slug: "robotics" },
          { id: 3, name: "Startups", slug: "startups" },
          { id: 4, name: "Cybersecurity", slug: "cybersecurity" },
          { id: 5, name: "Software Development", slug: "software-development" },
          { id: 6, name: "Space & Science", slug: "space-science" }
        ]);
        setCachedArticles([]);
        setError("API offline — waiting for backend connection.");
        await probeBackendStatus();
      } finally {
        setLoading(false);
        runDiagnostics();
      }
    };

    loadInitialData();
  }, []);

  // Return loading skeleton during SSR and initial browser hydration phase.
  // This guarantees zero form-autofill attributes (fdprocessedid) cause mismatches before React mounts.
  if (!mounted) {
    return <LoadingSkeleton />;
  }

  // Filter logic: use server-side search results when available, otherwise filter by category
  const baseArticles = searchResults !== null ? searchResults : cachedArticles;
  const filteredArticles = baseArticles.filter((article) => {
    const matchesCategory = selectedCategory
      ? article.category.toLowerCase().replace(/\s+/g, "-") === selectedCategory
      : true;
    return matchesCategory;
  });

  // Gradient Abstract SVG Graphic Generators
  // Returns highly immersive, premium custom SVGs customized for each news category
  const renderCategoryGraphic = (category: string) => {
    const cat = category.toLowerCase();
    
    // Neural Connections Vector Pattern for AI
    if (cat.includes("intelligence") || cat.includes("ai")) {
      return (
        <svg className="absolute inset-0 w-full h-full opacity-35 text-[#f0abfc] transition-transform duration-700 group-hover:scale-110" fill="none" viewBox="0 0 100 100" stroke="currentColor" strokeWidth="0.5">
          <circle cx="50" cy="50" r="32" strokeDasharray="2 3" />
          <circle cx="50" cy="50" r="16" />
          <line x1="20" y1="50" x2="80" y2="50" />
          <line x1="50" y1="20" x2="50" y2="80" />
          <line x1="28" y1="28" x2="72" y2="72" />
          <line x1="72" y1="28" x2="28" y2="72" />
          <circle cx="50" cy="50" r="4.5" fill="currentColor" className="animate-pulse" />
          <circle cx="20" cy="50" r="3" fill="currentColor" />
          <circle cx="80" cy="50" r="3" fill="currentColor" />
          <circle cx="50" cy="20" r="3" fill="currentColor" />
          <circle cx="50" cy="80" r="3" fill="currentColor" />
        </svg>
      );
    }
    
    // Mechanical Crosshairs Vector Pattern for Robotics
    if (cat.includes("robot") || cat.includes("robotic")) {
      return (
        <svg className="absolute inset-0 w-full h-full opacity-30 text-[#fef08a] transition-transform duration-700 group-hover:scale-110" fill="none" viewBox="0 0 100 100" stroke="currentColor" strokeWidth="0.5">
          <rect x="24" y="24" width="52" height="52" strokeDasharray="4 2" />
          <circle cx="50" cy="50" r="12" />
          <line x1="10" y1="10" x2="90" y2="90" />
          <line x1="90" y1="10" x2="10" y2="90" />
          <line x1="50" y1="5" x2="50" y2="95" strokeWidth="0.25" />
          <line x1="5" y1="50" x2="95" y2="50" strokeWidth="0.25" />
          <circle cx="50" cy="50" r="2" fill="currentColor" />
          <circle cx="24" cy="24" r="1.5" fill="currentColor" />
          <circle cx="76" cy="76" r="1.5" fill="currentColor" />
        </svg>
      );
    }

    // Trend Vectors and Node Waves for Startups
    if (cat.includes("startup")) {
      return (
        <svg className="absolute inset-0 w-full h-full opacity-35 text-[#22d3ee] transition-transform duration-700 group-hover:scale-110" fill="none" viewBox="0 0 100 100" stroke="currentColor" strokeWidth="0.5">
          <path d="M10,85 C30,75 35,40 60,60 T90,15" strokeWidth="0.75" />
          <path d="M10,85 C30,80 35,50 60,70 T90,25" strokeDasharray="2 2" />
          <line x1="10" y1="85" x2="90" y2="85" />
          <line x1="10" y1="15" x2="10" y2="85" />
          <circle cx="90" cy="15" r="3" fill="currentColor" className="animate-pulse" />
          <circle cx="60" cy="60" r="2" fill="currentColor" />
        </svg>
      );
    }

    // Lock and Vector Shields for Cybersecurity
    if (cat.includes("cybersecurity") || cat.includes("security")) {
      return (
        <svg className="absolute inset-0 w-full h-full opacity-35 text-[#f87171] transition-transform duration-700 group-hover:scale-110" fill="none" viewBox="0 0 100 100" stroke="currentColor" strokeWidth="0.5">
          <polygon points="50,12 82,24 82,56 50,88 18,56 18,24" />
          <polygon points="50,22 72,30 72,52 50,76 28,52 28,30" strokeDasharray="3 3" />
          <line x1="18" y1="24" x2="82" y2="56" />
          <line x1="82" y1="24" x2="18" y2="56" />
          <circle cx="50" cy="40" r="4" fill="currentColor" />
        </svg>
      );
    }

    // Default Tech Circuit Graphic
    return (
      <svg className="absolute inset-0 w-full h-full opacity-20 text-neutral-400" fill="none" viewBox="0 0 100 100" stroke="currentColor" strokeWidth="0.5">
        <rect x="35" y="35" width="30" height="30" />
        <line x1="50" y1="5" x2="50" y2="35" />
        <line x1="50" y1="65" x2="50" y2="95" />
        <line x1="5" y1="50" x2="35" y2="50" />
        <line x1="65" y1="50" x2="95" y2="50" />
        <circle cx="50" cy="35" r="1.5" fill="currentColor" />
        <circle cx="50" cy="65" r="1.5" fill="currentColor" />
        <circle cx="35" cy="50" r="1.5" fill="currentColor" />
        <circle cx="65" cy="50" r="1.5" fill="currentColor" />
      </svg>
    );
  };

  const getGradientForCategory = (category: string) => {
    const cat = category.toLowerCase();
    if (cat.includes("intelligence") || cat.includes("ai")) {
      return "from-[#0a060d] via-[#100713] to-[#05060b] border-fuchsia-950/60";
    }
    if (cat.includes("robot") || cat.includes("robotic")) {
      return "from-[#0a0705] via-[#110f05] to-[#040905] border-yellow-950/60";
    }
    if (cat.includes("startup")) {
      return "from-[#040909] via-[#040e0e] to-[#04080a] border-cyan-950/60";
    }
    if (cat.includes("cybersecurity") || cat.includes("security")) {
      return "from-[#0a0505] via-[#130606] to-[#0a040b] border-red-950/60";
    }
    return "from-[#080808] via-[#0e0e0e] to-[#121212] border-neutral-800/80";
  };

  /* ===========================================================================
     RENDER: DASHBOARD SHELL
     3-zone grid: Fixed Header → [Scrollable Feed | Fixed Sidebar]
     =========================================================================== */
  return (
    <div className="dashboard-shell">

      {/* ================================================================
          ZONE 1: FIXED HEADER (status strip + ticker + logo + search + nav)
          ================================================================ */}
      <div className="dashboard-header">

        {/* Top System Status Strip */}
        <div className="w-full bg-neutral-950 text-white border-b border-border py-1.5 px-4 flex items-center justify-between font-mono text-[9px] tracking-[0.22em] uppercase font-semibold">
          <div className="flex items-center gap-1.5">
            <span className="h-1.5 w-1.5 rounded-full bg-emerald-500 animate-pulse inline-block"></span>
            <span>LIVE TECHNOLOGY INTELLIGENCE</span>
          </div>
          <div className="hidden sm:flex items-center gap-3">
            <span>REAL-TIME TECH NEWS NETWORK</span>
            <span className="text-neutral-600">|</span>
            <span suppressHydrationWarning className="text-neutral-400">
              {new Date().toLocaleDateString([], { weekday: 'short', month: 'short', day: 'numeric' }).toUpperCase()}
            </span>
          </div>
        </div>

        {/* Live Scrolling Update Ticker */}
        <div className="w-full bg-neutral-900/60 dark:bg-neutral-950/60 border-b border-border/80 py-1 overflow-hidden">
          <div className="flex items-center whitespace-nowrap animate-marquee font-mono text-[8px] text-[#888888] tracking-wider">
            {tickerHeadlines.map((headline, idx) => (
              <span key={idx} className="mr-8 flex items-center gap-2">
                {headline.includes("STREAM") || headline.includes("LOCK") ? (
                  <Radio className="h-2.5 w-2.5 text-emerald-500 animate-pulse inline" />
                ) : (
                  <Terminal className="h-2.5 w-2.5 inline text-neutral-500" />
                )}
                {headline}
              </span>
            ))}
            {/* Duplicate to prevent cut-off in loop */}
            {tickerHeadlines.map((headline, idx) => (
              <span key={`dup-${idx}`} className="mr-8 flex items-center gap-2">
                <Terminal className="h-2.5 w-2.5 inline text-neutral-500" />
                {headline}
              </span>
            ))}
          </div>
        </div>

        {/* Main Logo + Search + Controls Bar */}
        <header className="border-b border-border bg-card">
          <div className="max-w-[1800px] mx-auto px-4 sm:px-5 py-3 flex justify-between items-center gap-4 lg:gap-6 w-full">
            {/* Logo Block */}
            <div className="shrink-0">
              <h1 className="text-xl sm:text-2xl font-extrabold tracking-tighter text-foreground font-sans uppercase leading-none">
                Tech News Today
              </h1>
              <p className="font-mono text-[7px] sm:text-[8px] text-muted uppercase tracking-[0.2em] leading-none mt-0.5">
                Autonomous AI Newsroom
              </p>
            </div>

            {/* Block 2 (Right Controls & Search) */}
            <div className="flex items-center gap-5 flex-1 md:flex-initial justify-end">
              {/* Console Search Bar */}
              <div className="w-full md:w-[620px] max-w-[620px] relative group">
                <div className="absolute inset-y-0 left-3 flex items-center pointer-events-none">
                  <Search className="h-3.5 w-3.5 text-neutral-500 group-focus-within:text-foreground transition-colors" />
                </div>
                <input
                  suppressHydrationWarning
                  type="text"
                  placeholder="Query autonomous news database..."
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  className="w-full bg-background/50 border border-border py-1.5 pl-9 pr-8 text-xs font-mono rounded-none focus:outline-none focus:border-foreground/80 focus:bg-background transition-all placeholder-neutral-500 text-foreground"
                />
                {searchQuery && (
                  <button 
                    suppressHydrationWarning
                    onClick={() => setSearchQuery("")}
                    className="absolute inset-y-0 right-3 flex items-center font-mono text-[8px] uppercase text-muted hover:text-foreground"
                  >
                    Clear
                  </button>
                )}
              </div>

              {/* Quick Stats & Controls */}
              <div className="hidden md:flex items-center gap-3 text-[9px] font-mono text-muted shrink-0">
                <span className="text-foreground font-bold">{cachedArticles.length}</span>
                <span>INDEXED</span>
                <span className="text-neutral-700">|</span>
                <button
                  suppressHydrationWarning
                  onClick={toggleTheme}
                  className="hover:text-foreground transition-colors flex items-center gap-1 mr-1"
                  title="Toggle Layout Theme"
                >
                  {theme === "dark" ? <Sun className="h-3 w-3" /> : <Moon className="h-3 w-3" />}
                </button>
                <span className="text-neutral-700">|</span>
                {/* User Dropdown / Login Button */}
                {user ? (
                  <div className="relative">
                    <button
                      onClick={() => setUserMenuOpen(!userMenuOpen)}
                      className="hover:text-foreground transition-colors flex items-center gap-1 uppercase font-bold text-foreground border border-border px-2.5 py-1 bg-card hover:bg-neutral-900"
                    >
                      {user.role === "reader" ? "USER" : "ADMIN"} ▼
                    </button>
                    {userMenuOpen && (
                      <div className="absolute right-0 top-full mt-1.5 w-40 border border-border bg-card z-50 shadow-xl font-mono text-[9px] tracking-wider text-left">
                        <div className="px-3 py-2 border-b border-border text-neutral-500 uppercase font-semibold text-[8px]">
                          Role: {user.role.replace("_", " ")}
                        </div>
                        {user.role === "reader" ? (
                          <>
                            <button className="w-full text-left px-3 py-2 text-neutral-400 border-b border-[#141414] opacity-50 cursor-not-allowed">
                              Profile (P5)
                            </button>
                            <button className="w-full text-left px-3 py-2 text-neutral-400 border-b border-[#141414] opacity-50 cursor-not-allowed">
                              Bookmarks (P5)
                            </button>
                            <button className="w-full text-left px-3 py-2 text-neutral-400 border-b border-[#141414] opacity-50 cursor-not-allowed">
                              Settings (P5)
                            </button>
                          </>
                        ) : (
                          <Link href="/admin" className="block px-3 py-2 text-neutral-400 hover:text-white hover:bg-[#111] transition-colors border-b border-[#141414]">
                            Dashboard
                          </Link>
                        )}
                        <button
                          onClick={handleLogout}
                          className="w-full text-left px-3 py-2 text-red-400 hover:text-red-300 hover:bg-[#111] transition-colors font-bold"
                        >
                          Logout
                        </button>
                      </div>
                    )}
                  </div>
                ) : (
                  <Link
                    href="/login"
                    className="bg-foreground text-background font-bold px-3 py-1 hover:bg-neutral-300 transition-colors tracking-widest text-[9px] uppercase"
                  >
                    Login
                  </Link>
                )}
              </div>
            </div>
          </div>
        </header>

        {/* Category Navigation Strip */}
        <nav className="border-b border-border bg-card/50">
          <div className="max-w-[1800px] mx-auto px-4 sm:px-5">
            <div className="flex items-center gap-1 overflow-x-auto py-2 scrollbar-thin">
              <button
                suppressHydrationWarning
                onClick={() => setCategory(null)}
                className={`relative px-3 py-1 text-[9px] font-mono tracking-widest uppercase transition-all whitespace-nowrap border ${
                  selectedCategory === null
                    ? "bg-foreground text-background border-foreground font-bold"
                    : "bg-card text-foreground border-border hover:bg-neutral-100 dark:hover:bg-neutral-900"
                }`}
              >
                ALL STREAMS
                {selectedCategory === null && (
                  <span className="absolute bottom-0 inset-x-0 h-[1.5px] bg-accent shadow-[0_0_6px_#ffffff]"></span>
                )}
              </button>
              {categories.map((cat) => (
                <button
                  suppressHydrationWarning
                  key={cat.id}
                  onClick={() => setCategory(cat.slug)}
                  className={`relative px-3 py-1 text-[9px] font-mono tracking-widest uppercase transition-all whitespace-nowrap border ${
                    selectedCategory === cat.slug
                      ? "bg-foreground text-background border-foreground font-bold"
                      : "bg-card text-foreground border-border hover:bg-neutral-100 dark:hover:bg-neutral-900"
                  }`}
                >
                  {cat.name}
                  {selectedCategory === cat.slug && (
                    <span className="absolute bottom-0 inset-x-0 h-[1.5px] bg-accent shadow-[0_0_6px_#ffffff]"></span>
                  )}
                </button>
              ))}
            </div>
          </div>
        </nav>

        {/* Horizontal Trending Topics Tags Strip for Readers */}
        <div className="border-b border-border bg-[#090909]/60 py-1.5 px-4 overflow-hidden">
          <div className="max-w-[1800px] mx-auto px-4 sm:px-5 flex items-center gap-3">
            <span className="font-mono text-[8px] tracking-[0.15em] text-[#888] uppercase shrink-0">
              Trending Topics:
            </span>
            <div className="flex items-center gap-1.5 overflow-x-auto scrollbar-none py-0.5">
              {telemetry && telemetry.trending_spikes && telemetry.trending_spikes.length > 0 ? (
                telemetry.trending_spikes.map((item: any, i: number) => (
                  <span
                    key={i}
                    onClick={() => loadTrendDetails(item.topic)}
                    className="px-2 py-0.5 bg-card border border-border font-mono text-[8px] uppercase text-foreground hover:border-neutral-500 cursor-pointer hover:bg-neutral-100 dark:hover:bg-neutral-900 transition-colors flex items-center gap-1 shrink-0"
                    title="Access Trend Briefing"
                  >
                    <span>#{item.topic}</span>
                    <span className="text-[6px] px-1 bg-neutral-800 text-neutral-400 font-bold">{item.weight}</span>
                  </span>
                ))
              ) : (
                Array.from(new Set(
                  cachedArticles.flatMap(a => [a.category, a.source]).filter(Boolean)
                )).slice(0, 8).map((topic, i) => (
                  <span
                    key={i}
                    onClick={() => loadTrendDetails(topic)}
                    className="px-2 py-0.5 bg-card border border-border font-mono text-[8px] uppercase text-foreground hover:border-neutral-500 cursor-pointer hover:bg-neutral-100 dark:hover:bg-neutral-900 transition-colors shrink-0"
                  >
                    #{topic}
                  </span>
                ))
              )}
            </div>
          </div>
        </div>
      </div>
      {/* END FIXED HEADER */}


      {/* ================================================================
          ZONE 2 + 3: DASHBOARD GRID (Feed | Sidebar)
          ================================================================ */}
      {/* ================================================================
          ZONE 2 + 3: DYNAMIC AD LAYOUT WRAPPING SCROLLABLE ARTICLE FEED
          ================================================================ */}
      <AdLayout>
        <div className="dashboard-feed h-full min-h-0 flex-1">
          <div className="max-w-[1200px] mx-auto px-4 sm:px-5 py-4 space-y-3">

            {/* Feed Header */}
            <div className="flex items-center justify-between pb-2 border-b border-border/60">
              <div className="flex items-center gap-2">
                <Radio className="h-3 w-3 text-emerald-500 animate-pulse" />
                <span className="font-mono text-[9px] font-bold uppercase tracking-widest text-foreground">
                  Intelligence Stream
                </span>
                <span className="font-mono text-[8px] text-muted ml-1">
                  {filteredArticles.length} SIGNALS
                </span>
              </div>
              <span suppressHydrationWarning className="font-mono text-[8px] text-muted">
                LAST SYNC: {new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
              </span>
            </div>

            {/* Advanced Filters Panel */}
            <div className="border border-border/80 p-2 flex flex-wrap gap-3 items-center justify-between font-mono text-[8px] uppercase tracking-wider bg-card/45 select-none shrink-0">
              {/* Source category quick toggles */}
              <div className="flex flex-wrap items-center gap-1.5">
                <span className="text-muted">Sources:</span>
                {[
                  { label: "ALL", value: "" },
                  { label: "OFFICIAL", value: "official" },
                  { label: "EDITORIAL", value: "editorial" },
                  { label: "COMMUNITY", value: "community" }
                ].map((item) => (
                  <button
                    key={item.value}
                    onClick={() => setFilterSourceCategory(item.value)}
                    className={`px-2 py-0.5 border transition-all ${
                      filterSourceCategory === item.value
                        ? "bg-foreground text-background border-foreground font-bold"
                        : "bg-background border-border hover:border-neutral-500"
                    }`}
                  >
                    {item.label}
                  </button>
                ))}
              </div>

              {/* Sort by selector */}
              <div className="flex items-center gap-1.5">
                <span className="text-muted">Sort By:</span>
                {[
                  { label: "RELEVANCE", value: "relevance" },
                  { label: "FRESHNESS", value: "freshness" }
                ].map((item) => (
                  <button
                    key={item.value}
                    onClick={() => setSortBy(item.value)}
                    className={`px-2 py-0.5 border transition-all ${
                      sortBy === item.value
                        ? "bg-foreground text-background border-foreground font-bold"
                        : "bg-background border-border hover:border-neutral-500"
                    }`}
                  >
                    {item.label}
                  </button>
                ))}
              </div>
            </div>

            {loading ? (
              /* Loading skeletons matching dense layout */
              <div className="space-y-3">
                {[1, 2, 3, 4, 5].map((i) => (
                  <div key={i} className="border border-border p-3 bg-card animate-pulse flex gap-3 items-center">
                    <div className="w-24 h-16 bg-border shrink-0"></div>
                    <div className="flex-1 space-y-2">
                      <div className="h-3 bg-border w-1/4"></div>
                      <div className="h-4 bg-border w-3/4"></div>
                      <div className="h-3 bg-border w-5/6"></div>
                    </div>
                  </div>
                ))}
              </div>
            ) : filteredArticles.length === 0 ? (
              /* Empty State */
              <div className="border border-border p-10 text-center bg-card space-y-3">
                {backendStatus === "proxy_error" ? (
                  <>
                    <AlertCircle className="h-7 w-7 text-amber-500 animate-bounce mx-auto mb-2" />
                    <h5 className="font-mono text-[11px] font-bold text-amber-500 uppercase tracking-widest">Gateway Routing Alert</h5>
                    <p className="font-mono text-[10px] text-neutral-400 max-w-md mx-auto">
                      API Gateway (Nginx Proxy) stale routing detected — reconnecting and re-resolving docker networks dynamically...
                    </p>
                  </>
                ) : backendStatus === "offline" ? (
                  <>
                    <Database className="h-7 w-7 text-red-500 animate-pulse mx-auto mb-2" />
                    <h5 className="font-mono text-[11px] font-bold text-red-500 uppercase tracking-widest">Database Offline</h5>
                    <p className="font-mono text-[10px] text-neutral-400 max-w-md mx-auto">
                      Backend database is temporarily unavailable — standby while autonomous container recovery is in progress...
                    </p>
                  </>
                ) : backendStatus === "sse_disconnected" ? (
                  <>
                    <Radio className="h-7 w-7 text-neutral-500 animate-pulse mx-auto mb-2" />
                    <h5 className="font-mono text-[11px] font-bold text-neutral-400 uppercase tracking-widest">Stream Disconnected</h5>
                    <p className="font-mono text-[10px] text-neutral-500 max-w-md mx-auto">
                      Event connection lost — attempting auto-recovery keepalive loops...
                    </p>
                  </>
                ) : (
                  <>
                    <Radio className="h-5 w-5 text-neutral-600 animate-pulse mx-auto mb-2" />
                    <p className="font-mono text-[10px] text-muted">No raw news streams currently matching search query or category filters.</p>
                  </>
                )}
              </div>
            ) : (
              /* DENSE UNIFORM ARTICLE STREAM */
              <div className="space-y-2">
                {filteredArticles.map((article, idx) => (
                  <Link
                    key={article.id}
                    href={`/articles/${article.slug}`}
                    className={`transition-all duration-200 ease-in-out hover:-translate-y-[2px] relative group flex gap-6 items-center cursor-pointer p-5 overflow-hidden border min-h-[220px] ${
                      realtimeIncomingIds.includes(article.id)
                        ? "realtime-incoming"
                        : idx === 0
                        ? "border-[#3b82f6]/40 bg-neutral-950/40 shadow-[0_0_15px_rgba(59,130,246,0.06)]"
                        : "border-border bg-card/60 hover:border-neutral-500/40"
                    }`}
                  >
                    {idx === 0 && (
                      <>
                        <span className="absolute left-0 inset-y-0 w-[2px] bg-[#3b82f6] shadow-[0_0_8px_#3b82f6]"></span>
                        <div className="absolute top-0 right-0 border-l border-b border-[#3b82f6]/40 bg-neutral-950 px-2 py-0.5 font-mono text-[7px] uppercase tracking-widest text-[#3b82f6] font-bold">
                          PRIORITY SIGNAL
                        </div>
                      </>
                    )}
                    
                    {/* Abstract Gradient Thumbnail */}
                    <div className={`w-[180px] h-[180px] border border-border/80 bg-gradient-to-br ${getGradientForCategory(article.category)} flex flex-col items-center justify-center relative overflow-hidden shrink-0 transition-transform duration-300`}>
                      <div className="absolute inset-0 opacity-10 bg-[radial-gradient(#fff_1px,transparent_1px)] [background-size:8px_8px] mix-blend-overlay"></div>
                      {renderCategoryGraphic(article.category)}
                      
                      {/* Real source thumbnail image */}
                      {(article.thumbnail_local || article.thumbnail_url) && !imageErrors[article.id] && (
                        <Image
                          src={(article.thumbnail_local || article.thumbnail_url) as string}
                          alt={article.title}
                          fill
                          sizes="180px"
                          className="object-cover z-20"
                          unoptimized={true}
                          onError={() => setImageErrors(prev => ({ ...prev, [article.id]: true }))}
                        />
                      )}

                      <span className="font-mono text-[5px] text-white/30 tracking-[0.15em] uppercase z-10">
                        {article.source}
                      </span>
                    </div>

                    {/* Content right block */}
                    <div className="flex-1 min-w-0 flex flex-col justify-between py-1 min-h-[180px]">
                      <div className="min-w-0 space-y-2">
                        <div className="flex items-center gap-2">
                          <span className="text-[7px] font-mono font-bold tracking-wider uppercase bg-background border border-border/60 px-1.5 py-0.5 text-foreground">
                            {article.category}
                          </span>
                          <span suppressHydrationWarning className="font-sans text-[9px] text-neutral-400 font-medium truncate">
                            {article.source} • {new Date(article.published_at).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                          </span>
                        </div>

                        <h4 className="font-sans text-xs sm:text-sm font-extrabold tracking-tight text-foreground group-hover:underline line-clamp-2 leading-snug">
                          {article.title}
                        </h4>
                        
                        <p className="font-sans text-[11px] text-neutral-400 line-clamp-4 leading-relaxed hidden sm:block">
                          {article.summary}
                        </p>
                      </div>

                      <div className="flex items-center justify-between pt-1 border-t border-border/30 font-mono text-[7px]">
                        <span className="text-foreground font-bold group-hover:translate-x-0.5 transition-transform flex items-center gap-0.5">
                          {idx === 0 ? "ACCESS WIREFLOW ↗" : "OPEN PAYLOAD →"}
                        </span>
                        <span className="text-neutral-600 uppercase tracking-wide">
                          {idx === 0 ? "PRIORITY" : "STABLE"}
                        </span>
                      </div>
                    </div>
                  </Link>
                ))}
              </div>
            )}

            {/* Feed Footer */}
            <div className="border-t border-border/60 pt-3 mt-4">
              <p className="font-mono text-[8px] text-muted text-center">
                © 2026 TECH NEWS TODAY • ALL MONITORS ONLINE • INGESTION RATE 0.85/MIN
              </p>
            </div>
          </div>
        </div>
      </AdLayout>

      {/* Live Trend Explorer Floating Briefing Panel Overlay */}
      {selectedTrend && (
        <div className="fixed bottom-4 right-4 z-50 w-[350px] sm:w-[420px] bg-card border border-border shadow-[0_4px_30px_rgba(0,0,0,0.5)] p-4 flex flex-col font-mono text-[10px] leading-relaxed transition-all duration-300 max-h-[90vh] overflow-y-auto select-none">
          <div className="flex justify-between items-center border-b border-border pb-2 mb-3">
            <span className="text-foreground font-bold tracking-widest text-[11px] uppercase flex items-center gap-1.5">
              <Orbit className="h-4 w-4 text-emerald-400 animate-spin" />
              Trend Intelligence Explorer: #{selectedTrend}
            </span>
            <button 
              onClick={() => {
                setSelectedTrend(null);
                setTrendDetails(null);
              }}
              className="text-muted hover:text-foreground text-[11px] uppercase font-bold border border-border px-2 py-0.5"
            >
              CLOSE
            </button>
          </div>

          {trendLoading ? (
            <div className="text-center py-8 text-muted animate-pulse">Computing authority weights & velocity spikes...</div>
          ) : !trendDetails ? (
            <div className="text-center py-8 text-muted">No telemetry computed for topic.</div>
          ) : (
            <div className="space-y-4">
              <div className="grid grid-cols-2 gap-3.5">
                <div className="border border-border/80 p-2 bg-neutral-950/80 rounded-sm">
                  <span className="text-muted block text-[8px] uppercase">Trend Velocity</span>
                  <span className="text-emerald-400 font-bold text-sm leading-snug">{trendDetails.velocity}</span>
                </div>
                <div className="border border-border/80 p-2 bg-neutral-950/80 rounded-sm">
                  <span className="text-muted block text-[8px] uppercase">Coverage Density</span>
                  <span className="text-neutral-200 font-bold text-sm leading-snug">{trendDetails.source_diversity} outlets</span>
                </div>
              </div>

              <div className="border border-border/80 p-2 bg-neutral-950/80 rounded-sm">
                <span className="text-muted block text-[8px] uppercase mb-1">Signal Freshness</span>
                <span className="text-foreground">{trendDetails.freshness}</span>
              </div>

              <div className="space-y-1.5">
                <span className="text-muted text-[8px] block uppercase font-bold tracking-widest">Active Covering Outlets</span>
                <div className="space-y-1.5">
                  {trendDetails.sources.map((src: any, i: number) => (
                    <div key={i} className="flex justify-between items-center border-b border-[#141414] pb-1 last:border-b-0">
                      <span className="font-bold text-neutral-200">{src.name}</span>
                      <div className="flex gap-2 text-[8px]">
                        <span className="text-muted">[{src.category.toUpperCase()} x{src.authority_weight}]</span>
                        <span className="text-foreground font-bold">Cred: {src.credibility}</span>
                      </div>
                    </div>
                  ))}
                </div>
              </div>

              <div className="space-y-2">
                <span className="text-muted text-[8px] block uppercase font-bold tracking-widest">Latest signal wires</span>
                <div className="space-y-2">
                  {trendDetails.articles.map((art: any) => (
                    <Link 
                      key={art.id} 
                      href={`/articles/${art.slug}`}
                      className="block p-2 border border-border/60 bg-background/50 hover:bg-neutral-900 hover:border-neutral-400 transition-all rounded-sm"
                    >
                      <h4 className="font-sans font-bold text-neutral-200 leading-snug text-xs line-clamp-1 mb-0.5">{art.title}</h4>
                      <p className="text-[7px] text-muted uppercase">{art.source} • {new Date(art.published_at).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</p>
                    </Link>
                  ))}
                </div>
              </div>
            </div>
          )}
        </div>
      )}

    </div>
  );
}

"use client";

import { useState, useEffect, FormEvent, useCallback } from "react";
import { useRouter } from "next/navigation";
import Link from "next/link";
import { useAppStore } from "../../store/useStore";
import { apiFetch, APIClientError } from "../../services/api";

const API_BASE = process.env.NEXT_PUBLIC_API_URL || "/api/v1";

interface AuthResponse {
  access_token: string;
  token_type: string;
  user: {
    id: number;
    name: string;
    email: string;
    role: string;
    permissions: string[];
  };
}

export default function SignupPage() {
  const router = useRouter();
  const { user, loginUser } = useAppStore();

  // Form Fields
  const [name, setName] = useState("");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [confirmPassword, setConfirmPassword] = useState("");
  const [showPassword, setShowPassword] = useState(false);
  const [agreeTerms, setAgreeTerms] = useState(false);

  // Layout & UI States
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isDuplicateEmail, setIsDuplicateEmail] = useState(false);
  const [mounted, setMounted] = useState(false);
  const [showWelcomeToast, setShowWelcomeToast] = useState(false);
  const [progressWidth, setProgressWidth] = useState(0);

  useEffect(() => {
    setMounted(true);
  }, []);

  // Redirect if already logged in
  useEffect(() => {
    if (mounted && user) {
      if (user.role === "reader") {
        router.push("/");
      } else {
        router.push("/admin");
      }
    }
  }, [mounted, user, router]);

  // Live password validation criteria checks
  const passHasMinLength = password.length >= 8;
  const passHasUppercase = /[A-Z]/.test(password);
  const passHasLowercase = /[a-z]/.test(password);
  const passHasNumber = /[0-9]/.test(password);
  const passMatchesConfirm = password === confirmPassword && confirmPassword.length > 0;
  
  // All password validations must pass
  const isPasswordValid = passHasMinLength && passHasUppercase && passHasLowercase && passHasNumber;

  const handleSignup = async (e: FormEvent) => {
    e.preventDefault();
    setError(null);
    setIsDuplicateEmail(false);

    // Frontend Validations
    if (name.trim().length < 2) {
      setError("Full Name must be at least 2 characters long.");
      return;
    }

    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(email.trim())) {
      setError("Please enter a valid email address.");
      return;
    }

    if (!isPasswordValid) {
      setError("Password does not meet the required security criteria.");
      return;
    }

    if (password !== confirmPassword) {
      setError("Password and Confirm Password fields must match.");
      return;
    }

    if (!agreeTerms) {
      setError("You must agree to the Terms of Service to create an account.");
      return;
    }

    setLoading(true);

    try {
      // POST /auth/register
      const data = await apiFetch<AuthResponse>("/auth/register", {
        method: "POST",
        body: JSON.stringify({
          name: name.trim(),
          email: email.trim().toLowerCase(),
          password: password,
        }),
      });

      // Session binding (Auto-login)
      loginUser(data.user, data.access_token);
      
      // Trigger Welcome Toast with progress animation and delayed redirect
      setShowWelcomeToast(true);
      setTimeout(() => setProgressWidth(100), 50);
      setTimeout(() => {
        router.push("/");
      }, 2500);
    } catch (err: any) {
      if (err instanceof APIClientError) {
        if (err.status === 409 || err.message?.includes("Email already registered")) {
          setError("Email already registered.");
          setIsDuplicateEmail(true);
        } else if (err.status === 429) {
          setError("Too many registration attempts. Please wait a minute.");
        } else {
          setError(err.message || "Registration failed. Try again.");
        }
      } else {
        setError("Connection error. Verify the API gateway is online.");
      }
    } finally {
      setLoading(false);
    }
  };

  if (!mounted) {
    return (
      <div className="min-h-screen bg-[#080808] flex items-center justify-center">
        <div className="w-6 h-6 border border-white/20 border-t-white animate-spin" />
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#080808] flex flex-col items-center justify-center px-4 py-12 relative overflow-hidden">
      {/* Subtle background grid */}
      <div className="absolute inset-0 border-grid opacity-[0.03]" />

      {/* System status bar */}
      <div className="fixed top-0 left-0 right-0 z-50 bg-neutral-950 border-b border-[#1a1a1a] py-1.5 px-4">
        <div className="flex items-center justify-center gap-2 font-mono text-[9px] tracking-[0.25em] uppercase text-neutral-400">
          <span className="h-1.5 w-1.5 bg-emerald-500 animate-pulse inline-block" />
          <span>TECH NEWS TODAY • REGISTER OPERATION NODE</span>
        </div>
      </div>

      {/* Signup card */}
      <div className="w-full max-w-md relative z-10">
        {/* Logo header */}
        <div className="text-center mb-8">
          <h1 className="text-3xl font-extrabold tracking-tighter text-white font-sans uppercase">
            TECH NEWS TODAY
          </h1>
          <p className="font-mono text-[10px] tracking-[0.3em] uppercase text-[#888] mt-2">
            Create Operations Account
          </p>
        </div>

        {/* Main card */}
        <div
          className={`border bg-[#0c0c0c] p-6 transition-colors duration-300 ${
            error ? "border-red-500/60" : "border-[#1a1a1a]"
          }`}
        >
          {/* Error banner with duplicate email specific handler */}
          {error && (
            <div className="mb-4 border border-red-500/30 bg-red-500/5 px-3 py-2 flex items-start gap-2">
              <svg className="w-3.5 h-3.5 text-red-400 mt-0.5 shrink-0" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                <circle cx="12" cy="12" r="10" />
                <line x1="12" y1="8" x2="12" y2="12" />
                <line x1="12" y1="16" x2="12.01" y2="16" />
              </svg>
              <div className="font-mono text-[10px] text-red-400 leading-relaxed">
                {isDuplicateEmail ? (
                  <span>
                    Email already registered.{" "}
                    <Link href="/login" className="text-white underline font-bold">
                      [Login Instead]
                    </Link>
                  </span>
                ) : (
                  <span>{error}</span>
                )}
              </div>
            </div>
          )}

          <form onSubmit={handleSignup} className="space-y-4">
            {/* Full Name */}
            <div>
              <label
                htmlFor="signup-name"
                className="block font-mono text-[9px] tracking-widest uppercase text-[#888] mb-1.5"
              >
                Full Name
              </label>
              <input
                id="signup-name"
                type="text"
                required
                value={name}
                onChange={(e) => setName(e.target.value)}
                placeholder="Operator Name"
                className="w-full bg-[#080808] border border-[#1a1a1a] px-3 py-2.5 font-mono text-[12px] text-white placeholder-neutral-600 focus:outline-none focus:border-white transition-colors"
              />
            </div>

            {/* Email Address */}
            <div>
              <label
                htmlFor="signup-email"
                className="block font-mono text-[9px] tracking-widest uppercase text-[#888] mb-1.5"
              >
                Email Address
              </label>
              <input
                id="signup-email"
                type="email"
                required
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                placeholder="operator@technews.today"
                className="w-full bg-[#080808] border border-[#1a1a1a] px-3 py-2.5 font-mono text-[12px] text-white placeholder-neutral-600 focus:outline-none focus:border-white transition-colors"
              />
            </div>

            {/* Password */}
            <div>
              <label
                htmlFor="signup-password"
                className="block font-mono text-[9px] tracking-widest uppercase text-[#888] mb-1.5"
              >
                Password
              </label>
              <div className="relative">
                <input
                  id="signup-password"
                  type={showPassword ? "text" : "password"}
                  required
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  placeholder="••••••••"
                  className="w-full bg-[#080808] border border-[#1a1a1a] px-3 py-2.5 pr-16 font-mono text-[12px] text-white placeholder-neutral-600 focus:outline-none focus:border-white transition-colors"
                />
                <button
                  type="button"
                  onClick={() => setShowPassword(!showPassword)}
                  className="absolute right-3 top-1/2 -translate-y-1/2 font-mono text-[8px] tracking-widest uppercase text-[#555] hover:text-white transition-colors"
                >
                  {showPassword ? "HIDE" : "SHOW"}
                </button>
              </div>

              {/* Password Dynamic Live Validations */}
              <div className="mt-2 border border-[#1a1a1a] bg-[#080808] p-2 space-y-1 font-mono text-[8px] tracking-wider text-[#555]">
                <div className="flex items-center gap-1.5">
                  <span className={`h-1.5 w-1.5 rounded-full ${passHasMinLength ? "bg-emerald-500 animate-pulse" : "bg-[#333]"}`} />
                  <span className={passHasMinLength ? "text-neutral-300" : "text-[#555]"}>MINIMUM 8 CHARACTERS</span>
                </div>
                <div className="flex items-center gap-1.5">
                  <span className={`h-1.5 w-1.5 rounded-full ${passHasUppercase ? "bg-emerald-500 animate-pulse" : "bg-[#333]"}`} />
                  <span className={passHasUppercase ? "text-neutral-300" : "text-[#555]"}>ONE UPPERCASE LETTER</span>
                </div>
                <div className="flex items-center gap-1.5">
                  <span className={`h-1.5 w-1.5 rounded-full ${passHasLowercase ? "bg-emerald-500 animate-pulse" : "bg-[#333]"}`} />
                  <span className={passHasLowercase ? "text-neutral-300" : "text-[#555]"}>ONE LOWERCASE LETTER</span>
                </div>
                <div className="flex items-center gap-1.5">
                  <span className={`h-1.5 w-1.5 rounded-full ${passHasNumber ? "bg-emerald-500 animate-pulse" : "bg-[#333]"}`} />
                  <span className={passHasNumber ? "text-neutral-300" : "text-[#555]"}>ONE NUMBER</span>
                </div>
              </div>
            </div>

            {/* Confirm Password */}
            <div>
              <label
                htmlFor="signup-confirm-password"
                className="block font-mono text-[9px] tracking-widest uppercase text-[#888] mb-1.5"
              >
                Confirm Password
              </label>
              <div className="relative">
                <input
                  id="signup-confirm-password"
                  type="password"
                  required
                  value={confirmPassword}
                  onChange={(e) => setConfirmPassword(e.target.value)}
                  placeholder="••••••••"
                  className={`w-full bg-[#080808] border px-3 py-2.5 font-mono text-[12px] text-white placeholder-neutral-600 focus:outline-none transition-colors ${
                    confirmPassword.length > 0
                      ? passMatchesConfirm
                        ? "border-emerald-500/40 focus:border-emerald-500"
                        : "border-red-500/40 focus:border-red-500"
                      : "border-[#1a1a1a] focus:border-white"
                  }`}
                />
                {confirmPassword.length > 0 && (
                  <span className={`absolute right-3 top-1/2 -translate-y-1/2 font-mono text-[7px] uppercase font-bold tracking-wider ${passMatchesConfirm ? "text-emerald-500" : "text-red-500"}`}>
                    {passMatchesConfirm ? "MATCH" : "MISMATCH"}
                  </span>
                )}
              </div>
            </div>

            {/* Terms of Service Checkbox */}
            <div className="flex items-start">
              <label className="flex items-start gap-2.5 cursor-pointer group" htmlFor="signup-terms">
                <div className="relative mt-0.5 shrink-0">
                  <input
                    id="signup-terms"
                    type="checkbox"
                    checked={agreeTerms}
                    onChange={(e) => setAgreeTerms(e.target.checked)}
                    className="sr-only"
                  />
                  <div
                    className={`w-3.5 h-3.5 border transition-colors ${
                      agreeTerms
                        ? "bg-white border-white"
                        : "border-[#333] group-hover:border-[#555]"
