          {/* Quick pivot to login */}
          <div className="text-center font-mono text-[10px] tracking-wider text-[#666] select-none">
            Already have an account?{" "}
            <Link
              href="/login"
              className="text-white hover:underline uppercase font-bold transition-colors"
            >
              Login
            </Link>
          </div>
        </div>

        {/* Footer system status */}
        <div className="mt-6 flex items-center justify-center gap-2">
          <span className="h-1.5 w-1.5 bg-emerald-500 inline-block" />
          <span className="font-mono text-[9px] tracking-[0.2em] uppercase text-[#555]">
            System Status: Operational
          </span>
        </div>
    </div>

    {/* Dynamic Welcome Toast Overlay */}
    {showWelcomeToast && (
      <div className="fixed inset-0 z-50 bg-black/80 flex items-center justify-center animate-fadeIn select-none">
        <div className="border border-emerald-500/40 bg-[#0c0c0c] p-6 max-w-sm w-full text-center space-y-4 shadow-[0_0_30px_rgba(16,185,129,0.1)]">
          <div className="flex justify-center">
            <span className="h-10 w-10 rounded-full bg-emerald-500/10 border border-emerald-500/30 flex items-center justify-center text-emerald-500 font-bold text-lg">
              ✓
            </span>
          </div>
          <h3 className="font-sans text-sm font-bold text-white uppercase tracking-wider">
            Registration Successful
          </h3>
          <p className="font-mono text-[10px] text-neutral-400 leading-relaxed">
            Welcome to Tech News Today.<br />
            Your account has been created successfully.
          </p>
          <div className="w-full bg-[#141414] h-1 relative overflow-hidden">
            <div 
              className="bg-emerald-500 h-full absolute left-0 top-0 transition-all duration-[2400ms] ease-linear"
              style={{ width: `${progressWidth}%` }}
            />
          </div>
          <p className="font-mono text-[8px] text-[#555] tracking-widest uppercase">
            Redirecting to newsroom stream...
          </p>
        </div>
      </div>
    )}
  </div>
);
}

"use client";

import { useEffect } from "react";
import { useAppStore } from "../store/useStore";

export default function AuthProvider({ children }: { children: React.ReactNode }) {
  const { loginUser, setRestoringSession, setAuthRefreshSuppressUntil } = useAppStore();

  useEffect(() => {
    const controller = new AbortController();
    const timeoutId = setTimeout(() => {
      console.warn("Session restore safety timeout reached. Aborting request.");
      controller.abort();
      setRestoringSession(false);
      
      // Suppress subsequent refresh attempts for 5 minutes
      const suppressUntil = Date.now() + 300000;
      setAuthRefreshSuppressUntil(suppressUntil);
    }, 3000);

    const initializeSession = async () => {
      try {
        const apiBase = process.env.NEXT_PUBLIC_API_URL || "/api/v1";
        const response = await fetch(`${apiBase}/auth/refresh`, {
          method: "POST",
          credentials: "include",
          headers: { "Content-Type": "application/json" },
          signal: controller.signal,
        });

        if (response.ok) {
          const payload = await response.json();
          const data = payload.data || payload;
          if (data.access_token && data.user) {
            loginUser(data.user, data.access_token);
          }
        } else {
          console.warn(`Session restore returned status ${response.status}. Continuing as guest.`);
          if (response.status === 401 || response.status === 403) {
            const suppressUntil = Date.now() + 300000;
            setAuthRefreshSuppressUntil(suppressUntil);
          }
        }
      } catch (e: any) {
        if (e.name === "AbortError") {
          console.warn("Session restore request aborted due to timeout.");
        } else {
          console.warn("Session restore attempt failed:", e);
        }
        const suppressUntil = Date.now() + 300000;
        setAuthRefreshSuppressUntil(suppressUntil);
      } finally {
        clearTimeout(timeoutId);
        setRestoringSession(false);
      }
    };

    initializeSession();
  }, [loginUser, setRestoringSession, setAuthRefreshSuppressUntil]);

  return <>{children}</>;
}

